"use client";

import { useTranslations } from "next-intl";
import { useEffect, useRef } from "react";

const GIS_SCRIPT_SRC = "https://accounts.google.com/gsi/client";

/**
 * Minimal subset of the Google Identity Services API the widget uses.
 * Typed inline so we don't take a dependency on `@types/google.accounts`
 * just for two function signatures.
 */
interface GoogleCredentialResponse {
  credential: string;
  select_by?: string;
  clientId?: string;
}
interface GoogleIdConfiguration {
  client_id: string;
  callback: (resp: GoogleCredentialResponse) => void;
  auto_select?: boolean;
  cancel_on_tap_outside?: boolean;
  ux_mode?: "popup" | "redirect";
}
interface GoogleButtonOptions {
  type?: "standard" | "icon";
  theme?: "outline" | "filled_blue" | "filled_black";
  size?: "large" | "medium" | "small";
  text?: "signin_with" | "signup_with" | "continue_with" | "signin";
  shape?: "rectangular" | "pill" | "circle" | "square";
  width?: string | number;
}
declare global {
  interface Window {
    google?: {
      accounts: {
        id: {
          initialize: (config: GoogleIdConfiguration) => void;
          renderButton: (parent: HTMLElement, options: GoogleButtonOptions) => void;
          prompt: () => void;
          cancel: () => void;
        };
      };
    };
  }
}

interface GoogleSignInButtonProps {
  /** Operator's Google OAuth client_id — PUBLIC by design (same one
   *  the operator embeds on their main-site Google login). The BE
   *  verifies `id_token.aud === clientId` on `startIdentifiedVisitor`,
   *  so a leaked clientId can't be abused (Google's allowlist + BE
   *  audience check are the actual security boundaries). */
  clientId: string;
  /** Called with the Google `id_token` when the visitor completes the
   *  popup. Caller routes it through `Wexio('identify',
   *  { googleIdToken })` → `startIdentifiedVisitor`. */
  onCredential: (idToken: string) => void;
}

/**
 * "Sign in with Google" — custom-styled button that triggers the
 * native Google Identity Services popup under the hood.
 *
 * We can't render a TRULY-custom OAuth flow for ID Tokens (Google
 * doesn't expose `initTokenClient` for id_tokens — only access
 * tokens), so the standard pattern is:
 *
 *   1. Initialise GIS with the operator's `clientId` + a callback.
 *   2. Render Google's own `renderButton` into an OFFSCREEN mount.
 *      Visitor never sees it; the DOM node + handlers exist.
 *   3. Our visible button (styled to match the passkey button so the
 *      auth gate looks coherent) `click()`s the offscreen GIS button
 *      programmatically. GIS runs its full popup flow → id_token
 *      back through our callback.
 *
 * Gives us full visual control over the gate while keeping all the
 * GIS auth UX (popup, account chooser, FedCM, cancellation) intact.
 * Lazy-loads `accounts.google.com/gsi/client` on first mount so
 * non-Google-enabled embeds pay zero network cost.
 */
export function GoogleSignInButton({ clientId, onCredential }: GoogleSignInButtonProps) {
  const t = useTranslations("messages");
  const hiddenMountRef = useRef<HTMLDivElement | null>(null);
  // Latest callback in a ref so the GIS initialize closure stays
  // wired to the CURRENT onCredential even if the parent re-renders.
  const onCredentialRef = useRef(onCredential);
  useEffect(() => {
    onCredentialRef.current = onCredential;
  }, [onCredential]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    let cancelled = false;

    const initAndRender = () => {
      if (cancelled) return;
      const g = window.google?.accounts?.id;
      const mount = hiddenMountRef.current;
      if (!g || !mount) return;
      g.initialize({
        client_id: clientId,
        callback: (resp) => {
          if (resp?.credential) onCredentialRef.current(resp.credential);
        },
        auto_select: false,
        cancel_on_tap_outside: true,
        ux_mode: "popup",
      });
      // Clear any prior render (clientId change across HMR cycles).
      mount.replaceChildren();
      g.renderButton(mount, {
        type: "standard",
        theme: "outline",
        size: "large",
        // Width is required for renderButton to actually emit the
        // inner div[role="button"] our click-proxy targets below.
        width: 200,
      });
    };

    if (window.google?.accounts?.id) {
      initAndRender();
      return () => {
        cancelled = true;
      };
    }

    const existing = document.querySelector<HTMLScriptElement>(`script[src="${GIS_SCRIPT_SRC}"]`);
    if (existing) {
      existing.addEventListener("load", initAndRender, { once: true });
      return () => {
        cancelled = true;
        existing.removeEventListener("load", initAndRender);
      };
    }

    const script = document.createElement("script");
    script.src = GIS_SCRIPT_SRC;
    script.async = true;
    script.defer = true;
    script.onload = initAndRender;
    document.head.appendChild(script);

    return () => {
      cancelled = true;
      script.onload = null;
    };
  }, [clientId]);

  const handleClick = () => {
    const mount = hiddenMountRef.current;
    if (!mount) return;
    // GIS renders an interactive div[role="button"] inside the mount.
    // Proxy our visible-button click to it so the visitor sees our
    // brand-tokenised UI while Google's popup flow runs as it would
    // from its own button.
    const gisButton = mount.querySelector<HTMLElement>('div[role="button"]');
    gisButton?.click();
  };

  return (
    <>
      <button
        type="button"
        onClick={handleClick}
        className="flex w-full items-center justify-center gap-2 rounded-wx border border-wx-border bg-wx-bg-elevated px-4 py-2 text-sm font-medium text-wx-fg transition-colors hover:bg-wx-bg-elevated-2"
      >
        <GoogleGlyph />
        <span>{t("googleSignIn")}</span>
      </button>
      {/* Offscreen mount for the real GIS button — kept out of the
          accessibility tree and the layout flow. Visually-hidden
          pattern (not `display:none`, which prevents GIS from
          measuring + rendering). */}
      <div
        ref={hiddenMountRef}
        aria-hidden="true"
        style={{
          position: "absolute",
          width: 1,
          height: 1,
          overflow: "hidden",
          clip: "rect(0 0 0 0)",
          clipPath: "inset(50%)",
          whiteSpace: "nowrap",
        }}
      />
    </>
  );
}

/** Inline SVG of Google's "G" mark — keeps the button self-contained
 *  (no extra image fetch, no bundle hit beyond a handful of paths). */
