"use client";

import { ApolloProvider as Provider } from "@apollo/client/react";
import { NextIntlClientProvider } from "next-intl";
import { type ReactNode, useEffect, useMemo, useRef, useState } from "react";
import { createPortal } from "react-dom";
import { WidgetShell } from "@/components/widget/widget-shell";
import { getApolloClient, setPublicKey } from "@/lib/apollo-client";
import { detectClientLocale } from "@/lib/locale-detect";
import {
  type VisitorIdentity,
  type VisitorPrefill,
  type WidgetEnv,
  WidgetEnvProvider,
} from "@/lib/use-widget-env";
import type { InjectableWidgetConfig, WidgetConfig } from "@/lib/widget-config";
import demoEn from "@/messages/demo.en.json";
import demoUk from "@/messages/demo.uk.json";
import enMessages from "@/messages/en.json";
import ukMessages from "@/messages/uk.json";

// Inlined Tailwind layer + theme tokens. Vite resolves `?inline` at
// build time; the type lives in `styles.css.d.ts`. We adopt this into
// the Shadow DOM portal so widget styles never collide with the host
// React tree's stylesheet.
import widgetStyles from "./styles.css?inline";

type SupportedLocale = "en" | "uk";

// `demo` is a separate file (mock content kept out of the chrome bundle)
// merged back in under the `demo` key — `useTranslations("demo")` is
// called unconditionally, so the namespace must exist for every locale.
const LOCALE_MESSAGES: Record<SupportedLocale, Record<string, unknown>> = {
  en: { ...enMessages, demo: demoEn },
  uk: { ...ukMessages, demo: demoUk },
};

export interface WexioWidgetProps {
  /**
   * Wexio integration public key — `pk_live_...`. Omit for demo mode
   * (renders the bundled `DEMO_CONFIG` so marketing sites and
   * Storybook stories work without a backend).
   */
  publicKey?: string;
  /**
   * UI locale. Defaults to `"en"`. Web-widget v1 ships English +
   * Ukrainian; extend `LOCALE_MESSAGES` in `react-component/index.tsx`
   * + `messages/<code>.json` to add more.
   */
  locale?: SupportedLocale;
  /**
   * Log a known user into the widget (the React equivalent of
   * Intercom's `boot({ user_id, ... })`). `userId` + `userHash` are the
   * verified identity — `userHash` is an HMAC-SHA256 of `userId` you
   * compute server-side with the integration secret. `name` / `email` /
   * `phone` populate the People profile; `attributes` is an open bag of
   * extra fields. Omit to keep the visitor anonymous.
   *
   * **Memoise this** — a fresh object literal every render churns the
   * env (the handshake itself is guarded against re-firing unless the
   * `userId`/`userHash` actually change).
   */
  user?: VisitorIdentity;
  /**
   * Default profile values to PRE-FILL the prechat form — the lighter,
   * unverified cousin of `user` (no `userHash`). When they cover every
   * required prechat field the widget attaches them + skips the form;
   * otherwise it pre-fills what it can. Use for a logged-in host that
   * knows the visitor's details but isn't doing verified identity.
   */
  prefill?: VisitorPrefill;
  /**
   * Override the resolved widget mode. In normal operator + visitor
   * use, leave undefined — it auto-resolves to `production` when a
   * `publicKey` is set, `demo` otherwise. Set `"preview"` only if you
   * also want the iframe-style `wexio:preview-config:v1` postMessage
   * channel active; for a React host, prefer `configOverride` below.
   */
  mode?: "production" | "preview" | "demo";
  /**
   * Live config patch — the operator dashboard's in-progress draft.
   * Merged on top of the resolved config (BE / demo) on every render,
   * so the preview pane reflects unsaved edits instantly with no
   * postMessage serialization. Covers everything in `WidgetConfig`:
   * `theme` (colors / fonts / radii), `themeMode`, `features` (which
   * tabs), `defaultTab`, `greeting`, `prechatForm`, `branding`,
   * `operatorAvatars`, `organizationLogoUrl`, `sounds`.
   *
   * NOT covered (not part of `WidgetConfig`): the Home-tab block
   * layout, and Help/News article content — those are fetched by the
   * widget from the BE at runtime, so previewing unsaved versions of
   * them needs a separate mechanism.
   *
   * **Memoise this** on the host side — a fresh object literal every
   * render re-runs the merge (cheap, but tidier to avoid).
   */
  configOverride?: Partial<WidgetConfig>;
  /**
   * Full, pre-resolved widget config. When provided, the widget boots
   * from it directly and SKIPS the `GET /api/web/config/:pk` bootstrap
   * request — for a host that already has the config (server-rendered it,
   * or fetched it once app-wide). `configOverride` still layers on top.
   * Keeps the live data layer (real chat / help / news); add `useDummyData`
   * if you also want mock content.
   *
   * Still pass `publicKey` — it's needed for the GraphQL header + the
   * visitor handshake; only the CONFIG fetch is skipped. The config's
   * localized chrome is whatever you pass, so re-supply it on a locale
   * change (there's no fetch to re-run).
   *
   * Typed `InjectableWidgetConfig`: `branding` + `status` (server-/plan-
   * owned) and `integrationId` / `name` (optional identity) are excluded —
   * a host can't override the paid white-label / plan gate from props; the
   * widget fills those itself. Pass the rest (theme / messenger / features
   * / homeLayout / greeting / prechat / sounds / security / locales).
   *
   * **Memoise this** — a fresh object literal every render re-runs the
   * env memo (harmless, but tidier to avoid).
   */
  config?: InjectableWidgetConfig;
  /**
   * Force the widget's data layer into mock mode regardless of whether a
   * `publicKey` was supplied. The dashboard's preview pane uses this so a
   * brand-new integration (with empty BE-side content) still shows a
   * populated widget — sample conversations, help articles, news, FAQs,
   * launcher unread count, operator avatars — on top of the operator's
   * real config (theme / logo / greeting / blocks / prechat / sounds all
   * flow through untouched, in either mode).
   */
  useDummyData?: boolean;
  /**
   * Dashboard-prefetched data for the preview pane. When the dashboard
   * already has operator-side news posts loaded, it can inject them
   * here and the widget will render those instead of round-tripping to
   * the BE's visitor surface. Lets the preview show real data without
   * the widget needing dashboard-origin authorization.
   *
   * Production embeds leave this undefined — visitor queries handle
   * data fetching normally.
   */
  previewData?: {
    /** Array of news posts for the News tab + `news-preview` home
     *  block. Same JSON shape the BE's `visitorNewsFeed` returns; the
     *  widget's extractors accept operator-side `NewsPost` rows
     *  unchanged. */
    newsPosts?: unknown[];
    /** Id-keyed lookup for the `featured-article` home block. */
    newsPostsById?: Record<string, unknown>;
    /** Array of help articles for the Help tab + `pinned-articles`
     *  home block + article detail. Operator-side `HelpArticle` row
     *  shape, accepted by the same extractors as visitor JSON. */
    helpArticles?: unknown[];
    /** Id-keyed lookup for the `pinned-articles` home block. */
    helpArticlesById?: Record<string, unknown>;
  };
  /**
   * Render the media lightbox (image / video gallery) as a
   * viewport-`fixed` overlay instead of one contained to this widget's
   * host box. Leave unset for a normal embed — the gallery stays
   * inside the box. Set `true` when the widget itself is rendered very
   * small (e.g. a dashboard's floating mobile-preview), so the gallery
   * is still usable. The overlay keeps the widget's Shadow-DOM styles
   * either way.
   */
  lightboxViewport?: boolean;
  /**
   * Notified every time the widget's intended dimensions change
   * (open ↔ closed ↔ expanded). Use for host-side layout sync —
   * e.g. push other UI aside when the panel opens.
   */
  onResize?: (size: { width: number; height: number }) => void;
  /**
   * Fired when the visitor taps the close chip. The widget hides
   * itself; the host may want to unmount the component or shrink
   * its container.
   */
  onClose?: () => void;
  /**
   * Pass-through wrapper class. The widget itself paints into a
   * Shadow DOM; this class lands on the outer host `<div>` you can
   * size + position with normal layout CSS.
   */
  className?: string;
  /**
   * Pass-through inline styles for the outer host `<div>`. Same
   * positioning role as `className` — pick whichever fits your
   * codebase.
   */
  style?: React.CSSProperties;
}

/**
 * `<WexioWidget />` — native React component embed for the Wexio web
 * messenger.
 *
 * Same `WidgetShell` React tree as the iframe / web-component builds,
 * mounted inside a Shadow DOM portal so styles stay isolated from the
 * host's React app. Host integrates via standard React idioms:
 *
 * ```tsx
 * <WexioWidget
 *   publicKey="pk_live_..."
 *   locale="en"
 *   onResize={({ width, height }) => layout.reserve(width, height)}
 *   onClose={() => setShowChat(false)}
 *   className="fixed bottom-5 right-5 w-[420px] h-[720px]"
 * />
 * ```
 *
 * **Why a Shadow DOM portal** — the alternative (direct render into
 * the host tree) means Tailwind classes from the widget collide with
 * the host's stylesheet, theme tokens leak, and any CSS reset on the
 * host page breaks the widget's layout. The portal gives us the
 * isolation of an iframe with the React-API of a native component.
 *
 * **SSR-safe** — renders `null` on the server. The shadow root +
 * portal target mount on first `useEffect`. Wrap with
 * `<Suspense fallback={null}>` if you need to defer hydration in
 * RSC-heavy apps.
 */
export function WexioWidget({
  publicKey,
  // No default: when the host doesn't pin a `locale`, fall back to the
  // visitor's browser via `detectClientLocale()` (resolved below).
  locale,
  user,
  prefill,
  mode,
  configOverride,
  config,
  useDummyData,
  previewData,
  lightboxViewport,
  onResize,
  onClose,
  className,
  style,
}: WexioWidgetProps) {
  const hostRef = useRef<HTMLDivElement | null>(null);
  const [portalTarget, setPortalTarget] = useState<HTMLElement | null>(null);
  // Resolved UI locale. Phase 1: an explicit `locale` prop, else the
  // browser (`detectClientLocale()` with no strategy yet). Phase 2: once
  // `useWidgetConfig` reports the operator's `localeStrategy` via the env
  // callback below, re-resolve (e.g. switch to the host page's
  // `<html lang>` for `WEBSITE`, or a pinned code). An explicit prop
  // pins it — the strategy callback is then a no-op.
  const [resolvedLocale, setResolvedLocale] = useState<SupportedLocale>(
    () => locale ?? detectClientLocale(),
  );
  // Keep the explicit prop authoritative if the host changes it.
  useEffect(() => {
    if (locale) setResolvedLocale(locale);
  }, [locale]);
  // The shadow root — handed to the widget via `env.styleRoot` so its
  // theme-token `<style>` block is injected INSIDE the shadow DOM
  // (self-contained theming; never touches the host page's `<head>`).
  const [shadowRoot, setShadowRoot] = useState<ShadowRoot | null>(null);

  // Keep the latest callbacks accessible to the env without re-creating
  // the env object on every host re-render — that would loop the
  // resize effect inside `WidgetShell` (which has `env` in its deps).
  const onResizeRef = useRef(onResize);
  const onCloseRef = useRef(onClose);
  useEffect(() => {
    onResizeRef.current = onResize;
    onCloseRef.current = onClose;
  }, [onResize, onClose]);

  // Stamp the apollo singleton's public-key synchronously the first
  // time we have one — same trick the web-component path uses to
  // avoid racing the first GraphQL request against the effect inside
  // `ApolloProvider`.
  useEffect(() => {
    setPublicKey(publicKey ?? null);
  }, [publicKey]);

  // Mount the shadow root once, on the first commit on the client.
  useEffect(() => {
    const host = hostRef.current;
    if (!host) return;
    // `attachShadow` throws if called twice on the same element —
    // React StrictMode double-invokes effects in dev, so re-use any
    // existing root rather than recreating it.
    const shadow = host.shadowRoot ?? host.attachShadow({ mode: "open" });

    // Adopt the bundled Tailwind layer + theme tokens. Falls back to
    // a `<style>` node when constructable stylesheets are unavailable
    // (older Safari / Firefox-ESR).
    if (typeof CSSStyleSheet !== "undefined" && "replaceSync" in CSSStyleSheet.prototype) {
      const sheet = new CSSStyleSheet();
      sheet.replaceSync(widgetStyles);
      shadow.adoptedStyleSheets = [...(shadow.adoptedStyleSheets ?? []), sheet];
    } else if (!shadow.querySelector("style[data-wexio-style]")) {
      const styleNode = document.createElement("style");
      styleNode.setAttribute("data-wexio-style", "true");
      styleNode.textContent = widgetStyles;
      shadow.appendChild(styleNode);
    }

    // Portal target — a plain div inside the shadow root that React
    // renders the `WidgetShell` tree into.
    let target = shadow.querySelector<HTMLDivElement>("div[data-wexio-portal-target]");
    if (!target) {
      target = document.createElement("div");
      target.setAttribute("data-wexio-portal-target", "true");
      target.style.display = "contents";
      shadow.appendChild(target);
    }
    setPortalTarget(target);
    setShadowRoot(shadow);
  }, []);

  // Build the env per (mode, publicKey, configOverride) — the inner
  // callbacks route through refs so updating an `onResize` prop
  // doesn't bust the env reference. `configOverride` IS in the deps:
  // when the dashboard editor edits a token the env changes, which
  // flows into `useWidgetConfig`'s effective-config `useMemo`. The
  // shell's resize effect also re-runs on that change — harmless
  // (it just re-reports unchanged dimensions), as long as the host
  // memoises `configOverride` so it only changes on real edits.
  const env = useMemo<WidgetEnv>(() => {
    return {
      kind: "web-component",
      publicKeyOverride: publicKey,
      modeOverride: mode ?? (publicKey ? "production" : "demo"),
      configOverride,
      // Full config injection — skips the bootstrap `GET /config`.
      configBase: config,
      forceDummyData: useDummyData,
      previewData,
      // The React embed always lives inside a host-controlled `<div>` —
      // anchor the launcher + panel to that box, not the viewport, so the
      // widget can be dropped into a dashboard preview pane (or any sized
      // container) without escaping to a fixed viewport corner. The host
      // gives the outer `<div>` its positioning context via `className` /
      // `style` (`relative` / `absolute` / `fixed` all establish one).
      embedded: true,
      // Known-user identity (Intercom-style boot). Routes the visitor
      // handshake to the identified flow; omit to stay anonymous.
      visitorIdentity: user,
      // Unverified default profile — pre-fills / auto-attaches the prechat.
      visitorPrefill: prefill,
      // Gallery overlay scope — `true` breaks the lightbox out to the
      // full viewport (for hosts that render the widget very small).
      lightboxViewport: lightboxViewport ?? false,
      // Self-contained theming: `data-theme` goes on the portal-target
      // element and the operator's theme `<style>` is injected into the
      // shadow root — so the dark-mode structural rules in `globals.css`
      // (adopted into this same shadow tree) actually match. Both are
      // `undefined` until the shadow root mounts, but `WidgetShell` only
      // renders once `portalTarget` exists, so the hooks that read these
      // always see the resolved values.
      themeRoot: portalTarget ?? undefined,
      styleRoot: shadowRoot ?? undefined,
      onResize: (width, height) => {
        onResizeRef.current?.({ width, height });
      },
      onClose: () => {
        onCloseRef.current?.();
      },
      // Phase 2 of locale resolution — `useWidgetConfig` reports the
      // operator's strategy here once the config lands. Skip entirely
      // when the host pinned an explicit `locale` prop.
      onLocaleStrategy: locale
        ? undefined
        : (strategy: string) => setResolvedLocale(detectClientLocale(strategy)),
    };
  }, [
    publicKey,
    mode,
    configOverride,
    config,
    useDummyData,
    previewData,
    lightboxViewport,
    portalTarget,
    shadowRoot,
    locale,
    user,
    prefill,
  ]);

  const tree = portalTarget
    ? createPortal(
        <ReactWidgetTree env={env} locale={resolvedLocale}>
          <WidgetShell />
        </ReactWidgetTree>,
        portalTarget,
      )
    : null;

  return (
    <div ref={hostRef} data-wexio-widget-host="true" className={className} style={style}>
      {tree}
    </div>
  );
}

/**
 * Same provider stack the web-component path uses, factored out so we
 * don't duplicate the Apollo + NextIntl + WidgetEnv layering.
 */
function ReactWidgetTree({
  env,
  locale,
  children,
}: {
  env: WidgetEnv;
  locale: SupportedLocale;
  children: ReactNode;
}) {
  const messages = LOCALE_MESSAGES[locale];
  // Memoise the apollo client lookup so React strict-mode's
  // double-effect doesn't churn it.
  const client = useMemo(() => getApolloClient(), []);
  return (
    <Provider client={client}>
      <NextIntlClientProvider locale={locale} messages={messages}>
        <WidgetEnvProvider env={env}>{children}</WidgetEnvProvider>
      </NextIntlClientProvider>
    </Provider>
  );
}

// Re-export `setPublicKey` for advanced consumers who want to stamp
// the apollo client outside the component lifecycle (e.g. SSR data
// fetching that needs the same header).
export { setPublicKey as setWexioPublicKey } from "@/lib/apollo-client";
// Re-export the prop type so consumers can spread it through wrappers.
export type { WexioWidgetProps as WexioWidgetReactProps };
