"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import {
  getPublicKey,
  setOnVisitorIntegrationMismatch,
  setOnVisitorUnauthorized,
  setVisitorToken,
} from "./apollo-client";
import {
  useStartAnonymousVisitorMutation,
  useStartIdentifiedVisitorMutation,
} from "./graphql/queries/generated/messaging.generated";
import type { VisitorIdentity, VisitorPrefill, WidgetEnv } from "./use-widget-env";

/**
 * Visitor session — calls `startAnonymousVisitor` on first mount and
 * stashes the JWT into `apollo-client`'s module-scoped slot so every
 * subsequent query/mutation stamps `Authorization: Bearer <token>`.
 *
 * **Visitor id is sticky** in `localStorage["wexio:visitor-id"]` so
 * returning visitors land in the same chat across reloads + tabs.
 * Generated as a random uuid on first visit.
 *
 * **Gating**:
 *   - Skips entirely when `enabled === false` (demo + preview modes
 *     where there's no real BE integration to authenticate against).
 *   - One-shot per mount — no auto re-auth here. JWT expiry handling
 *     comes in Day 2g (silent renew ~30s before `expiresIn`).
 *
 * **Errors are non-fatal**: a failed handshake leaves the widget in
 * "anonymous, unauthenticated" mode — Help + News still work
 * (anonymous-readable), but chat history + send mutations 4xx until
 * the handshake succeeds. Errors are surfaced to the caller; UI
 * decides whether to retry / show banner.
 */
export interface VisitorSession {
  token: string | null;
  chatId: string | null;
  peopleId: string | null;
  displayName: string | null;
  isAuthenticating: boolean;
  error: string | null;
  /** `true` once the BE confirms a VERIFIED-identified visitor
   *  (`kind === 'identified'`). Sensitive UI should gate on this — never
   *  on a passed email. `false` for anonymous / prefilled visitors. */
  verified: boolean;
}

/** Common subset of the `VisitorAuthResult` both handshakes return. */
type HandshakeResult = {
  token: string;
  expiresIn: number;
  chatId: string;
  peopleId: string;
  /** Resolved visitor id — the BE echoes the id it actually used. It no
   *  longer rotates (that forked chats); we persist whatever comes back so
   *  the widget stays in lockstep if that ever changes again. */
  visitorId: string;
  displayName: string;
  /** `'anonymous' | 'identified'` — drives `VisitorSession.verified`. */
  kind: string;
};

/** Storage-key generators — every key is scoped by the integration's
 *  `publicKey` so two operators embedding the widget on different
 *  sites (both iframes load the SAME `widget.wexio.com` origin →
 *  shared localStorage) don't see each other's visitor state.
 *
 *  Without this scoping, operator A's visitor JWT would be read by
 *  operator B's widget on first mount, fail BE validation
 *  (publicKey mismatch in the JWT), trigger a 401 recovery, and leak
 *  audit-log noise / a brief UX flicker. Same-operator multi-domain
 *  setups intentionally still share state (same publicKey → same
 *  storage key → SSO across the operator's properties). */
const visitorIdKey = (publicKey: string | null) =>
  publicKey ? `wexio:visitor-id:${publicKey}` : "wexio:visitor-id";
const identifiedSessionKey = (publicKey: string | null) =>
  publicKey ? `wexio:visitor-session:${publicKey}` : "wexio:visitor-session";

/** Legacy (pre-publicKey-scoping) keys — read once on first mount and
 *  removed so a returning visitor's existing session is preserved for
 *  THIS integration but no longer bleeds to others on the same widget
 *  origin. */
const LEGACY_VISITOR_ID_KEY = "wexio:visitor-id";
const LEGACY_IDENTIFIED_SESSION_KEY = "wexio:visitor-session";

interface PersistedIdentifiedSession {
  token: string;
  chatId: string;
  peopleId: string;
  displayName: string;
  /** Wall-clock ms when the token expires (mint time + `expiresIn`). */
  expiresAt: number;
}

/** Persist a freshly-minted identified session so a reload restores it.
 *  Exported because the passkey ceremony (a 2-step flow outside the
 *  handshake) mints its session out-of-band and hands it to the shell. */
export function persistIdentifiedSession(input: {
  token: string;
  chatId: string;
  peopleId: string;
  displayName: string;
  expiresIn: number;
}): void {
  if (typeof window === "undefined") return;
  try {
    const payload: PersistedIdentifiedSession = {
      token: input.token,
      chatId: input.chatId,
      peopleId: input.peopleId,
      displayName: input.displayName,
      expiresAt: Date.now() + input.expiresIn * 1000,
    };
    localStorage.setItem(identifiedSessionKey(getPublicKey()), JSON.stringify(payload));
  } catch {
    /* private mode — session just won't survive reload */
  }
}

/** Read the persisted identified session if it's still valid (with a
 *  small leeway so a near-expired token isn't restored only to 401).
 *  Clears + returns null when missing / expired / malformed.
 *
 *  Performs a one-time migration of a legacy (pre-publicKey-scoping)
 *  global key — moves it under THIS publicKey so the visitor doesn't
 *  lose their session, and clears the global key so other operators
 *  don't see it on their first read. */
function readPersistedIdentifiedSession(): PersistedIdentifiedSession | null {
  if (typeof window === "undefined") return null;
  const pk = getPublicKey();
  try {
    let raw = localStorage.getItem(identifiedSessionKey(pk));
    if (!raw && pk) {
      // Migrate: legacy global key → publicKey-scoped key.
      const legacy = localStorage.getItem(LEGACY_IDENTIFIED_SESSION_KEY);
      if (legacy) {
        localStorage.setItem(identifiedSessionKey(pk), legacy);
        localStorage.removeItem(LEGACY_IDENTIFIED_SESSION_KEY);
        raw = legacy;
      }
    }
    if (!raw) return null;
    const parsed = JSON.parse(raw) as PersistedIdentifiedSession;
    if (
      typeof parsed?.token !== "string" ||
      typeof parsed?.expiresAt !== "number" ||
      parsed.expiresAt - RENEW_LEEWAY_SECONDS * 1000 <= Date.now()
    ) {
      localStorage.removeItem(identifiedSessionKey(pk));
      return null;
    }
    return parsed;
  } catch {
    return null;
  }
}

function clearPersistedIdentifiedSession(): void {
  if (typeof window === "undefined") return;
  try {
    localStorage.removeItem(identifiedSessionKey(getPublicKey()));
    // Belt-and-braces: also clear the legacy global key in case a
    // previous build wrote it before this migration shipped.
    localStorage.removeItem(LEGACY_IDENTIFIED_SESSION_KEY);
  } catch {
    /* nothing to clear */
  }
}

/** Renew the JWT this many seconds before its declared expiry. Trades
 *  some early-renewal overhead for headroom against clock skew between
 *  the visitor's machine + the BE. */
const RENEW_LEEWAY_SECONDS = 30;

/** Prefix of the per-integration prechat-submitted flags — kept in sync
 *  with `prechatStorageKey` in the prechat helpers. Cleared on shutdown
 *  so the next visitor on a shared device is asked again. */
const PRECHAT_FLAG_PREFIX = "wexio:prechat-submitted:";

/**
 * Wipe the stored visitor session — for `shutdown` (logout / shared
 * device). Drops the in-memory token, forgets the sticky `visitorId` (so
 * the next handshake is a fresh identity, NOT the previous user's chat),
 * and clears the prechat-submitted flags. The caller still needs to
 * re-handshake (bump `epoch`) + clear the in-memory chat.
 */
export function resetStoredVisitorSession(): void {
  setVisitorToken(null);
  clearPersistedIdentifiedSession();
  if (typeof window === "undefined") return;
  try {
    const pk = getPublicKey();
    localStorage.removeItem(visitorIdKey(pk));
    // Also clear the legacy global key (pre-publicKey-scoping).
    localStorage.removeItem(LEGACY_VISITOR_ID_KEY);
    for (let i = localStorage.length - 1; i >= 0; i--) {
      const key = localStorage.key(i);
      if (key?.startsWith(PRECHAT_FLAG_PREFIX)) localStorage.removeItem(key);
    }
  } catch {
    /* private mode — nothing persisted to clear */
  }
}

export function useVisitorAuth(opts: {
  enabled: boolean;
  /** Known-user identity from the host. When it carries a `userId` +
   *  `userHash`, the handshake routes to `startIdentifiedVisitor` so the
   *  visitor lands as a verified, named person; otherwise it stays
   *  anonymous. May arrive AFTER mount (the iframe receives it over
   *  postMessage) — a late arrival re-handshakes on the same `visitorId`,
   *  which the BE transitions anonymous → identified. */
  identity?: VisitorIdentity | null;
  /** Bump to force a fresh handshake — used by `shutdown` after
   *  `resetStoredVisitorSession()` has cleared the old `visitorId`, so the
   *  re-handshake mints a brand-new anonymous identity. */
  epoch?: number;
}): VisitorSession {
  const [session, setSession] = useState<VisitorSession>({
    token: null,
    chatId: null,
    peopleId: null,
    displayName: null,
    isAuthenticating: opts.enabled,
    error: null,
    verified: false,
  });

  const [startAnonymous] = useStartAnonymousVisitorMutation();
  const [startIdentified] = useStartIdentifiedVisitorMutation();
  // Latest identity, read inside `performHandshake` without making it a
  // dependency (the effect re-fires on `identityKey` instead).
  const identityRef = useRef<VisitorIdentity | null>(opts.identity ?? null);
  identityRef.current = opts.identity ?? null;
  const renewTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  // Absolute wall-clock timestamp (ms) for the next scheduled renew.
  // `setTimeout` pauses while the browser tab is suspended (sleep /
  // backgrounded with throttling), so the timer can be hours behind
  // the real expiry. On `visibilitychange` we compare against this
  // value to decide whether to handshake immediately.
  const nextRenewAt = useRef<number>(0);

  // Single handshake function reused for first-load + silent renew.
  // Silent renew reuses the same `visitorId` so the BE returns the
  // same `chatId` + `peopleId` — the visitor's session continuity is
  // preserved across token rotations.
  const performHandshake = useCallback(
    async (cancelled: { current: boolean }) => {
      try {
        const visitorId = ensureVisitorId();
        const identity = identityRef.current;
        // Identity present → verified identified handshake via ONE proof:
        // a Google `id_token` (FedCM), a host-signed `jwt`, or the legacy
        // `userId`+`userHash` HMAC pair. Profile fields ride along; extra
        // attributes go as the `contextSnapshot` JSON. Otherwise anonymous.
        let out: HandshakeResult | undefined;
        if (
          identity &&
          (identity.googleIdToken || identity.jwt || (identity.userId && identity.userHash))
        ) {
          const res = await startIdentified({
            variables: {
              input: {
                visitorId,
                // exactly one proof — precedence: Google → jwt → HMAC.
                ...(identity.googleIdToken
                  ? { googleIdToken: identity.googleIdToken }
                  : identity.jwt
                    ? { jwt: identity.jwt }
                    : { userId: identity.userId, userHash: identity.userHash }),
                name: identity.name,
                email: identity.email,
                phone: identity.phone,
                contextSnapshot: identity.attributes
                  ? JSON.stringify(identity.attributes)
                  : undefined,
              },
            },
          });
          if (cancelled.current) return;
          out = res.data?.startIdentifiedVisitor;
        } else {
          const res = await startAnonymous({
            variables: { input: { visitorId } },
          });
          if (cancelled.current) return;
          out = res.data?.startAnonymousVisitor;
        }
        if (!out) {
          setSession((prev) => ({
            ...prev,
            isAuthenticating: false,
            error: "handshake_empty_response",
          }));
          return;
        }
        // Persist the BE-resolved visitorId if it ever differs from what we
        // sent. The BE no longer rotates (it resolves one stable row per
        // visitorId now), so this is normally a no-op — kept as a cheap
        // safety net to stay in lockstep with the server of record.
        if (out.visitorId && out.visitorId !== visitorId) {
          try {
            localStorage.setItem(visitorIdKey(getPublicKey()), out.visitorId);
          } catch {
            /* private mode — best effort */
          }
        }
        setVisitorToken(out.token);
        setSession({
          token: out.token,
          chatId: out.chatId,
          peopleId: out.peopleId,
          displayName: out.displayName,
          isAuthenticating: false,
          error: null,
          // The BE is authoritative — `kind` reflects whether the proof
          // actually verified, not just what we attempted.
          verified: out.kind === "identified",
        });
        // Persist a VERIFIED session so a reload restores it (instead of
        // re-handshaking anonymously → sign-in gate). Anonymous sessions
        // clear it so a logged-out reload stays anonymous.
        if (out.kind === "identified") {
          persistIdentifiedSession({
            token: out.token,
            chatId: out.chatId,
            peopleId: out.peopleId,
            displayName: out.displayName,
            expiresIn: out.expiresIn,
          });
        } else {
          clearPersistedIdentifiedSession();
        }
        // Schedule silent renew. `expiresIn` is seconds; we fire
        // ~30s before expiry so the new token replaces the old one
        // BEFORE any request 401s. A failed renew leaves the prior
        // token in place — it'll keep working until it actually
        // expires, at which point the session degrades gracefully.
        const renewInMs = Math.max(5_000, (out.expiresIn - RENEW_LEEWAY_SECONDS) * 1000);
        if (renewTimer.current) clearTimeout(renewTimer.current);
        nextRenewAt.current = Date.now() + renewInMs;
        renewTimer.current = setTimeout(() => {
          if (!cancelled.current) performHandshake(cancelled);
        }, renewInMs);
      } catch (err) {
        if (cancelled.current) return;
        setSession({
          token: null,
          chatId: null,
          peopleId: null,
          displayName: null,
          isAuthenticating: false,
          error: (err as Error).message,
          verified: false,
        });
      }
    },
    [startAnonymous, startIdentified],
  );

  // Stable key for the identity — flips when a (different) identity
  // arrives so the effect below re-handshakes. `null` while anonymous.
  // Covers every proof: a Google id_token, a signed `jwt`, or the
  // `userId:userHash` pair.
  const id = opts.identity;
  const identityKey = id?.googleIdToken
    ? `google:${id.googleIdToken}`
    : id?.jwt
      ? `jwt:${id.jwt}`
      : id?.userId && id?.userHash
        ? `${id.userId}:${id.userHash}`
        : null;

  // biome-ignore lint/correctness/useExhaustiveDependencies: identityKey is a re-fire trigger (read via identityRef inside performHandshake), not used directly in the body
  useEffect(() => {
    if (!opts.enabled) {
      setSession((prev) => ({ ...prev, isAuthenticating: false }));
      return;
    }
    if (typeof window === "undefined") return;

    const cancelled = { current: false };
    // Restore a persisted VERIFIED session first, so a page reload keeps
    // the visitor signed in (instead of re-handshaking anonymously → the
    // sign-in gate). Skipped when the host supplied a fresh identity —
    // that re-handshakes identified and wins. There's no silent re-proof
    // for passkey/FedCM, so when the restored token expires we fall back
    // to a fresh (anonymous) handshake (the gate returns; re-sign-in).
    const restored = identityRef.current ? null : readPersistedIdentifiedSession();
    if (restored) {
      setVisitorToken(restored.token);
      setSession({
        token: restored.token,
        chatId: restored.chatId,
        peopleId: restored.peopleId,
        displayName: restored.displayName,
        isAuthenticating: false,
        error: null,
        verified: true,
      });
      const expiresInMs = Math.max(0, restored.expiresAt - Date.now());
      nextRenewAt.current = restored.expiresAt;
      if (renewTimer.current) clearTimeout(renewTimer.current);
      renewTimer.current = setTimeout(() => {
        if (cancelled.current) return;
        clearPersistedIdentifiedSession();
        performHandshake(cancelled);
      }, expiresInMs);
    } else {
      // Re-runs when `identityKey` changes — e.g. the iframe receives the
      // host's identity over postMessage after the initial anonymous
      // handshake, upgrading the session to identified on the same chat.
      performHandshake(cancelled);
    }

    // Wake-from-sleep recovery — browsers pause `setTimeout` while a
    // tab is suspended (real sleep, OR aggressive background
    // throttling). The scheduled renew may be hours behind real time
    // by the time the user comes back; without this, the next send
    // 401s with `jwt expired` and the visitor sees a generic failure.
    // On `visibilitychange → visible`, if we've passed the scheduled
    // renew time we run a handshake immediately. The handshake itself
    // reschedules the timer.
    const onVisibility = () => {
      if (cancelled.current) return;
      if (typeof document === "undefined" || document.hidden) return;
      if (nextRenewAt.current === 0) return; // pre-first-handshake
      if (Date.now() >= nextRenewAt.current) {
        performHandshake(cancelled);
      }
    };
    document.addEventListener("visibilitychange", onVisibility);

    return () => {
      cancelled.current = true;
      document.removeEventListener("visibilitychange", onVisibility);
      if (renewTimer.current) {
        clearTimeout(renewTimer.current);
        renewTimer.current = null;
      }
    };
    // `identityKey` re-fires the effect when the host identifies the
    // visitor (or swaps identity); `opts.epoch` re-fires it on shutdown
    // (after the stored visitorId was cleared → fresh anonymous identity).
    // `performHandshake` reads the latest identity from `identityRef`.
  }, [opts.enabled, performHandshake, identityKey, opts.epoch]);

  // 401 recovery — Apollo's error link calls this when a NON-handshake
  // request is rejected as Unauthorized (stale / forged / expired /
  // tampered token). We drop the bad token + persisted session and
  // re-handshake: with `requireAuth` that lands on the sign-in gate so
  // the visitor can log in again; otherwise they get a fresh anonymous
  // token and can keep messaging. This is the "auto-logout on a bad
  // session" — without it a doctored `wexio:visitor-session` leaves the
  // widget stuck "verified" but unable to send OR re-login.
  useEffect(() => {
    if (!opts.enabled || typeof window === "undefined") return;
    let recovering = false;
    setOnVisitorUnauthorized(() => {
      if (recovering) return; // collapse a burst of concurrent 401s
      recovering = true;
      clearPersistedIdentifiedSession();
      setVisitorToken(null);
      void performHandshake({ current: false }).finally(() => {
        recovering = false;
      });
    });
    // `webIntegrationMismatch` — distinct from a generic 401. The BE
    // tells us the stored JWT was minted for a different integration
    // (cross-operator visitor whose legacy global localStorage key got
    // eager-migrated into THIS publicKey's slot by `ensureVisitorId` /
    // `readPersistedIdentifiedSession`). Self-heal by clearing the
    // scoped session AND the sticky visitorId for THIS publicKey, then
    // re-handshaking — the next handshake mints fresh, correctly-scoped
    // state. Without this we'd loop: token bad → 401 path drops it →
    // next mount re-migrates the same legacy key → same mismatch.
    setOnVisitorIntegrationMismatch(() => {
      if (recovering) return;
      recovering = true;
      clearPersistedIdentifiedSession();
      setVisitorToken(null);
      try {
        const pk = getPublicKey();
        // Drop the sticky visitorId scoped to THIS publicKey too — the
        // visitorId was likely also migrated from the legacy key and
        // refers to the OTHER operator's People row.
        localStorage.removeItem(visitorIdKey(pk));
      } catch {
        /* private mode — best effort */
      }
      void performHandshake({ current: false }).finally(() => {
        recovering = false;
      });
    });
    return () => {
      setOnVisitorUnauthorized(null);
      setOnVisitorIntegrationMismatch(null);
    };
  }, [opts.enabled, performHandshake]);

  return session;
}

/**
 * Resolve the host-supplied visitor identity for the shell.
 *
 * Embeds (web-component / react-component) set `env.visitorIdentity`
 * directly — they run in the host's JS context. The iframe can't read
 * the host's data, so it receives identity over `postMessage`: this
 * hook announces readiness to the parent (`wexio:widget:ready:v1`) and
 * listens for `wexio:identify:v1`. Returns the env value when present,
 * else whatever arrived over the bridge (`null` until then).
 */
export function useHostVisitorData(env: WidgetEnv): {
  identity: VisitorIdentity | null;
  prefill: VisitorPrefill | null;
} {
  const [received, setReceived] = useState<{
    identity: VisitorIdentity | null;
    prefill: VisitorPrefill | null;
  }>({ identity: null, prefill: null });

  useEffect(() => {
    // Embeds pass these inline on `env`; only the iframe needs the bridge.
    if (env.visitorIdentity || env.visitorPrefill) return;
    if (typeof window === "undefined") return;

    const onMessage = (e: MessageEvent) => {
      const data = e.data;
      if (!data || typeof data !== "object") return;
      // Verified identity → identified handshake. Accept EITHER a signed
      // `jwt` (recommended) OR the legacy `userId`+`userHash` pair.
      if (data.type === "wexio:identify:v1") {
        const u = data.user;
        if (!u || typeof u !== "object") return;
        const hasGoogle = typeof u.googleIdToken === "string";
        const hasJwt = typeof u.jwt === "string";
        const hasHmac = typeof u.userId === "string" && typeof u.userHash === "string";
        if (!hasGoogle && !hasJwt && !hasHmac) return;
        setReceived((prev) => ({
          ...prev,
          identity: {
            googleIdToken: hasGoogle ? u.googleIdToken : undefined,
            jwt: hasJwt ? u.jwt : undefined,
            userId: typeof u.userId === "string" ? u.userId : undefined,
            userHash: typeof u.userHash === "string" ? u.userHash : undefined,
            name: typeof u.name === "string" ? u.name : undefined,
            email: typeof u.email === "string" ? u.email : undefined,
            phone: typeof u.phone === "string" ? u.phone : undefined,
            attributes: u.attributes && typeof u.attributes === "object" ? u.attributes : undefined,
          },
        }));
      } else if (data.type === "wexio:prefill:v1") {
        // Unverified profile → pre-fill / auto-attach the prechat.
        const p = data.prefill;
        if (!p || typeof p !== "object") return;
        setReceived((prev) => ({
          ...prev,
          prefill: {
            name: typeof p.name === "string" ? p.name : undefined,
            email: typeof p.email === "string" ? p.email : undefined,
            phone: typeof p.phone === "string" ? p.phone : undefined,
          },
        }));
      } else if (data.type === "wexio:shutdown:v1") {
        // Logout — forget the host-supplied identity/prefill so the
        // re-handshake (driven by the shell's epoch bump) goes anonymous.
        setReceived({ identity: null, prefill: null });
      }
    };
    window.addEventListener("message", onMessage);
    // Tell the loader we're ready so it replies with the host's identity +
    // prefill. (The loader also sends them proactively on iframe load —
    // this is the fast path / retry against a race.)
    window.parent?.postMessage({ type: "wexio:widget:ready:v1" }, "*");
    return () => window.removeEventListener("message", onMessage);
  }, [env.visitorIdentity, env.visitorPrefill]);

  return {
    identity: env.visitorIdentity ?? received.identity,
    prefill: env.visitorPrefill ?? received.prefill,
  };
}

/**
 * Returns a stable visitor id from localStorage; mints one on first
 * visit. We use a uuid-v4-shaped random string rather than something
 * derived from fingerprinting — operators on privacy-sensitive sites
 * shouldn't see their visitors fingerprinted by the widget.
 *
 * Exported so the passkey sign-in (a separate ceremony, see
 * `usePasskeyAuth`) binds to the SAME sticky visitor id this handshake
 * uses — the BE then attaches the verified passkey to the visitor's
 * existing anonymous contact + chat (anon → identified continuity).
 */
export function ensureVisitorId(): string {
  try {
    const pk = getPublicKey();
    const scopedKey = visitorIdKey(pk);
    const existing = localStorage.getItem(scopedKey);
    if (existing) return existing;
    // Migrate from the legacy global key on first read so a returning
    // visitor keeps their identity on the operator that wrote it. The
    // legacy key is removed in the same step so OTHER operators
    // sharing the same widget origin don't inherit it on their first
    // mount (the whole point of the scoping).
    if (pk) {
      const legacy = localStorage.getItem(LEGACY_VISITOR_ID_KEY);
      if (legacy) {
        localStorage.setItem(scopedKey, legacy);
        localStorage.removeItem(LEGACY_VISITOR_ID_KEY);
        return legacy;
      }
    }
    const fresh = generateVisitorId();
    localStorage.setItem(scopedKey, fresh);
    return fresh;
  } catch {
    // Privacy mode / cookies disabled → use an in-memory id. The
    // visitor loses chat continuity across reloads but the widget
    // still works for the current session.
    return generateVisitorId();
  }
}

function generateVisitorId(): string {
  if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
    return crypto.randomUUID();
  }
  // Fallback for older browsers — still 32 hex chars of entropy.
  const bytes = new Uint8Array(16);
  if (typeof crypto !== "undefined" && crypto.getRandomValues) {
    crypto.getRandomValues(bytes);
  } else {
    for (let i = 0; i < 16; i++) bytes[i] = Math.floor(Math.random() * 256);
  }
  return Array.from(bytes, (b) => b.toString(16).padStart(2, "0")).join("");
}
