"use client";

import { Search } from "lucide-react";
import { useTranslations } from "next-intl";
import type { HomeBlock, WidgetTab } from "@/lib/widget-config";

export function HelpSearchBlock({
  block,
  onOpenTab,
}: {
  block: Extract<HomeBlock, { kind: "help-search" }>;
  onOpenTab: (tab: WidgetTab) => void;
}) {
  const t = useTranslations("home");
  return (
    <button
      type="button"
      onClick={() => onOpenTab("help")}
      className="flex w-full items-center gap-2.5 rounded-wx-lg border border-wx-border bg-wx-bg-elevated px-3.5 py-3 text-left transition-colors hover:bg-wx-bg-elevated-2"
    >
      <Search size={16} className="shrink-0 text-wx-fg-muted" />
      <span className="text-sm text-wx-fg-muted">
        {block.placeholder?.trim() || t("searchPlaceholder")}
      </span>
    </button>
  );
}
