import { DEFAULT_LOCALE, SUPPORTED_LOCALES, type SupportedLocale } from "./i18n";

/**
 * Resolve the active locale on the client. Used by the widget shell
 * to set `NextIntlClientProvider`'s `locale` on mount.
 *
 * Resolution order:
 *
 *   1. `?lang=` URL search param          — explicit dev / marketing override
 *   2. `wexio-locale` cookie              — persisted explicit override
 *   3. operator `localeStrategy`:
 *        - a pinned code (`en` / `uk`)    — use it
 *        - `WEBSITE`                       — host page `<html lang>`
 *        - `AUTO` (or unset)               — fall through to the browser
 *   4. `navigator.language`               — browser preference
 *   5. `DEFAULT_LOCALE`
 *
 * `strategy` comes from the operator's BE config (`WidgetConfig.localeStrategy`).
 * It's the operator's choice of HOW to pick the visitor's language; the
 * explicit `?lang=` / cookie signals still sit above it as dev / preview
 * escape hatches. When `strategy` is omitted the behaviour is identical to
 * the legacy `?lang=` → cookie → `navigator.language` chain.
 *
 * Every raw value is normalised the same way: lower-cased and stripped of
 * its region tag, splitting on BOTH `-` and `_` so `uk-UA`, `uk-UK`, and a
 * POSIX-style `uk_UA` all collapse to `uk` before matching against
 * `SUPPORTED_LOCALES`.
 */
export function detectClientLocale(strategy?: string): SupportedLocale {
  if (typeof window === "undefined") return DEFAULT_LOCALE;

  // 1. Explicit `?lang=` override — wins over everything (dev, marketing
  //    tour, dashboard preview), regardless of the operator's strategy.
  const url = new URL(window.location.href);
  const fromUrl = matchLocale(url.searchParams.get("lang"));
  if (fromUrl) return fromUrl;

  // 2. Persisted explicit override (the cookie middleware sets from `?lang=`).
  const fromCookie = matchLocale(readCookie("wexio-locale"));
  if (fromCookie) return fromCookie;

  // 3. Operator strategy.
  if (strategy && strategy !== "AUTO" && strategy !== "WEBSITE") {
    // Pinned to a specific language. If the operator pinned a code the
    // widget bundle doesn't ship, fall through rather than render a
    // broken/untranslated UI.
    const pinned = matchLocale(strategy);
    if (pinned) return pinned;
  } else if (strategy === "WEBSITE") {
    // Match the host page — `<html lang="…">`, which a site's own
    // language switcher keeps in sync. The widget shares the host
    // document in web-component / react-component mode, so this reads
    // the host's attribute directly. Falls through to the browser when
    // the page declares no (supported) language.
    const fromPage = matchLocale(document.documentElement.lang);
    if (fromPage) return fromPage;
  }

  // 4. Browser preference — also the `AUTO` path.
  const fromNav = matchLocale(navigator.language);
  if (fromNav) return fromNav;

  return DEFAULT_LOCALE;
}

/**
 * Normalise a raw locale-ish string (`"uk-UA"`, `"UK_uk"`, `"en"`) and
 * return it only if its base language is one we ship. `null` for empty /
 * unsupported input so callers can use it in a `??` / `if` chain.
 */
function matchLocale(raw: string | null | undefined): SupportedLocale | null {
  if (!raw) return null;
  const base = raw.toLowerCase().split(/[-_]/)[0];
  return (SUPPORTED_LOCALES as readonly string[]).includes(base) ? (base as SupportedLocale) : null;
}

function readCookie(name: string): string | null {
  const cookies = document.cookie.split(";");
  for (const raw of cookies) {
    const [key, ...rest] = raw.trim().split("=");
    if (key === name) return decodeURIComponent(rest.join("="));
  }
  return null;
}
