import { forwardRef } from "react";

/**
 * "Unread messages" divider — a hairline rule with a centered label,
 * marking where the visitor's unread run begins. The tab scrolls this into
 * the centre of the viewport on open so the visitor lands on the first
 * thing they haven't seen. Forwards a ref so the tab can drive that scroll.
 */
export const UnreadDivider = forwardRef<HTMLDivElement, { label: string }>(({ label }, ref) => (
  <div ref={ref} className="flex items-center gap-2 py-1">
    <span aria-hidden="true" className="h-px flex-1 bg-wx-danger/40" />
    <span className="text-[11px] font-semibold text-wx-danger">{label}</span>
    <span aria-hidden="true" className="h-px flex-1 bg-wx-danger/40" />
  </div>
));
UnreadDivider.displayName = "UnreadDivider";
