"use client";

import { useEffect, useRef } from "react";
import { apiBase } from "./api";
import { getPublicKey } from "./apollo-client";

/** Sender attribution. BE shape uses `from` (visitor / operator / bot
 *  / ai / system). The widget previously read `sender` — keep both
 *  for back-compat so a deploy mismatch doesn't blank the avatar
 *  line. */
export interface RealtimeSender {
  kind: "operator" | "ai" | "bot" | "system" | "visitor";
  name: string;
  avatar?: string;
}

/** Quick-reply chip shape on the wire. BE emits `{ label, value, type }`;
 *  the widget's button renderer expects `{ text, payload, style }`. The
 *  SSE consumer normalises one to the other.
 *
 *  `type === "callback"` is the only widely-used variant — the value
 *  identifies a flow branch the bot routes on. Other types map through
 *  unchanged. */
export interface RealtimeMessageButton {
  label: string;
  value: string;
  type?: string;
}

export interface RealtimeMessageEvent {
  /** Backend message id once persisted; client-temp id while in-flight.
   *  For `kind === 'read-receipt'` this is a synthetic `read-<ts>` id
   *  the BE mints and the visitor ignores. */
  externalMessageId: string;
  /** Optional — the new BE shape omits `direction` and lets the
   *  consumer derive it from `from.kind` (visitor → OUTBOUND, else
   *  INBOUND). Kept for back-compat with older event emitters. */
  direction?: "INBOUND" | "OUTBOUND" | string;
  kind: "text" | "media" | "buttons" | "location" | "typing" | "read-receipt" | string;
  text?: string;
  payload?: unknown;
  /** Quick-reply chips for `kind === 'buttons'` messages. */
  buttons?: RealtimeMessageButton[];
  /** New shape — preferred. */
  from?: RealtimeSender;
  /** Legacy shape — older BE deploys emit this name; keep as a
   *  fallback so a deploy mismatch doesn't lose attribution. */
  sender?: RealtimeSender;
  sentAt?: string;
  /** Set on AI typing events — which step of the assistant turn is
   *  running: `"thinking"` (prep / STT / deciding), `"searching"` (RAG
   *  knowledge lookup), `"typing"` (model producing the answer). Drives
   *  the typing-bubble caption. Absent for operator typing. */
  phase?: "thinking" | "searching" | "typing" | string;
  /** Set when `kind === 'read-receipt'`. Carries the exact message
   *  ids that flipped to READ — the iframe matches against its
   *  local store and upgrades just those bubbles. */
  readReceipt?: {
    messageIds: string[];
    readAt: string;
  };
}

interface UseVisitorRealtimeOpts {
  chatId: string | null;
  token: string | null;
  enabled?: boolean;
  onMessage: (event: RealtimeMessageEvent) => void;
}

/**
 * Opens an SSE stream against the BE's `/api/web/realtime/:chatId`
 * endpoint and fires `onMessage` for each event.
 *
 * **Auth**: the standard browser `EventSource` API doesn't allow
 * custom headers, so the JWT rides on the URL as a `?token=` param.
 * This is fine because (a) the URL never leaves the visitor's
 * browser, (b) the token is short-lived (~10 min), and (c) the BE's
 * `VisitorJwtGuard` accepts it via query in addition to header
 * (small accommodation made for SSE specifically).
 *
 * **Reconnect**: handled by the browser automatically — when the
 * connection drops, `EventSource` retries with backoff. We don't
 * intervene.
 *
 * **Typing events** fire `kind: 'typing'` and don't carry text — the
 * caller renders a "X is typing…" indicator until the next non-typing
 * event for the same chat.
 */
export function useVisitorRealtime({
  chatId,
  token,
  enabled = true,
  onMessage,
}: UseVisitorRealtimeOpts): void {
  // Keep the callback in a ref so changes don't reopen the SSE stream
  // — we'd lose events during the reconnect window otherwise.
  const onMessageRef = useRef(onMessage);
  useEffect(() => {
    onMessageRef.current = onMessage;
  }, [onMessage]);

  useEffect(() => {
    if (!enabled || !chatId || !token) return;
    if (typeof window === "undefined") return;

    // `WebOriginGuard` requires the integration's publicKey on every
    // visitor request. `EventSource` can't set custom headers, so we
    // attach it as a query param — the guard accepts it there (it's
    // already a documented fallback for SSE-style transports).
    const publicKey = getPublicKey();
    if (!publicKey) {
      // Without a publicKey the BE would reject with
      // `webMissingPublicKey`; bail before opening the stream rather
      // than burning a reconnect cycle.
      return;
    }
    const url =
      `${apiBase()}/api/web/realtime/${encodeURIComponent(chatId)}` +
      `?token=${encodeURIComponent(token)}` +
      `&publicKey=${encodeURIComponent(publicKey)}`;
    const source = new EventSource(url, { withCredentials: false });

    const handle = (event: MessageEvent) => {
      try {
        const parsed = JSON.parse(event.data) as RealtimeMessageEvent;
        onMessageRef.current(parsed);
      } catch {
        // Malformed payload — log + skip. The SSE stream itself
        // remains open; one bad frame doesn't kill the connection.
        // eslint-disable-next-line no-console
        console.warn("[wexio] unparseable SSE frame", event.data);
      }
    };

    source.addEventListener("message", handle);
    source.addEventListener("messageUpdate", handle as EventListener);

    return () => {
      source.removeEventListener("message", handle);
      source.removeEventListener("messageUpdate", handle as EventListener);
      source.close();
    };
  }, [chatId, token, enabled]);
}
