"use client";

import { useEffect, useState } from "react";
import { useWidgetEnv } from "./use-widget-env";

export type ThemeMode = "light" | "dark";
export type ThemePreference = ThemeMode | "auto";

/** Visitor-side overrides — sourced from the BE profile query when
 *  Profile is enabled. Honoured only when `allowed` is `true` (i.e.
 *  `themeModeEditable`); when `false`, the operator preference wins
 *  outright and the visitor's saved choice is IGNORED — matches the
 *  `WEB_PROFILE_TAB.md` contract. */
export interface VisitorThemeOpts {
  preference?: ThemePreference | null;
  allowed?: boolean;
}

/**
 * Resolves the active light/dark mode from (in priority order):
 *
 *   1. `?theme=dark|light|auto` URL param         — dashboard preview link
 *   2. `wexio:preview-theme-mode` postMessage     — dashboard live edit
 *   3. **visitor profile** (`visitor.preference`) — BE-persisted choice,
 *      honoured only when `visitor.allowed !== false`
 *   4. `operatorPreference` (config.themeMode)    — operator's saved choice
 *   5. `localStorage["wexio:theme"]`              — visitor's sticky pref
 *      (only honoured when `visitor.allowed !== false`, so the operator's
 *      "force light/dark" lock is respected)
 *   6. `prefers-color-scheme` media query         — visitor OS preference
 *
 * When `themeModeEditable === false` the visitor layers are skipped
 * entirely — operator wins outright (falls through to OS only if operator
 * is `auto`).
 *
 * Writes `data-theme="light|dark"` on the theme root so the
 * CSS-variable blocks in `globals.css` switch atomically. The theme
 * root is `env.themeRoot` when set (the React-component embed points
 * it at its Shadow DOM portal target, keeping theming self-contained),
 * otherwise `<html>` (iframe / web-component builds).
 */
export function useThemeMode(
  operatorPreference?: ThemePreference,
  visitor?: VisitorThemeOpts,
): ThemeMode {
  const [resolved, setResolved] = useState<ThemeMode>("dark");
  const env = useWidgetEnv();
  const themeRoot = env.themeRoot;

  useEffect(() => {
    const url = new URL(window.location.href);
    const urlTheme = url.searchParams.get("theme") as ThemePreference | null;
    const validOperator =
      operatorPreference && isThemePreference(operatorPreference) ? operatorPreference : null;
    const visitorAllowed = visitor?.allowed !== false;
    const validVisitor =
      visitor?.preference && isThemePreference(visitor.preference) ? visitor.preference : null;

    // Resolve the active preference. URL/postMessage previews always win
    // for dashboard tooling. Then: visitor's BE-persisted choice (only
    // when `themeModeEditable`) > operator's forced choice > visitor's
    // localStorage cache (only when allowed) > AUTO/OS.
    const pickPreference = (): ThemePreference => {
      if (urlTheme && isThemePreference(urlTheme)) return urlTheme;
      // Visitor's BE preference (skipped entirely when not allowed).
      if (visitorAllowed && validVisitor && validVisitor !== "auto") {
        return validVisitor;
      }
      if (validOperator && validOperator !== "auto") return validOperator;
      if (visitorAllowed) {
        const cached = localStorage.getItem("wexio:theme") as ThemePreference | null;
        if (cached && isThemePreference(cached)) return cached;
      }
      // Operator's `AUTO` (or unset) — fall through to OS.
      return "auto";
    };

    let preference: ThemePreference = pickPreference();

    const target: HTMLElement = themeRoot ?? document.documentElement;

    const apply = () => {
      const mode: ThemeMode =
        preference === "auto"
          ? window.matchMedia("(prefers-color-scheme: dark)").matches
            ? "dark"
            : "light"
          : preference;
      target.dataset.theme = mode;
      setResolved(mode);
    };

    apply();

    // System pref change — only matters when `preference === "auto"`.
    const media = window.matchMedia("(prefers-color-scheme: dark)");
    const onMedia = () => preference === "auto" && apply();
    media.addEventListener?.("change", onMedia);

    // Live preview override from the parent (dashboard).
    const onMessage = (event: MessageEvent) => {
      if (!event.data || typeof event.data !== "object") return;
      if (event.data.type !== "wexio:preview-theme-mode:v1") return;
      const next = event.data.mode as ThemePreference | undefined;
      if (next && isThemePreference(next)) {
        preference = next;
        apply();
      }
    };
    window.addEventListener("message", onMessage);

    return () => {
      media.removeEventListener?.("change", onMedia);
      window.removeEventListener("message", onMessage);
    };
  }, [operatorPreference, themeRoot, visitor?.preference, visitor?.allowed]);

  return resolved;
}

function isThemePreference(v: unknown): v is ThemePreference {
  return v === "light" || v === "dark" || v === "auto";
}
