"use client";

import { AnimatePresence, motion } from "motion/react";
import { cn } from "@/lib/utils";

interface UnreadBadgeProps {
  /** Unread count. 0 (or less) renders nothing. >99 caps to "99+". */
  count: number;
  /** `sm` — tab-icon scale (default); `md` — launcher-FAB scale. */
  size?: "sm" | "md";
  /** Absolute positioning supplied by the caller (e.g.
   *  `"absolute -top-1.5 -right-2"`). The badge anchors to the nearest
   *  positioned ancestor. */
  className?: string;
}

const SIZE_CLASSES: Record<NonNullable<UnreadBadgeProps["size"]>, string> = {
  sm: "h-3.5 min-w-3.5 px-0.75 text-[8px]",
  md: "h-5 min-w-5 px-1.5 text-[10px]",
};

/**
 * Shared unread-count badge — a red pill that:
 *   - **bounces in** on appear and re-bounces on every count change (a
 *     pronounced springy overshoot, re-keyed on `count`),
 *   - **pulses** continuously while unread: a constant soft halo plus a
 *     blurred disc that expands + fades on a loop (a radiating "light",
 *     not a hard ring),
 *   - **pops out** when the count drops to 0.
 *
 * Used on the bottom-nav messages tab and the launcher FAB so both share
 * one behaviour. The caller positions it via `className` and the parent
 * must NOT be `overflow-hidden` (it would shear the glow — see
 * `bottom-nav.tsx`).
 */
export function UnreadBadge({ count, size = "sm", className }: UnreadBadgeProps) {
  return (
    <AnimatePresence>
      {count > 0 && (
        // OUTER: positioning + appear/disappear + a pop on each count change
        // (re-keyed so it remounts and replays). Scale here is the pop, so
        // it never fights the pulse below.
        <motion.span
          key={count}
          role="status"
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          exit={{ scale: 0 }}
          // Low `damping` → a pronounced springy overshoot (bounce).
          transition={{ type: "spring", stiffness: 600, damping: 9 }}
          className={cn("inline-flex", className)}
          aria-label={`${count} unread`}
        >
          {/* Constant soft halo — blurred disc so the badge always reads as
              gently "lit", not only during the pulse. */}
          <span
            aria-hidden="true"
            className="absolute inset-0 -z-10 rounded-full bg-wx-danger opacity-40 blur-[2px]"
          />
          {/* PULSE: a blurred red disc that expands + fades on a loop. */}
          <motion.span
            aria-hidden="true"
            initial={false}
            animate={{ opacity: [0.5, 0], scale: [1, 1.55] }}
            transition={{
              duration: 1.6,
              ease: "easeOut",
              repeat: Number.POSITIVE_INFINITY,
              repeatDelay: 0.4,
            }}
            className="absolute inset-0 -z-10 rounded-full bg-wx-danger blur-[2px]"
          />
          {/* The crisp badge on top. */}
          <span
            className={cn(
              "relative flex items-center justify-center",
              "rounded-full bg-wx-danger font-bold leading-none text-white",
              SIZE_CLASSES[size],
            )}
          >
            {count > 99 ? "99+" : count}
          </span>
        </motion.span>
      )}
    </AnimatePresence>
  );
}
