import type { MockMessage, MockMessageButton, MockMessageMedia } from "@/dummy";
import { AI_ASSISTANT_NAME } from "@/lib/ai-assistant";

/**
 * Map the BE's `visitorChatHistory` payload into the widget's local
 * `MockMessage` shape. Defensive on every field — history rows arrive
 * as loosely-typed JSON. Reverses the list so the oldest message is
 * first (the BE returns newest-first).
 */
export function mapHistoryToMessages(
  data: { visitorChatHistory: unknown } | null | undefined,
  locale: string,
): MockMessage[] {
  if (!data) return [];
  const raw = data.visitorChatHistory;
  if (!raw || typeof raw !== "object") return [];
  const items = (raw as { items?: unknown }).items;
  if (!Array.isArray(items)) return [];
  return items
    .filter((m): m is Record<string, unknown> => typeof m === "object" && m !== null)
    .map((m, idx): MockMessage => {
      const sender = (m.sender as { kind?: string; name?: string }) ?? {};
      const deliveryStatus =
        typeof m.deliveryStatus === "string"
          ? (m.deliveryStatus as MockMessage["deliveryStatus"])
          : undefined;
      // Quick-reply buttons survive across reloads — the BE persists
      // them on the message row. Previously the mapper dropped this
      // field on the floor, so re-opening the chat after a session
      // refresh showed text bubbles without the chips that were
      // there in the live session.
      // Operator avatar — flows down on the same `sender.avatar`
      // field the SSE-live path uses. Without mapping it here the
      // operator bubbles after a page reload showed the monogram
      // fallback even when the operator had a personal photo set.
      const senderAvatar =
        typeof (sender as { avatar?: unknown }).avatar === "string"
          ? (sender as { avatar: string }).avatar
          : undefined;
      const rawButtons = m.buttons;
      const buttons: MockMessageButton[] | undefined = Array.isArray(rawButtons)
        ? rawButtons
            .filter((b): b is Record<string, unknown> => typeof b === "object" && b !== null)
            .map((b) => {
              // The BE shape uses `{ label, value }`; the widget's
              // local `MockMessageButton` shape uses `{ text, payload }`.
              const label =
                typeof b.label === "string" ? b.label : typeof b.text === "string" ? b.text : "";
              const value =
                typeof b.value === "string"
                  ? b.value
                  : typeof b.payload === "string"
                    ? b.payload
                    : label;
              return { text: label, payload: value };
            })
            .filter((b) => !!b.text)
        : undefined;
      const senderKind = (sender.kind as MockMessage["sender"]["kind"]) ?? "operator";
      // Bot / AI senders read as AI_ASSISTANT_NAME in the bubble regardless of
      // what the BE labels them. Operator names flow through
      // untouched so a "Real human is now here" handoff still feels
      // human.
      const senderName =
        senderKind === "ai" || senderKind === "bot" ? AI_ASSISTANT_NAME : (sender.name ?? "");
      const media = normalizeBackendMedia(m.media);
      const createdAt = typeof m.createdAt === "string" ? m.createdAt : undefined;
      return {
        id: String(m.id ?? `m-${idx}`),
        direction: (m.direction === "INBOUND" ? "INBOUND" : "OUTBOUND") as "INBOUND" | "OUTBOUND",
        text: typeof m.text === "string" ? m.text : "",
        ageLabel: formatAge(createdAt, locale),
        // Keep the raw timestamp for date-separator grouping (ageLabel is
        // only the time-of-day string).
        ...(createdAt ? { createdAt } : {}),
        sender: {
          kind: senderKind,
          name: senderName,
          ...(senderAvatar ? { avatar: senderAvatar } : {}),
        },
        ...(media.length > 0 ? { media } : {}),
        ...(buttons && buttons.length > 0 ? { buttons } : {}),
        ...(deliveryStatus ? { deliveryStatus } : {}),
      };
    })
    .reverse();
}

/**
 * Normalize the BE's media shape into the widget's local
 * `MockMessageMedia` shape. Accepts either:
 *   - history rows: `media: [{ url, mimeType, filename, ... }]`
 *   - SSE media event: `media: { mediaId: { url, mimeType, filename, ... } }`
 *
 * The BE uses `mimeType` (camelCase) while the widget's renderer
 * (`MessageBubble`, `Media`, `media-lightbox`) all key off `mimetype`
 * (lowercase). Renaming is the one transform we have to do here.
 */
export function normalizeBackendMedia(raw: unknown): MockMessageMedia[] {
  if (!raw) return [];
  const items: unknown[] = Array.isArray(raw)
    ? raw
    : typeof raw === "object" && raw !== null
      ? [
          // SSE single-attachment event. The CURRENT shape carries the media
          // fields on the object itself: `{ mediaId: string, url, mimeType,
          // filename, thumbnailUrl, caption }`. An older shape nested the
          // whole Media doc under `mediaId` — unwrap that ONLY when it's an
          // object (the new `mediaId` is a bare string id, not the doc).
          typeof (raw as { mediaId?: unknown }).mediaId === "object" &&
          (raw as { mediaId?: unknown }).mediaId !== null
            ? (raw as { mediaId: unknown }).mediaId
            : raw,
        ]
      : [];
  return items
    .filter((m): m is Record<string, unknown> => typeof m === "object" && m !== null)
    .map((m) => {
      const url = typeof m.url === "string" ? m.url : "";
      const mimetype =
        typeof m.mimeType === "string"
          ? m.mimeType
          : typeof m.mimetype === "string"
            ? m.mimetype
            : "";
      const alt =
        typeof m.filename === "string" ? m.filename : typeof m.alt === "string" ? m.alt : "";
      return { url, mimetype, alt };
    })
    .filter((m) => !!m.url && !!m.mimetype);
}

/**
 * Decode the recorder bar's raw base64 payload back into a Blob so
 * the optimistic visitor bubble can play the audio locally — the
 * BE round-trip would otherwise leave the visitor staring at a
 * silent bubble for a beat. Match the recorder's emitted mime type
 * exactly so `<audio>` picks the right decoder.
 */
export function base64ToBlob(base64: string, mimetype: string): Blob {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return new Blob([bytes], { type: mimetype });
}

/** Format a timestamp into a short locale-aware "h:mm" age label. */
function formatAge(timestamp: string | undefined, locale: string): string {
  if (!timestamp) return "";
  try {
    return new Date(timestamp).toLocaleTimeString(locale, {
      hour: "numeric",
      minute: "2-digit",
    });
  } catch {
    return "";
  }
}
