"use client";

import { ChevronRight, Sparkles } from "lucide-react";
import { useLocale, useTranslations } from "next-intl";
import { getMockNewsItems } from "@/dummy";
import { useVisitorNewsListQuery } from "@/lib/graphql/queries/generated/news.generated";
import { useWidgetEnv } from "@/lib/use-widget-env";
import type { HomeBlock, WidgetTab } from "@/lib/widget-config";
import { extractTitlesFromList, extractTitlesFromRaw } from "../helpers";
import { BlockCard } from "../shared";

export function NewsPreviewBlock({
  block,
  onOpenTab,
  isDummy,
}: {
  block: Extract<HomeBlock, { kind: "news-preview" }>;
  onOpenTab: (tab: WidgetTab) => void;
  isDummy: boolean;
}) {
  const t = useTranslations("home");
  const tDemo = useTranslations("demo");
  const locale = useLocale();
  const env = useWidgetEnv();
  const max = Math.max(1, Math.min(6, block.maxItems ?? 3));

  // Same prefetch short-circuit as the News tab — render the
  // dashboard-supplied list instead of hitting the visitor feed when
  // the preview pane has already loaded the operator's posts.
  // Empty arrays don't count (still-loading edge case) — fall through
  // to the BE query so the block doesn't render permanently empty.
  const previewFeed = !isDummy ? env.previewData?.newsPosts : undefined;
  const hasPreview = Array.isArray(previewFeed) && previewFeed.length > 0;

  // Real path queries the consolidated `visitorNewsList` the News
  // tab uses. Skipped in dummy mode — we render bundled
  // getMockNewsItems() instead so the dashboard preview's "demo" toggle
  // gets a populated card.
  const { data, error, loading } = useVisitorNewsListQuery({
    variables: { args: { locale, limit: max } },
    skip: isDummy || hasPreview,
  });

  const titles = isDummy
    ? getMockNewsItems(tDemo)
        .slice(0, max)
        .map((n) => n.title)
    : hasPreview
      ? extractTitlesFromRaw(previewFeed).slice(0, max)
      : extractTitlesFromList(data?.visitorNewsList.items, error).slice(0, max);

  // Live mode + no items → hide the card entirely rather than showing a
  // header with nothing under it. Loading shows the header but no rows so
  // the layout doesn't jump when items arrive.
  if (!isDummy && !loading && titles.length === 0) return null;

  return (
    <BlockCard
      title={block.title?.trim() || t("newsPreviewTitle")}
      onOpenAll={() => onOpenTab("news")}
    >
      <ul className="flex flex-col">
        {titles.map((title, i) => (
          // biome-ignore lint/suspicious/noArrayIndexKey: list is order-stable
          <li key={i}>
            <button
              type="button"
              onClick={() => onOpenTab("news")}
              className="flex w-full items-center gap-2 px-3.5 py-2.5 text-left transition-colors hover:bg-wx-bg-elevated-2"
            >
              <Sparkles size={14} className="shrink-0 text-wx-fg-muted" />
              <span className="min-w-0 flex-1 truncate text-sm text-wx-fg">{title}</span>
              <ChevronRight size={14} className="shrink-0 text-wx-fg-subtle" />
            </button>
          </li>
        ))}
      </ul>
    </BlockCard>
  );
}
