"use client";

import type { ComponentType, SVGProps } from "react";

/**
 * Real brand SVG marks for channel-switcher inline tiles. lucide-react
 * doesn't ship brand icons (trademarks), so we inline the canonical
 * Simple Icons paths for the few channels operators actually use.
 *
 * Each component takes `size` (square px) + `className` so it slots
 * into the same call sites as `lucide-react` glyphs. `fill="currentColor"`
 * means the tile's text colour controls the mark — operators get
 * tinted brand marks when their palette overrides `--wx-fg`.
 */

interface BrandIconProps {
  size?: number;
  className?: string;
}

function svgProps(size: number, className?: string): SVGProps<SVGSVGElement> {
  return {
    xmlns: "http://www.w3.org/2000/svg",
    width: size,
    height: size,
    viewBox: "0 0 24 24",
    fill: "currentColor",
    "aria-hidden": "true",
    className,
  };
}

