"use client";

import { NextIntlClientProvider, useLocale, useMessages } from "next-intl";
import { type ReactNode, useEffect, useState } from "react";
import { useWidgetConfig } from "@/lib/use-widget-config";

/**
 * Demo content lives in separate `messages/demo.{locale}.json` files
 * that are **not** in the always-loaded i18n bundle — production
 * visitors never download them. This wrapper dynamically imports the
 * demo namespace and merges it into the next-intl provider ONLY when
 * the widget runs in demo mode (`isDummy` — the operator dashboard
 * preview / marketing site). In live mode the demo builders are never
 * called, so the namespace isn't needed and nothing extra is fetched.
 */
export function DemoMessages({ children }: { children: ReactNode }) {
  const { isDummy } = useWidgetConfig();
  const locale = useLocale();
  const base = useMessages();
  // A caller may already supply the demo namespace (tests, or an SSR
  // path that pre-merged it) — then there's nothing to fetch.
  const baseHasDemo = "demo" in (base as Record<string, unknown>);
  const [demo, setDemo] = useState<Record<string, unknown> | null>(null);

  useEffect(() => {
    if (!isDummy || baseHasDemo) return;
    let active = true;
    loadDemoMessages(locale).then((m) => {
      if (active) setDemo(m);
    });
    return () => {
      active = false;
    };
  }, [isDummy, baseHasDemo, locale]);

  // Live / production, or the namespace is already present — pass
  // through with the lean bundle (no extra fetch).
  if (!isDummy || baseHasDemo) return <>{children}</>;
  // Demo mode, but the lazily-imported namespace hasn't landed yet —
  // hold the tree so builders never read missing keys (e.g. the
  // messages tab seeds its conversation once on mount).
  if (!demo) return null;
  return (
    <NextIntlClientProvider locale={locale} messages={{ ...base, demo }}>
      {children}
    </NextIntlClientProvider>
  );
}

/** Per-locale dynamic import so each demo bundle is its own chunk,
 *  fetched on demand. Unknown locales fall back to English. */
async function loadDemoMessages(locale: string): Promise<Record<string, unknown>> {
  switch (locale) {
    case "uk":
      return (await import("@/messages/demo.uk.json")).default;
    default:
      return (await import("@/messages/demo.en.json")).default;
  }
}
