"use client";

import { X } from "lucide-react";
import { AnimatePresence, motion } from "motion/react";
import { useTranslations } from "next-intl";
import { AI_ASSISTANT_NAME } from "@/lib/ai-assistant";
import { stripHtml } from "@/lib/strip-html";
import type { UnreadPeekMessage } from "@/lib/use-visitor-unread";
import { useWidgetConfig } from "@/lib/use-widget-config";
import { cn } from "@/lib/utils";

interface LauncherPeekProps {
  message: UnreadPeekMessage | null;
  /** Visitor tapped the body of the peek → open the panel directly
   *  on the Messages tab. */
  onOpen: () => void;
  /** Visitor dismissed the peek (X chip). Doesn't mark read — just
   *  hides until the next inbound. */
  onDismiss: () => void;
  /** Visitor tapped a quick-reply button. The shell sends the
   *  payload as a visitor message, then opens the panel so the
   *  visitor sees the conversation. */
  onSendButton: (payload: string, text: string) => void;
  /** Which corner the launcher + panel anchor to — the peek pins to
   *  the SAME side. Defaults to `"right"`. */
  position?: "left" | "right";
  /** Anchor to the host `<div>` (`absolute`) instead of the viewport
   *  (`fixed`). Set by the React-component embed — see `WidgetEnv.embedded`. */
  embedded?: boolean;
}

/**
 * Floating preview pinned above the closed launcher FAB — surfaces
 * the latest unread operator message so visitors can read & quick-
 * reply without opening the panel.
 *
 * **Composition** is two stacked surfaces (per Day-12 design pass):
 *
 *   1. **Text bubble** — message body, dismiss X. Tapping the body
 *      opens the panel on Messages. No avatar, no sender label —
 *      visitors recognise messages from the FAB context.
 *
 *   2. **Quick-reply chips** — each chip is its own pill, stacked
 *      vertically below the text bubble (NOT inside it). Tap →
 *      send the payload as the visitor's reply + open the panel.
 *
 * **Layout**: anchored bottom-right above the launcher, max-width
 * 300. Stacked block lets the buttons read as discrete tap targets
 * rather than a chip row crammed into the bubble.
 */
export function LauncherPeek({
  message,
  onOpen,
  onDismiss,
  onSendButton,
  position = "right",
  embedded = false,
}: LauncherPeekProps) {
  const t = useTranslations("peek");
  const onLeft = position === "left";
  return (
    <AnimatePresence>
      {message && (
        <motion.div
          key={message.id}
          // Bouncy pop-in from lower + smaller so the peek "springs up" from
          // the launcher rather than just fading; low damping = a little
          // overshoot.
          initial={{ opacity: 0, y: 18, scale: 0.88 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          exit={{ opacity: 0, y: 8, scale: 0.96 }}
          transition={{ type: "spring", stiffness: 440, damping: 20 }}
          className={cn(
            "bottom-24 z-40 flex w-[300px] flex-col gap-2",
            embedded ? "absolute" : "fixed",
            onLeft ? "left-4" : "right-4",
          )}
          role="dialog"
          aria-label={t("newMessage")}
        >
          {/* Text bubble — message body + dismiss. Tap the body to
              open the panel; X dismisses without marking read.
              TipTap operator content arrives as HTML; the peek isn't
              the right surface for block rendering (it sits inside a
              `<button>`), so we collapse to a plain-text preview. */}
          {message.text && (
            // Lifts on hover to signal it's tappable (opens the panel).
            <motion.div
              whileHover={{ y: -3 }}
              transition={{ type: "spring", stiffness: 400, damping: 24 }}
              className={cn(
                "relative rounded-wx-lg border border-wx-border bg-wx-bg",
                "p-4 pr-9 text-wx-fg",
                "shadow-[0_16px_40px_rgba(0,0,0,0.16)]",
              )}
            >
              <button
                type="button"
                onClick={onDismiss}
                aria-label={t("dismiss")}
                className={cn(
                  "absolute top-2 right-2 flex h-6 w-6 items-center justify-center rounded-full",
                  "text-wx-fg-muted transition-colors hover:bg-wx-bg-elevated hover:text-wx-fg",
                )}
              >
                <X size={12} />
              </button>
              <button
                type="button"
                onClick={onOpen}
                className={cn("block w-full text-left", "transition-opacity hover:opacity-90")}
              >
                <PeekSender sender={message.sender} />
                <span
                  className={cn(
                    "mt-1.5 block text-sm leading-relaxed",
                    "wrap-anywhere",
                    // Cap very long operator messages in the peek — it's a
                    // preview, not the full thread. Truncates with an ellipsis
                    // after 10 lines; tapping opens the panel to read it all.
                    "line-clamp-10",
                  )}
                >
                  {stripHtml(message.text)}
                </span>
              </button>
            </motion.div>
          )}

          {/* Quick-reply chips — discrete cards stacked below the
              text bubble. Each is its own tap target with the same
              brand-styled pill we use under chat bubbles. */}
          {message.buttons.length > 0 && (
            <div className={cn("flex flex-col gap-1.5", onLeft ? "items-start" : "items-end")}>
              {message.buttons.map((btn) => (
                <motion.button
                  key={btn.payload}
                  type="button"
                  onClick={() => onSendButton(btn.payload, btn.text)}
                  whileHover={{ y: -1 }}
                  whileTap={{ scale: 0.96 }}
                  transition={{ type: "spring", stiffness: 480, damping: 26 }}
                  className={cn(
                    // Idle: clean `wx-bg` surface (matches the
                    // outgoing-side message bubbles) lifted by a
                    // soft shadow so it reads as a tap target.
                    // Hover: fills with full brand → text inverts
                    // to the primary foreground.
                    "max-w-full rounded-full bg-wx-bg px-3.5 py-2 text-sm font-medium text-wx-primary",
                    "transition-colors hover:bg-wx-primary hover:text-wx-primary-fg",
                    "shadow-[0_4px_12px_rgba(0,0,0,0.08)]",
                  )}
                >
                  {btn.text}
                </motion.button>
              ))}
            </div>
          )}
        </motion.div>
      )}
    </AnimatePresence>
  );
}

/**
 * Sender header rendered above the peek preview text — avatar +
 * display name + role suffix (when no name is configured). Mirrors
 * the bubble attribution inside the conversation so visitors see who
 * pinged them before they tap to open. Falls back to a neutral
 * monogram if the operator hasn't uploaded an avatar.
 */
function PeekSender({ sender }: { sender: UnreadPeekMessage["sender"] }) {
  const { config } = useWidgetConfig();
  const t = useTranslations("peek");
  const isGaia = sender.kind === "ai" || sender.kind === "bot";
  // AI / bot ALWAYS reads as AI_ASSISTANT_NAME regardless of what label the BE
  // attached ("Bot", "WEB widget", an internal handle, …). Matches
  // the in-thread bubble + typing indicator so visitors see one
  // consistent assistant identity. Operator names flow through;
  // empty operator name falls back to the role label.
  const displayName = isGaia ? AI_ASSISTANT_NAME : (sender.name?.trim() ?? "");
  const roleLabel = displayName ? null : sender.kind === "operator" ? t("operator") : null;
  const aiAvatarUrl = config.messenger?.aiAssistantAvatar ?? null;
  return (
    <span className="flex items-center gap-2 text-xs">
      {isGaia ? (
        // Operator-configured AI assistant avatar wins. When unset, we
        // render no avatar at all (matches the in-thread bubble's
        // explicit-opt-in behaviour — no Wexio brand-mark fallback so
        // the AI doesn't visually advertise the host product).
        aiAvatarUrl ? (
          <span
            role="img"
            aria-label={t("aiAssistant")}
            className="relative flex h-5 w-5 shrink-0 items-center justify-center overflow-hidden rounded-full bg-wx-bg-elevated shadow-sm"
          >
            {/* biome-ignore lint/performance/noImgElement: uploaded image of arbitrary host/dimensions; next/image needs known sizes + an allowlist */}
            <img
              src={aiAvatarUrl}
              alt=""
              className="h-full w-full object-cover"
              loading="eager"
              decoding="async"
            />
          </span>
        ) : null
      ) : sender.avatar ? (
        // biome-ignore lint/performance/noImgElement: uploaded image of arbitrary host/dimensions; next/image needs known sizes + an allowlist
        <img
          src={sender.avatar}
          alt={displayName || roleLabel || ""}
          className="h-5 w-5 shrink-0 rounded-full object-cover"
        />
      ) : (
        <span
          className={cn(
            "flex h-5 w-5 shrink-0 items-center justify-center rounded-full",
            "bg-wx-bg-elevated text-[9px] font-semibold text-wx-fg-muted",
          )}
        >
          {/* Operator monogram — prefer initials from the operator's
              own name ("RL" for "Ralph J. Lesperance") over a
              generic role-label first letter. Same logic the message
              bubble's BotAvatar uses, so the peek and the
              in-thread avatar stay visually identical. */}
          {peekInitialsOf(displayName || roleLabel || "")}
        </span>
      )}
      <span className="font-medium text-wx-fg-muted">{displayName || roleLabel}</span>
    </span>
  );
}

/**
 * Compact initials extractor for the peek's monogram fallback.
 * Mirrors `initialsOf` in `messages-tab.tsx`:
 *   "Ralph J. Lesperance"   → "RL"
 *   "Operator"              → "O"
 *   "" / "  "               → ""
 * Kept local to avoid the launcher peek picking up the messages-tab
 * import graph (Apollo, animated icons, etc) for one function.
 */
function peekInitialsOf(name: string): string {
  const words = name
    .trim()
    .split(/\s+/)
    .map((w) => w.replace(/[^\p{L}\p{N}]/gu, ""))
    .filter((w) => w.length > 0);
  if (words.length === 0) return "";
  if (words.length === 1) return words[0].charAt(0).toUpperCase();
  return words[0].charAt(0).toUpperCase() + words[words.length - 1].charAt(0).toUpperCase();
}
