"use client";

import { AnimatePresence, motion } from "motion/react";
import { useTranslations } from "next-intl";
import {
  ChevronDownIcon,
  type ChevronDownIconHandle,
  MessageSquareIcon,
  type MessageSquareIconHandle,
} from "@/components/widget/icons/animated";
import { UnreadBadge } from "@/components/widget/unread-badge";
import { useIconHover } from "@/lib/use-icon-hover";
import { cn } from "@/lib/utils";

interface WidgetLauncherProps {
  isOpen: boolean;
  onToggle: () => void;
  /** Unread count surfaced as a pill on the FAB. Zero hides the
   *  badge entirely; 99+ caps to `99+` to keep the pill width bounded. */
  unreadCount?: number;
  /** Which bottom corner the FAB anchors to. Defaults to `"right"`. */
  position?: "left" | "right";
  /** Anchor to the host `<div>` (`absolute`) instead of the viewport
   *  (`fixed`). Set by the React-component embed — see `WidgetEnv.embedded`. */
  embedded?: boolean;
}

/**
 * Floating launcher. Theme-invariant brand surface (`--wx-launcher-bg`)
 * so the FAB reads as a wexio mark on any host page regardless of
 * light/dark preference.
 *
 * Icon morph between chat-bubble (closed) and X (open) via
 * `AnimatePresence`. Each lucide-animated icon's internal animation
 * fires when the **button** is hovered (not the icon itself) — wired
 * via `useIconHover` since the icon receives pointer events through
 * the button.
 */
export function WidgetLauncher({
  isOpen,
  onToggle,
  unreadCount = 0,
  position = "right",
  embedded = false,
}: WidgetLauncherProps) {
  const t = useTranslations("launcher");
  const messageHover = useIconHover<MessageSquareIconHandle>();
  const closeHover = useIconHover<ChevronDownIconHandle>();
  const activeHandlers = isOpen ? closeHover.parentHandlers : messageHover.parentHandlers;
  // Hide the badge while the panel is open — the visitor's already
  // looking at the chat. (UnreadBadge handles the 99+ cap itself.)
  const showBadge = !isOpen && unreadCount > 0;

  return (
    <motion.button
      type="button"
      onClick={onToggle}
      aria-label={isOpen ? t("close") : t("open")}
      whileHover={{ scale: 1.05 }}
      whileTap={{ scale: 0.92 }}
      transition={{ type: "spring", stiffness: 400, damping: 22 }}
      // Drive the icon's hover animation from motion's POINTER-based hover
      // (not React's synthetic `onMouseEnter`). In the react-component's
      // Shadow DOM, synthetic mouse-enter is unreliable — the FAB still
      // scaled (motion's own hover) but the icon never wiggled. `onHoverStart`
      // / `onHoverEnd` are pointer-based and fire in a shadow root. The
      // spread below keeps `onFocus`/`onBlur` for keyboard parity.
      onHoverStart={activeHandlers.onMouseEnter}
      onHoverEnd={activeHandlers.onMouseLeave}
      {...activeHandlers}
      className={cn(
        embedded ? "absolute" : "fixed",
        "bottom-4 z-50",
        position === "left" ? "left-4" : "right-4",
        "flex h-14 w-14 items-center justify-center rounded-full",
        "bg-wx-launcher-bg text-wx-launcher-fg",
        "shadow-[0_8px_24px_rgba(0,0,0,0.18)]",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wx-launcher-bg focus-visible:ring-offset-2 focus-visible:ring-offset-white",
      )}
    >
      <UnreadBadge
        count={showBadge ? unreadCount : 0}
        size="md"
        className="absolute -top-1 -right-1 z-10"
      />
      <AnimatePresence mode="wait" initial={false}>
        {isOpen ? (
          <motion.span
            key="x"
            initial={{ opacity: 0, rotate: -90, scale: 0.7 }}
            animate={{ opacity: 1, rotate: 0, scale: 1 }}
            exit={{ opacity: 0, rotate: 90, scale: 0.7 }}
            transition={{ duration: 0.18 }}
          >
            <ChevronDownIcon ref={closeHover.iconRef} size={24} />
          </motion.span>
        ) : (
          <motion.span
            key="chat"
            initial={{ opacity: 0, rotate: 90, scale: 0.7 }}
            animate={{ opacity: 1, rotate: 0, scale: 1 }}
            exit={{ opacity: 0, rotate: -90, scale: 0.7 }}
            transition={{ duration: 0.18 }}
          >
            <MessageSquareIcon
              ref={messageHover.iconRef}
              size={24}
              // `lucide-animated` icons render a wrapping <div>
              // (props extend HTMLAttributes<HTMLDivElement>), so
              // plain `fill-*` utilities land on the div and never
              // reach the SVG. Reach in with an arbitrary selector
              // and override the icon's `stroke` too — these glyphs
              // are stroke-only by default, so just setting `fill`
              // gives you a filled outline, not a true silhouette.
              // Light mode → white; dark mode → brand-dark `#121314`
              // (`--wx-bg` in dark; `--wx-primary` flips to white).
              className="[&_svg]:fill-wx-launcher-fg [&_svg]:stroke-wx-launcher-fg dark:[&_svg]:fill-wx-bg dark:[&_svg]:stroke-wx-bg"
            />
          </motion.span>
        )}
      </AnimatePresence>
    </motion.button>
  );
}
