"use client";

import { motion } from "motion/react";
import { useTranslations } from "next-intl";
import { cn } from "@/lib/utils";

interface BrandingFooterProps {
  className?: string;
}

/**
 * "Powered by Wexio" badge. Tiny, no border, slides up from below
 * with a fade on first paint.
 *
 * **Inline placement** (not absolute) — earlier iterations used
 * absolute positioning so the badge floated over content, but on
 * the Messages tab that hid the composer's bottom edge. Inline
 * means it reserves a small line of layout space at the bottom of
 * the panel, sitting under the bottom nav (list routes) or under
 * the composer (drill-in routes). The motion entry preserves the
 * "fade up from below" feel without the overlap.
 *
 * Paid white-label plans hide the badge entirely
 * (`config.branding.hidden`), checked at the shell level — this
 * component just renders.
 */
export function BrandingFooter({ className }: BrandingFooterProps) {
  const t = useTranslations("branding");
  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.32, delay: 0.15, ease: "easeOut" }}
      className={cn(
        "flex items-center justify-center gap-1 bg-wx-bg px-4 py-1.5 text-[10px] font-medium text-wx-fg-subtle",
        className,
      )}
    >
      <span>{t("poweredBy")}</span>
      <a
        href="https://wexio.io?ref=widget"
        target="_blank"
        rel="noopener"
        className="font-semibold text-wx-fg-muted transition-colors hover:text-wx-fg"
      >
        {t("wexio")}
      </a>
    </motion.div>
  );
}
