"use client";

import { useTranslations } from "next-intl";
import { Button } from "@/components/ui/button";
import {
  ArrowLeftIcon,
  type ArrowLeftIconHandle,
  XIcon,
  type XIconHandle,
} from "@/components/widget/icons/animated";
import { useIconHover } from "@/lib/use-icon-hover";
import { cn } from "@/lib/utils";
import { SoundToggle } from "./sound-toggle";

interface ConversationHeaderProps {
  title: string;
  subtitle?: string;
  organizationLogoUrl?: string | null;
  muted: boolean;
  onToggleMute: () => void;
  /** Omit when there's nowhere to go back to (Messages is the only
   *  enabled tab) — the back button hides entirely so the visitor
   *  doesn't see a dead control. */
  onBack?: () => void;
  onClose: () => void;
  /** Expand toggle — present only on routes where the widget can
   *  widen (messages, single article). Omitting it hides the chip. */
  expanded?: boolean;
  onToggleExpand?: () => void;
}

/**
 * Sticky conversation header for the Messages tab. Back arrow + Wexio
 * mark + sender name & subtitle + close button. Replaces the generic
 * widget chrome while the visitor is in a conversation.
 *
 * Both animated icons (`ArrowLeftIcon`, `XIcon`) animate on the
 * parent button's hover — `useIconHover` propagates the hover signal
 * via ref handles so visitors see motion when they hover a tap
 * target, not when they happen to land on the SVG itself.
 */
export function ConversationHeader({
  title,
  subtitle,
  organizationLogoUrl,
  muted,
  onToggleMute,
  onBack,
  onClose,
  expanded,
  onToggleExpand,
}: ConversationHeaderProps) {
  const t = useTranslations("header");
  const tHeader = useTranslations("header");
  const back = useIconHover<ArrowLeftIconHandle>();
  const close = useIconHover<XIconHandle>();

  return (
    <header className={cn("flex items-center gap-3 border-b border-wx-border bg-wx-bg px-3 py-3")}>
      {onBack && (
        <Button
          type="button"
          variant="ghost"
          size="icon"
          aria-label={t("back")}
          onClick={onBack}
          className="shrink-0"
          {...back.parentHandlers}
        >
          <ArrowLeftIcon ref={back.iconRef} size={18} />
        </Button>
      )}
      {organizationLogoUrl && (
        <span className="h-9 w-9 shrink-0 overflow-hidden rounded-full">
          {/* biome-ignore lint/performance/noImgElement: uploaded image of arbitrary host/dimensions; next/image needs known sizes + an allowlist */}
          <img src={organizationLogoUrl} alt={title} className="h-full w-full object-cover" />
        </span>
      )}
      <div className="min-w-0 flex-1">
        <p className="truncate text-sm font-semibold text-wx-fg">{title}</p>
        {subtitle && <p className="truncate text-xs text-wx-fg-muted">{subtitle}</p>}
      </div>
      <SoundToggle muted={muted} onToggle={onToggleMute} />
      {onToggleExpand && (
        <Button
          type="button"
          variant="ghost"
          size="icon"
          aria-label={expanded ? tHeader("collapse") : tHeader("expand")}
          onClick={onToggleExpand}
          className="shrink-0"
        >
          <ExpandGlyph expanded={!!expanded} />
        </Button>
      )}
      <Button
        type="button"
        variant="ghost"
        size="icon"
        aria-label={t("close")}
        onClick={onClose}
        className="shrink-0"
        {...close.parentHandlers}
      >
        <XIcon ref={close.iconRef} size={18} />
      </Button>
    </header>
  );
}

/**
 * Inline Maximize2 / Minimize2 — keeps `ConversationHeader`'s import
 * list tight without pulling another file. Lucide-react ships these
 * as plain SVG components.
 */
function ExpandGlyph({ expanded }: { expanded: boolean }) {
  if (expanded) {
    return (
      // Minimize2
      <svg
        xmlns="http://www.w3.org/2000/svg"
        width="18"
        height="18"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
        aria-hidden="true"
      >
        <polyline points="4 14 10 14 10 20" />
        <polyline points="20 10 14 10 14 4" />
        <line x1="14" y1="10" x2="21" y2="3" />
        <line x1="3" y1="21" x2="10" y2="14" />
      </svg>
    );
  }
  return (
    // Maximize2
    <svg
      xmlns="http://www.w3.org/2000/svg"
      width="18"
      height="18"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      aria-hidden="true"
    >
      <polyline points="15 3 21 3 21 9" />
      <polyline points="9 21 3 21 3 15" />
      <line x1="21" y1="3" x2="14" y2="10" />
      <line x1="3" y1="21" x2="10" y2="14" />
    </svg>
  );
}
