/**
 * Collapse a (potentially TipTap-authored) HTML string down to plain
 * text suitable for preview chips — launcher peek, recent-message
 * block, browser tab title. Decodes entities and normalises whitespace.
 *
 * Not a sanitizer. Don't use this to defang untrusted HTML for
 * display; the BE-side sanitiser owns that. This helper exists
 * because peek surfaces sit inside `<button>` elements, where
 * rendering block-level HTML (`<p>`, `<ul>`, `<figure>`, …) yields
 * invalid markup. Stripping to a single line keeps the markup valid
 * and the preview readable.
 */
export function stripHtml(input: string | null | undefined): string {
  if (!input) return "";
  // Quick path — no tag opener present, nothing to strip.
  if (!/[<&]/.test(input)) return input;
  if (typeof document !== "undefined") {
    const el = document.createElement("div");
    el.innerHTML = input;
    return (el.textContent ?? "").replace(/\s+/g, " ").trim();
  }
  // SSR / build-time fallback — coarse regex sweep. The widget runs
  // client-only, but `next build` evaluates the module graph during
  // prerender so we avoid throwing on `document`.
  return input
    .replace(/<[^>]*>/g, "")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, " ")
    .trim();
}
