"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import { MUTE_STORAGE_KEY, resolveSoundUrl } from "./sounds";
import type { WidgetSounds } from "./widget-config";

/**
 * Plays notification sounds for inbound + outbound messages.
 *
 * Audio elements are preloaded once on mount + reused across plays
 * (avoids the cold-start latency of `new Audio(url)` on every event).
 * `playInbound` / `playOutbound` are stable refs — pass them straight
 * to event listeners without `useCallback` gymnastics.
 *
 * **Visitor mute wins.** Visitors who tap the mute toggle persist the
 * preference in `localStorage["wexio:sound-muted"]`. Operator-level
 * `sounds.enabled` is the *default* (audible) but mute always overrides.
 *
 * Browser autoplay policy: most browsers block audio until the user
 * has interacted with the page. The first `play()` call inside a
 * click handler unlocks subsequent silent triggers (e.g. SSE inbound
 * fires after the visitor sent their first message → already
 * unlocked). We swallow `NotAllowedError` instead of crashing.
 */
export function useSoundPlayer(sounds: WidgetSounds | null) {
  const [muted, setMuted] = useState(false);
  const inboundRef = useRef<HTMLAudioElement | null>(null);
  const outboundRef = useRef<HTMLAudioElement | null>(null);

  // Read persisted mute preference on first mount. Without this the
  // toggle would reset between page reloads — bad UX.
  useEffect(() => {
    if (typeof window === "undefined") return;
    const stored = localStorage.getItem(MUTE_STORAGE_KEY);
    setMuted(stored === "1");
  }, []);

  // (Re)preload audio elements whenever the sound config changes.
  useEffect(() => {
    if (typeof window === "undefined") return;
    inboundRef.current?.pause();
    outboundRef.current?.pause();

    const inboundUrl = resolveSoundUrl(sounds?.inboundSoundId);
    const outboundUrl = resolveSoundUrl(sounds?.outboundSoundId);
    const volume =
      typeof sounds?.volume === "number" ? Math.max(0, Math.min(1, sounds.volume)) : 0.5;

    inboundRef.current = inboundUrl ? buildAudio(inboundUrl, volume) : null;
    outboundRef.current = outboundUrl ? buildAudio(outboundUrl, volume) : null;

    return () => {
      inboundRef.current?.pause();
      outboundRef.current?.pause();
    };
  }, [sounds]);

  const toggleMuted = useCallback(() => {
    setMuted((prev) => {
      const next = !prev;
      try {
        localStorage.setItem(MUTE_STORAGE_KEY, next ? "1" : "0");
      } catch {
        // Privacy mode / quota errors — accept the runtime toggle
        // and skip persistence rather than crashing.
      }
      return next;
    });
  }, []);

  const play = useCallback(
    (kind: "inbound" | "outbound") => {
      if (muted) return;
      if (sounds && sounds.enabled === false) return;
      const ref = kind === "inbound" ? inboundRef.current : outboundRef.current;
      if (!ref) return;
      ref.currentTime = 0;
      ref.play().catch(() => {
        // Autoplay blocked or asset failed — swallow. Next user-
        // gesture-triggered call unlocks the policy.
      });
    },
    [muted, sounds],
  );

  return {
    muted,
    toggleMuted,
    playInbound: () => play("inbound"),
    playOutbound: () => play("outbound"),
  };
}

function buildAudio(src: string, volume: number): HTMLAudioElement {
  const audio = new Audio(src);
  audio.preload = "auto";
  audio.volume = volume;
  return audio;
}
