import { Loader2, Monitor, Moon, Sun } from "lucide-react";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import type { VisitorProfile } from "@/lib/graphql/queries/generated/profile.generated";
import { SUPPORTED_LOCALES } from "@/lib/locales";
import { cn } from "@/lib/utils";
import { localeDisplayName } from "./helpers";
import { Section } from "./section";
import { SettingsRow } from "./settings-row";
import { Switch } from "./switch";
import type { PrefKey, PrefValue } from "./use-apply-pref";

/** Wire values for `preferences.themeMode` — must match the BE's
 *  `IsIn(['system','light','dark'])` validator. */
const THEME_OPTIONS = [
  { value: "system", icon: Monitor, labelKey: "themeAuto" },
  { value: "light", icon: Sun, labelKey: "themeLight" },
  { value: "dark", icon: Moon, labelKey: "themeDark" },
] as const;

/**
 * Preferences section — language picker, theme segmented control, and
 * desktop-notifications switch. Every control auto-saves on change via
 * `applyPref` (passed down from the parent); no explicit Save button.
 *
 * The language row is hidden entirely when `languageEditable` is false
 * (operator's `localeStrategy === "DEFAULT"` pin).
 *
 * Desktop-notifications has a richer turn-on flow than the others: we
 * gate persistence on the browser permission so a "saved=true but
 * permission=denied" silent lie is impossible.
 */
export function PreferencesSection({
  profile,
  locale,
  languageEditable,
  prefSaving,
  applyPref,
  onNotificationError,
  t,
}: {
  profile: VisitorProfile;
  locale: string;
  languageEditable: boolean;
  prefSaving: PrefKey | null;
  applyPref: (key: PrefKey, value: PrefValue) => Promise<void>;
  /** Surface inline notifications-permission errors via the parent's
   *  shared banner — they're not field-level. */
  onNotificationError: (i18nKey: string | null) => void;
  t: (key: string) => string;
}) {
  return (
    <Section
      eyebrow={t("preferencesHeading")}
      adornment={
        prefSaving ? (
          <span className="inline-flex items-center gap-1 text-[10px] font-normal text-wx-fg-subtle">
            <Loader2 size={10} className="animate-spin" aria-hidden="true" />
            {t("saving")}
          </span>
        ) : undefined
      }
    >
      {languageEditable && (
        <SettingsRow label={t("preferenceLanguage")}>
          <div className="w-40">
            <Select
              value={profile.preferences.language ?? locale}
              disabled={prefSaving === "language"}
              onValueChange={(v) => applyPref("language", v || null)}
            >
              <SelectTrigger aria-label={t("preferenceLanguage")}>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {SUPPORTED_LOCALES.map((code) => (
                  <SelectItem key={code} value={code}>
                    {localeDisplayName(code, locale)}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </SettingsRow>
      )}

      <SettingsRow
        label={t("preferenceThemeMode")}
        hint={!profile.themeModeEditable ? t("themeLocked") : undefined}
      >
        <div className="inline-flex items-center gap-0.5 rounded-full bg-wx-bg-elevated p-0.5">
          {THEME_OPTIONS.map(({ value, icon: Icon, labelKey }) => {
            const active = (profile.preferences.themeMode ?? "system") === value;
            return (
              <button
                key={value}
                type="button"
                aria-pressed={active}
                aria-label={t(labelKey)}
                title={t(labelKey)}
                disabled={!profile.themeModeEditable || prefSaving === "themeMode"}
                onClick={() => applyPref("themeMode", value)}
                className={cn(
                  "flex h-7 w-9 items-center justify-center rounded-full transition-all",
                  active
                    ? "bg-wx-bg text-wx-fg shadow-[0_1px_3px_rgba(0,0,0,0.08)]"
                    : "text-wx-fg-muted hover:text-wx-fg",
                  "disabled:cursor-not-allowed disabled:opacity-50",
                )}
              >
                <Icon size={13} aria-hidden="true" />
              </button>
            );
          })}
        </div>
      </SettingsRow>

      <SettingsRow
        label={t("preferenceDesktopNotifications")}
        hint={t("preferenceDesktopNotificationsHint")}
      >
        <Switch
          checked={
            !!profile.preferences.desktopNotifications &&
            (typeof Notification === "undefined" || Notification.permission === "granted")
          }
          onChange={async (next) => {
            // Turn-off short-circuits — just persist false. Turn-on
            // must clear the browser gate FIRST so the saved-true
            // state always matches what we can actually deliver
            // (saved=true + permission=denied would be a silent lie).
            if (!next) {
              void applyPref("desktopNotifications", false);
              return;
            }
            if (typeof Notification === "undefined") {
              onNotificationError("notificationsRequest");
              return;
            }
            if (Notification.permission === "denied") {
              onNotificationError("notificationsBlocked");
              return;
            }
            if (Notification.permission === "default") {
              try {
                const result = await Notification.requestPermission();
                if (result !== "granted") {
                  onNotificationError("notificationsBlocked");
                  return;
                }
              } catch {
                onNotificationError("notificationsRequest");
                return;
              }
            }
            void applyPref("desktopNotifications", true);
          }}
        />
      </SettingsRow>
    </Section>
  );
}
