// The article views render Markdown (`react-markdown` + the
// micromark/mdast stack, ~80 KB combined). They're drill-in routes
// behind navigation, so `lazy()` keeps that stack out of the initial
// payload — it streams in the first time a visitor opens an article.
const HelpArticleView = lazy(() =>
  import("../help-article-view").then((m) => ({ default: m.HelpArticleView })),
);
const NewsArticleView = lazy(() =>
  import("../news-article-view").then((m) => ({ default: m.NewsArticleView })),
);

/** localStorage key for the visitor's panel expand/collapse preference.
 *  Persisted (not session) so a visitor who likes the wide panel keeps
 *  it across reloads + revisits. */
const PANEL_EXPANDED_KEY = "wexio:panel-expanded";

/** Viewport margins the panel reserves — mirror the `max-w` / `max-h`
 *  Tailwind clamps on the panel (`100vw - 2rem`, `100dvh - 7rem`). Used
 *  to clamp the ANIMATION target to the size that actually renders, so
 *  width + height settle together instead of the height stopping early
 *  at its ceiling. Keep in sync with the className. */
const PANEL_MARGIN_X = 32; // 2rem
const PANEL_MARGIN_Y = 112; // 7rem

/** Read the persisted expand preference. Defensive against storage being
 *  unavailable (private mode) + SSR (no `window`) → defaults collapsed. */
function readExpandedPref(): boolean {
  if (typeof window === "undefined") return false;
  try {
    return localStorage.getItem(PANEL_EXPANDED_KEY) === "1";
  } catch {
    return false;
  }
}

/** Render a desktop-notification body from a (possibly Tiptap-HTML)
 *  message + its attachments. The Notification API treats `body` as
 *  plain text — raw HTML would show literally — so route the message
 *  through DOMParser for proper entity decoding + tag stripping.
 *  Falls back to a media marker when the visible text is empty. */
function htmlToPlainText(html: string, media: { mimetype: string }[]): string {
  let text = "";
  if (html) {
    try {
      // DOMParser is the safest entity-aware HTML → text path. We don't
      // attach the document to the live DOM — just extract textContent.
      const doc = new DOMParser().parseFromString(html, "text/html");
      text = (doc.body.textContent ?? "").replace(/\s+/g, " ").trim();
    } catch {
      // Defensive: fall back to a regex strip if DOMParser is somehow
      // unavailable (very old browsers / sandboxed contexts).
      text = html
        .replace(/<[^>]*>/g, " ")
        .replace(/\s+/g, " ")
        .trim();
    }
  }
  if (text) return text;
  if (media.length === 0) return "New message";
  const head = media[0]?.mimetype ?? "";
  const kind = head.startsWith("image/")
    ? "Image"
    : head.startsWith("video/")
      ? "Video"
      : head.startsWith("audio/")
        ? "Voice message"
        : "Attachment";
  return media.length > 1 ? `${kind} +${media.length - 1}` : kind;
}

/** Shared fallback while a lazily-loaded drill-in view streams in. */
function RouteChunkFallback() {
  return (
    <div className="flex flex-1 items-center justify-center">
      <div className="border-wx-border border-t-wx-primary h-5 w-5 animate-spin rounded-full border-2" />
    </div>
  );
}

/**
 * Top-level widget shell — owns the navigation stack + decides which
 * surfaces render.
 *
 * **Two layout modes** (route-driven):
 *   - **List routes** (`home` / `help` / `news`)        — bottom nav
 *     + tab-style headers. Visitor is browsing an index.
 *   - **Drill-in routes** (`messages` / `help-category` /
 *     `help-article`)                                    — no bottom
 *     nav. Sticky header with a back button + per-route title.
 *
 * **Home tab is special**: the header chrome (logo + avatars + mute +
 * close) scrolls WITH the hero so the brand gradient backdrop reads
 * as one continuous surface. Other tabs render a sticky strip header.
 *
 * **Motion**: panel slide-in with spring; per-route content crossfades
 * through `AnimatePresence`; launcher icon morph via the FAB.
 */
export function WidgetShell() {
  // Demo content (`messages/demo.*.json`) is lazily imported + merged
  // into i18n only in demo mode by `DemoMessages` — it stays out of the
  // production bundle every visitor downloads.
  return (
    <DemoMessages>
      <WidgetShellInner />
    </DemoMessages>
  );
}

function WidgetShellInner() {
  const tHeader = useTranslations("header");
  // Visitor's active language — threaded into article-detail views so
  // their content queries fetch the right locale (was hardcoded "en").
  const locale = useLocale();
  const env = useWidgetEnv();

  const { mode, config, isDummy } = useWidgetConfig();
  // Operator's saved mode preference flows in here. BE serialises the
  // enum in uppercase (`AUTO` / `LIGHT` / `DARK`); normalise to the
  // lowercase set the widget's CSS / data-theme attribute expects.
  // `useThemeMode` still respects URL + postMessage overrides, the
  // visitor's localStorage pref (when operator allows `auto`), and
  // the visitor's OS preference as fallbacks.
  // Theme + logos are resolved BELOW (after `session` is defined) — the
  // visitor profile query needs `session.token` and we want it threaded into
  // `useThemeMode` directly. See the block right after the `session` const.
  // Which corner the launcher + panel anchor to (operator-configurable;
  // defaults to bottom-right).
  const launcherLeft = config.theme?.launcherPosition === "LEFT_BOTTOM";
  // React-component embed → anchor to the host `<div>` (`absolute` +
  // %-based clamps) instead of the viewport (`fixed` + vw/dvh clamps),
  // so the widget stays inside its container. See `WidgetEnv.embedded`.
  const embedded = env.embedded ?? false;
  const { muted, toggleMuted, playInbound, playOutbound } = useSoundPlayer(config.sounds);
  // Host-supplied visitor data (embeds set it on `env`; the iframe
  // receives it over postMessage). `identity` (verified, userHash) routes
  // the handshake to the identified flow; `prefill` (unverified profile)
  // pre-fills / auto-attaches the prechat.
  const { identity: visitorIdentity, prefill: visitorPrefill } = useHostVisitorData(env);
  // Identity the visitor established INSIDE the widget (e.g. tapped the
  // Google sign-in button) — distinct from `visitorIdentity` which the
  // HOST supplies. Host identity wins; this fills in when the host didn't
  // identify and the visitor signs in themselves.
  const [widgetIdentity, setWidgetIdentity] = useState<VisitorIdentity | null>(null);
  // Bumped by `Wexio('shutdown')` (logout / shared device) to force a
  // fresh anonymous handshake after the stored session is wiped.
  const [sessionEpoch, setSessionEpoch] = useState(0);
  useEffect(() => {
    if (typeof window === "undefined") return;
    const onMessage = (e: MessageEvent) => {
      if (!e.data || e.data.type !== "wexio:shutdown:v1") return;
      // Forget the stored visitorId + token + any in-widget sign-in, then
      // re-handshake fresh. The new chatId clears `liveMessages` via the
      // effect below, so the next person on a shared device never sees
      // the prior chat.
      resetStoredVisitorSession();
      setWidgetIdentity(null);
      setPasskeySession(null);
      setSessionEpoch((n) => n + 1);
    };
    window.addEventListener("message", onMessage);
    return () => window.removeEventListener("message", onMessage);
  }, []);
  const baseSession = useVisitorAuth({
    enabled: mode === "production" && !isDummy,
    identity: visitorIdentity ?? widgetIdentity,
    epoch: sessionEpoch,
  });
  // Passkey produces a full verified session out-of-band (a 2-step
  // WebAuthn ceremony, not an identity token), so it can't route through
  // `useVisitorAuth`'s identity handshake like Google does. The hook
  // already stamped the token into Apollo; here we adopt the rest as a
  // session OVERRIDE so the UI reads `verified` + the new `chatId`.
  // Cleared on shutdown so the next person falls back to a fresh
  // anonymous handshake.
  const [passkeySession, setPasskeySession] = useState<VisitorSession | null>(null);
  const session = passkeySession ?? baseSession;

  // Visitor's BE-persisted profile preferences (theme mode + language +
  // desktop-notifications opt-in). Skipped when Profile is disabled or the
  // visitor isn't authed yet — the query needs a visitor JWT. The language
  // preference is persisted to a cookie inside the hook; mid-session locale
  // change requires a remount which is out of scope.
  const profilePrefs = useVisitorProfilePreferences({
    enabled: !!config.features.profile && !isDummy && !!session.token,
  });

  // DevTools helpers exposed on `window`:
  //
  //   - `__wexioNotifyDebug()` — dump the state the next inbound will
  //     evaluate against (pref + permission + prefs-loaded + session).
  //   - `__wexioTestNotify()`  — fire `new Notification(...)` DIRECTLY
  //     with hard-coded copy, bypassing the entire inbound pipeline.
  //     If THIS doesn't show on screen either, the popup is being eaten
  //     by macOS / Chrome (Focus mode, alert style = None, Chrome
  //     "quieter notifications", etc.) — not our code.
  useEffect(() => {
    if (typeof window === "undefined") return;
    const w = window as unknown as {
      __wexioNotifyDebug?: () => unknown;
      __wexioTestNotify?: () => unknown;
    };
    w.__wexioNotifyDebug = () => {
      const state = {
        prefEnabled: profilePrefs.desktopNotifications,
        permission: typeof Notification !== "undefined" ? Notification.permission : "(unsupported)",
        prefsLoaded: profilePrefs.loaded,
        featureEnabled: !!config.features.profile,
        sessionToken: !!session.token,
      };
      console.log("[wexio] notify state:", state);
      return state;
    };
    w.__wexioTestNotify = () => {
      if (typeof Notification === "undefined") {
        console.warn("[wexio] Notification API not available in this context");
        return "unsupported";
      }
      if (Notification.permission !== "granted") {
        console.warn("[wexio] permission not granted:", Notification.permission);
        return Notification.permission;
      }
      try {
        const n = new Notification("Wexio test", {
          body: "If you can see this, notifications work.",
          tag: "wexio-test",
        });
        n.onshow = () => console.log("[wexio] test notification: onshow fired");
        n.onerror = (e) => console.warn("[wexio] test notification: onerror", e);
        n.onclose = () => console.log("[wexio] test notification: onclose");
        console.log("[wexio] test notification posted to browser");
        return "posted";
      } catch (err) {
        console.warn("[wexio] test notification threw:", err);
        return err;
      }
    };
  }, [
    profilePrefs.desktopNotifications,
    profilePrefs.loaded,
    config.features.profile,
    session.token,
  ]);
  // Theme — operator preference + visitor profile preference (when
  // `themeModeEditable`). See `useThemeMode` for the full precedence chain.
  const resolvedThemeMode = useThemeMode(normaliseThemeMode(config.themeMode), {
    preference: profilePrefs.themeMode,
    allowed: profilePrefs.themeModeEditable,
  });
  // Resolve the operator's per-mode logo down to a single URL the header
  // components render. Prefer the active mode's logo; fall back to the
  // other mode's (one logo is better than none); `null` when the operator
  // uploaded neither — the header then shows the framed Wexio fallback mark.
  const organizationLogoUrl = resolveOrgLogo(config.organizationLogo, resolvedThemeMode);
  // Conversation-header logo. Demo has no operator logo, so fall back to
  // the theme-matched Wexio mark (`logo-light.png` in light mode,
  // `logo-dark.png` in dark) so the header reads as branded rather than
  // blank. Scoped to the conversation header — the home header keeps its
  // own `WexioMark` placeholder. CDN-aware via `assetUrl`.
  const conversationLogoUrl =
    organizationLogoUrl ?? (isDummy ? assetUrl(`/logo-${resolvedThemeMode}.png`) : null);

  const [route, setRoute] = useState<WidgetRoute>(() =>
    // Initial route honours the operator's `defaultTab` AND the
    // features flag set — if `defaultTab` is on a disabled tab
    // (e.g. preview mode patches features after first render),
    // fall back to the first enabled tab.
    defaultRouteFor(pickInitialTab(config.defaultTab, config.features)),
  );

  // Snap the route to a valid tab whenever the features flag set
  // OR the `defaultTab` changes — `useState` only runs its
  // initializer ONCE, so a postMessage config patch that lands
  // after mount (preview mode, BE config arriving async) would
  // otherwise leave the visitor stuck on a disabled tab. Effect
  // is no-op when the current tab is already enabled.
  //
  // `route` intentionally excluded — we only need to react to config
  // changes; reading the current `route` inside the effect is enough,
  // and adding it as a dep would re-snap on every navigation.
  // biome-ignore lint/correctness/useExhaustiveDependencies: route is read inside the effect, not a trigger — see note above
  useEffect(() => {
    const currentTab = routeToTab(route);
    if (isTabEnabled(currentTab, config.features)) return;
    const next = pickInitialTab(config.defaultTab, config.features);
    setRoute(defaultRouteFor(next));
  }, [config.features, config.defaultTab]);
  const [isOpen, setIsOpen] = useState(false);
  // Initialised from localStorage so the preference survives reloads /
  // revisits. Safe to read in the initializer (no hydration mismatch):
  // the panel is closed at first paint, so `expanded` doesn't affect any
  // SSR-rendered DOM until the visitor opens + expands it.
  const [expanded, setExpanded] = useState(readExpandedPref);
  // Persist the preference on every change. Writing the initial value
  // back is a harmless no-op (it equals what we just read).
  useEffect(() => {
    try {
      localStorage.setItem(PANEL_EXPANDED_KEY, expanded ? "1" : "0");
    } catch {
      // Private mode / blocked storage — keep it in-memory this session.
    }
  }, [expanded]);
  // Currently-visible article title — fed by the help/news article
  // views via `onTitleResolved`. Shown in the sticky header for
  // article routes so the bar reads as a breadcrumb ("← Article
  // name") instead of the parent tab nameplate ("News" / "Help").
  // `null` while the article is still loading; the header falls
  // back to the tab title until the article view resolves.
  //
  // We DON'T clear this here on route change. The previous version
  // had a route-watching `useEffect` that scheduled `setArticleTitle(
  // null)` on every nav — but the article view's own `useEffect`
  // (which calls `onTitleResolved`) fires on the same tick when the
  // Apollo cache returns instantly on a re-visit. React's batching
  // could resolve `null` last, dropping the title back to "News"
  // permanently. Clearing is now owned by the article view itself
  // via a cleanup function: it sets the title on mount, clears it
  // on unmount. That's deterministic regardless of cache state.
  const [articleTitle, setArticleTitle] = useState<string | null>(null);
  // Stays `true` after the first open. Used to gate the route
  // content — when the panel has never been opened, none of the
  // tab components mount, so their GraphQL queries + SSE
  // subscriptions stay dormant. Only the launcher unread query
  // (and the visitor-auth handshake it depends on) runs while
  // closed.
  const [hasOpened, setHasOpened] = useState(false);
  useEffect(() => {
    if (isOpen) setHasOpened(true);
  }, [isOpen]);

  // Unread state for the launcher badge + peek card. Real mode
  // queries `visitorChatUnread`; demo mode derives from getMockConversation().
  const unread = useVisitorUnread({
    chatId: session.chatId,
    isDummy,
  });

  // ─── Shell-level SSE pump ─────────────────────────────────────
  // Listens for realtime events across the whole widget lifetime —
  // not just while MessagesTab is mounted — so the launcher peek +
  // home-tab `recent-message` block refresh as soon as an operator /
  // bot / AI message arrives. MessagesTab still handles its own
  // transient state (typing indicator, in-flight composer) but
  // session-durable state (`liveMessages`) lives here so a visitor
  // who switches Help → Messages and back doesn't lose the new
  // bubbles they just saw.
  const apolloClient = useApolloClient();
  const messagesTabHandlerRef = useRef<((e: RealtimeMessageEvent) => void) | null>(null);

  // Messages appended in-session (SSE-delivered inbound + visitor's
  // optimistic outbound). Merged with the `visitorChatHistory` query
  // result inside MessagesTab — kept here so route changes don't drop
  // them.
  const [liveMessages, setLiveMessages] = useState<MockMessage[]>([]);
  // Demo-only: a launcher-peek quick-reply tapped before the panel
  // opened. Handed to MessagesTab, which "sends" it on mount; cleared
  // once consumed.
  const [pendingPeekReply, setPendingPeekReply] = useState<string | null>(null);
  // Reset on chatId change — new visitor session, new accounting.
  // `session.chatId` is an intentional re-run trigger (not read in the
  // body): when the visitor's chat changes we want the live buffer
  // wiped, so it must stay in the dep array.
  // biome-ignore lint/correctness/useExhaustiveDependencies: chatId is a deliberate reset trigger, not an unused dep
  useEffect(() => {
    setLiveMessages([]);
  }, [session.chatId]);

  // Re-fetch the visitor profile whenever the underlying identity
  // changes — anon → identified after a passkey / Google sign-in, or a
  // different identified person on a shared device. Without this the
  // ProfileTab + `useVisitorProfilePreferences` would keep showing the
  // PRIOR session's cached profile (the `VisitorProfile` query takes no
  // variables, so the cache key doesn't move when the auth header does;
  // Apollo happily returns the anon result to an identified session).
  // Keyed off `session.peopleId` since that's the BE-resolved row id —
  // stable per user, flips on every real identity change. Skipped while
  // the feature is off or there's no session yet.
  // biome-ignore lint/correctness/useExhaustiveDependencies: peopleId is the deliberate refetch trigger; apolloClient is a stable instance
  useEffect(() => {
    if (!config.features.profile) return;
    if (!session.peopleId || !session.token) return;
    void apolloClient.refetchQueries({ include: [VisitorProfileDocument] });
  }, [session.peopleId]);

  /**
   * Append a message to the in-session live list. Dedupes by id so
   * SSE replays + optimistic-then-confirmed sends don't double up.
   */
  const appendLiveMessage = useCallback((msg: MockMessage) => {
    setLiveMessages((prev) => {
      if (prev.some((m) => m.id === msg.id)) return prev;
      return [...prev, msg];
    });
  }, []);

  /**
   * Swap an optimistic tmp-id row for the BE-persisted real row.
   * Used by the visitor's send path — append optimistic with a
   * `tmp-…` id, fire the mutation, replace once the BE returns the
   * canonical message id. Keeps the bubble visible the whole time
   * AND lets history-cache dedupe work on later reads.
   */
  const replaceLiveMessage = useCallback((tmpId: string, msg: MockMessage) => {
    // Preserve the original row's `clientKey` across the swap so
    // React's reconciler treats it as the SAME bubble. Without this
    // the AnimatePresence key flips when `id` changes from tmp-… to
    // the BE-canonical id, the bubble unmounts + remounts, and the
    // visitor sees their just-sent message "re-animate" the moment
    // an SSE event triggers a re-render. The caller can still pass
    // an explicit `clientKey` to override (rare).
    setLiveMessages((prev) =>
      prev.map((m) =>
        m.id === tmpId ? { ...msg, clientKey: msg.clientKey ?? m.clientKey ?? tmpId } : m,
      ),
    );
  }, []);
  // Stable register fn — MessagesTab calls this on mount with its
  // handler; the returned cleanup nulls the ref on unmount. Stable
  // identity is critical: a fresh function each render would loop
  // the tab's `useEffect`.
  const registerMessagesRealtimeHandler = useRef((handler: (e: RealtimeMessageEvent) => void) => {
    messagesTabHandlerRef.current = handler;
    return () => {
      if (messagesTabHandlerRef.current === handler) {
        messagesTabHandlerRef.current = null;
      }
    };
  }).current;

  useVisitorRealtime({
    chatId: session.chatId,
    token: session.token,
    enabled: !isDummy && mode === "production",
    onMessage: (event) => {
      // Forward to the MessagesTab handler (if mounted) so the
      // in-conversation list + typing indicator keep updating.
      messagesTabHandlerRef.current?.(event);

      // Read-receipts adjust the unread counter locally — no refetch.
      if (event.kind === "read-receipt") {
        unread.noteRead(event.readReceipt?.messageIds ?? []);
        return;
      }
      // Typing pings don't move any counter — they're consumed by
      // the MessagesTab handler above for the typing indicator only.
      if (event.kind === "typing") return;

      // Visitor's own echoes don't count toward unread / recent.
      const senderKind = (event.from ?? event.sender)?.kind;
      if (senderKind === "visitor") return;

      // Sound — fire for ANY non-visitor inbound regardless of route.
      // Previously this was wired only through `MessagesTab.onInbound`,
      // which doesn't mount when the visitor is on Home / Profile / the
      // launcher → no audible cue unless they were already on the chat
      // thread. The unread badge + recent-message card update from this
      // same handler, so the sound belongs with them, not inside the
      // tab. (MessagesTab keeps its own `onInbound` call for its
      // optimistic-echo flow — those are local appends, not SSE.)
      playInbound();

      // Append the inbound to the shared live list so the bubble
      // survives a Messages → Help → Messages round-trip. Outbound
      // (visitor) messages append from the send path inside
      // MessagesTab; SSE echoes of those are filtered above.
      const sender = event.from ?? event.sender;
      const buttons: MockMessageButton[] | undefined = Array.isArray(event.buttons)
        ? event.buttons.map((b) => ({ text: b.label, payload: b.value }))
        : undefined;
      // AI / bot senders display as AI_ASSISTANT_NAME regardless of the BE
      // label ("WEB widget", "Bot", etc) — that mirrors how the
      // typing indicator already labels them, and matches what
      // history-mapping does on reload. Operator senders flow
      // through unchanged so a real handoff still feels human.
      const displaySenderName =
        senderKind === "ai" || senderKind === "bot" ? AI_ASSISTANT_NAME : (sender?.name ?? "");
      // Format the message's send time the same way the history
      // mapper does so live + reloaded bubbles read identically.
      // Empty `ageLabel` (the previous value) left the live bubbles
      // missing the time strip — until the visitor reloaded the
      // page and history paint kicked in. `sentAt` falls back to
      // `Date.now()` when the BE forgets to stamp it.
      const sentAtIso = event.sentAt ?? new Date().toISOString();
      const ageLabel = (() => {
        try {
          return new Date(sentAtIso).toLocaleTimeString(undefined, {
            hour: "numeric",
            minute: "2-digit",
          });
        } catch {
          return "";
        }
      })();
      // Media events (`kind === "media"`) carry the attachment on
      // `event.media`. Either shape — SSE `{ mediaId: {...} }` singular
      // or array — is accepted by the normaliser, which also renames
      // the BE's `mimeType` to the widget's `mimetype` so the bubble
      // renderer + `<Media>` audio player pick it up.
      const rawMedia = (event as { media?: unknown }).media;
      const media = normalizeBackendMedia(rawMedia);
      // A media message's text rides on `media.caption` (single-attachment
      // SSE shape) — fall back to it when the event has no top-level `text`.
      const caption =
        rawMedia && typeof rawMedia === "object" && !Array.isArray(rawMedia)
          ? (rawMedia as { caption?: unknown }).caption
          : undefined;
      appendLiveMessage({
        id: event.externalMessageId,
        direction: "OUTBOUND",
        text: event.text || (typeof caption === "string" ? caption : ""),
        ageLabel,
        sender: {
          kind: (senderKind ?? "operator") as MockMessage["sender"]["kind"],
          name: displaySenderName,
          ...(sender?.avatar ? { avatar: sender.avatar } : {}),
        },
        ...(media.length > 0 ? { media } : {}),
        ...(buttons ? { buttons } : {}),
        deliveryStatus: "DELIVERED" as const,
      });

      // Launcher badge + peek card → advance the local counter from
      // the event payload. No `visitorChatUnread` refetch — we seeded
      // once on session start and the SSE stream keeps us in sync.
      // MessagesTab decides when to ack via `markChatRead` (gated on
      // scroll position, see the tab's `ack` logic).
      unread.noteInbound(event);

      // Desktop notification — opt-in via profile preference. The ONLY
      // case where we DON'T fire is when the visitor is actively reading
      // the Messages tab in a visible browser window (they'll see the
      // bubble appear inline — a desktop popup would be redundant + a
      // little jarring). Every other state — panel collapsed, tab in
      // background, another sub-tab open (Home/Help/News/Profile) — gets
      // a notification because the new message wouldn't otherwise be
      // visible. Tagged by message id so an SSE reconnect re-pumping the
      // same event doesn't double-notify. Body falls back to a media
      // marker so an image-only reply still surfaces something readable.
      const docVisible = typeof document !== "undefined" && !document.hidden;
      const activelyReadingMessages = isOpen && docVisible && route.kind === "messages";
      const prefEnabled = profilePrefs.desktopNotifications;
      const permState =
        typeof Notification !== "undefined" ? Notification.permission : "(unsupported)";
      const permGranted = permState === "granted";
      const willNotify = prefEnabled && permGranted && !activelyReadingMessages;

      // One-line diagnostic so DevTools shows exactly why a notification
      // did / didn't fire on each inbound. Uses `console.log` rather than
      // `console.debug` because Chrome filters debug-level by default
      // (you'd need to flip the "Verbose" level on to see it) — and the
      // whole point of this line is for the user to see it without any
      // DevTools toggling. Cheap noise in dev; ship a feature flag later
      // if it gets annoying.
      console.log("[wexio] inbound:", {
        id: event.externalMessageId,
        kind: event.kind,
        from: displaySenderName,
        prefEnabled,
        permission: permState,
        isOpen,
        docVisible,
        route: route.kind,
        activelyReadingMessages,
        willNotify,
      });

      if (prefEnabled && permGranted && !activelyReadingMessages) {
        try {
          const captionText = typeof caption === "string" ? caption : "";
          // BE sends rich-text inbounds as Tiptap HTML
          // (`<p class="tiptap-paragraph">…</p>`, lists, marks, etc.).
          // The Notification API renders `body` as plain text — raw HTML
          // would show literally — so route through DOMParser to get
          // textContent the browser-native way (handles entities, nested
          // tags, line breaks correctly; no fragile regex).
          const body = htmlToPlainText(event.text || captionText, media);
          // Icon: prefer the sender's own avatar (operator photo / AI
          // mark) — it carries more meaning than the org logo when the
          // visitor sees a notification slide in. Fall back to the
          // operator org logo and then to nothing.
          const notificationIcon = sender?.avatar ?? organizationLogoUrl ?? undefined;
          const n = new Notification(displaySenderName || "New message", {
            body,
            tag: event.externalMessageId,
            icon: notificationIcon,
          });
          // Click → focus the existing widget tab + open the panel on
          // the Messages route. Without this Chrome's default behaviour
          // is to open / focus the page's URL in a new tab. The
          // notification auto-closes itself once the visitor has acted.
          n.onclick = () => {
            try {
              window.focus();
            } catch {
              /* some sandboxed contexts disallow focus; ignore */
            }
            setIsOpen(true);
            setRoute({ kind: "messages" });
            n.close();
          };
        } catch (err) {
          // Notification API can throw on iOS web / SecurityError contexts;
          // log so the visitor / operator can see what blocked it instead
          // of silently dropping (matches the diagnostic warns above).
          console.warn("[wexio] desktop notification failed:", err);
        }
      } else if (prefEnabled && !permGranted) {
        // Pref says yes but browser permission isn't granted — the toggle
        // should normally keep these in sync (see profile-tab's permission
        // gate), but log here so a permission revoked from chrome://settings
        // doesn't silently swallow notifications.
        console.warn(
          "[wexio] desktop notifications enabled but browser permission is not granted; current value:",
          permState,
        );
      }

      // Home-tab `recent-message` block → write the new inbound
      // straight into the Apollo cache so subscribers re-render
      // without burning a `visitorChatRecentInbound` round-trip.
      if (session.chatId) {
        apolloClient.writeQuery({
          query: VisitorChatRecentInboundDocument,
          variables: { chatId: session.chatId },
          data: {
            __typename: "Query",
            visitorChatRecentInbound: {
              __typename: "VisitorChatRecentInbound",
              id: event.externalMessageId,
              text: event.text ?? null,
              createdAt: event.sentAt ?? new Date().toISOString(),
              sender: {
                __typename: "VisitorUnreadSender",
                kind: sender?.kind ?? "operator",
                name: sender?.name ?? "",
                avatar: sender?.avatar ?? null,
              },
            },
          },
        });
      }
    },
  });
  // Quick-reply sender used by the launcher peek. Real mode goes
  // through the existing `sendVisitorMessage` mutation; demo mode
  // is handled inline (no BE) — we just open the panel so the
  // messages tab takes over.
  const [sendVisitor] = useSendVisitorMessageMutation();

  // Routes that can widen — visitor benefits from more reading room
  // when they're inside a conversation or a single article. List
  // surfaces (home / help index / news index) stay at the default
  // width so the chrome composition the visitor expects holds.
  // **Persistence**: `expanded` is stored in localStorage
  // (`PANEL_EXPANDED_KEY`), so it survives navigation, reloads, AND
  // revisits — expand on Messages, leave, come back later, still wide.
  // Non-expandable routes simply ignore the flag via `effectiveExpanded`
  // rather than resetting it.
  const expandable =
    route.kind === "messages" || route.kind === "help-article" || route.kind === "news-article";
  const effectiveExpanded = expandable && expanded;

  // IDEAL dimensions — the widget wants 420 × 670 (640 × 860 expanded).
  // These are what we REPORT to the host (iframe loader / web-component),
  // which clamps to the host viewport itself.
  const idealW = effectiveExpanded ? 640 : 420;
  // Default-state height is 670 (trimmed 50px from 720) for a more
  // compact panel; the expanded state stays tall.
  const idealH = effectiveExpanded ? 860 : 670;

  // Viewport size — tracked so the expand ANIMATION targets the size the
  // panel will actually render at. Without this the spring animates the
  // height toward 860 even when the screen is shorter, so the height
  // meets its `max-h` ceiling and stops while the width is still moving
  // (the "height finishes first" the visitor sees, especially on screens
  // under ~860px tall). `null` until mounted → SSR-safe, no hydration gap
  // (panel is closed at first paint).
  const [viewport, setViewport] = useState<{ w: number; h: number } | null>(null);
  useEffect(() => {
    if (typeof window === "undefined") return;
    const read = () => {
      const w = window.innerWidth;
      const h = window.innerHeight;
      // Bail when the size didn't actually change — `resize` also fires
      // on zoom / mobile keyboard / devtools docking with no delta.
      // Returning the same reference makes React skip the re-render, so
      // the only renders are the ones that genuinely re-fit the panel.
      setViewport((prev) => (prev && prev.w === w && prev.h === h ? prev : { w, h }));
    };
    read();
    window.addEventListener("resize", read);
    return () => window.removeEventListener("resize", read);
  }, []);

  // CLAMPED dimensions used by the open/expand animation. Mirrors the CSS
  // `max-w / max-h`, so the spring animates to exactly what renders and
  // both axes settle together. Embedded (host-container) keeps the ideal
  // — the CSS `%` clamps handle it and we can't measure the container as
  // cheaply; the viewport path covers iframe + web-component.
  const panelW = embedded || !viewport ? idealW : Math.min(idealW, viewport.w - PANEL_MARGIN_X);
  const panelH = embedded || !viewport ? idealH : Math.min(idealH, viewport.h - PANEL_MARGIN_Y);

  // Track navigation direction so transitions feel like "going
  // deeper" (slide left + scale down a touch) or "going back"
  // (slide right + scale up). Tab indices give us a natural order;
  // drill-ins use a higher rank than their parent tab.
  const lastRankRef = useRef<number>(routeRank(route));
  const direction = (() => {
    const next = routeRank(route);
    const prev = lastRankRef.current;
    lastRankRef.current = next;
    if (next === prev) return 0;
    return next > prev ? 1 : -1;
  })();

  // Resize the embed surface based on open / closed / expanded state.
  // Reports the IDEAL dimensions (NOT the viewport-clamped ones) — the
  // iframe loader's styles + the web-component host clamp to viewport on
  // narrow screens. Reporting ideal here also breaks a feedback loop:
  // inside the iframe `window.innerHeight` IS the iframe height, so
  // reporting the clamped height would shrink the iframe, which would
  // shrink the clamp, and so on.
  useEffect(() => {
    const width = isOpen ? idealW : 72;
    const height = isOpen ? idealH : 72;
    env.onResize(width, height);
  }, [isOpen, idealW, idealH, env]);

  const close = () => {
    setIsOpen(false);
    if (mode === "production") env.onClose();
  };

  // Bulk-read acknowledgement is owned by MessagesTab — it knows
  // whether the new inbound is actually in view (at the bottom of
  // the conversation) vs. scrolled out of sight. The shell exposes
  // `unread.count` + `unread.clear` as props; the tab fires the
  // `markChatRead` mutation at the right moment and then clears
  // local state via `unread.clear` so the peek/badge disappear
  // without waiting for the SSE read-receipt round-trip.

  /**
   * Launcher peek → quick-reply tap. In real mode we send the
   * payload via the visitor mutation; in demo mode we just open the
   * panel (the messages tab's existing demo simulator will react to
   * the visitor's reply once they're inside). Both paths open the
   * widget so the visitor sees their reply land.
   */
  const handlePeekButton = async (payload: string, text: string) => {
    if (isDummy) {
      // Demo: hand the reply to the messages tab to "send" on mount
      // (visitor bubble + canned response), and clear the peek now so
      // it doesn't resurface after the visitor closes the widget.
      setPendingPeekReply(text);
      unread.clear();
    } else if (session.chatId) {
      try {
        await sendVisitor({ variables: { input: { text } } });
      } catch {
        // Quietly swallow — visitor will retry from inside the
        // panel; surfacing an error toast at the peek level would
        // be more noise than help.
      }
      // Real mode: MessagesTab mounts with `unreadCount > 0`, sees the
      // new message is at the bottom, and acks via `markChatRead` +
      // clearUnread. The peek is hidden by the `isOpen` gate either way.
    }
    setRoute({ kind: "messages" });
    setIsOpen(true);
    // Quick-reply tap is the visitor's reply — treat as an outbound
    // signal so the operator dashboard's "visitor responded" badge
    // catches it without waiting for the SSE round-trip.
    playOutbound();
    void payload;
  };

  const handlePeekOpen = () => {
    setRoute({ kind: "messages" });
    setIsOpen(true);
  };

  // Branding gate is server-authoritative: `config.branding` is always
  // resolved from the BE by publicKey (the full fetch, or the lite
  // `?view=gate` fetch when presentation is injected — never from
  // host-injected props), and the BE plan-gates `hidden`. So a host can't
  // fake white-label removal.
  const showBrandingFooter = !config.branding?.hidden;
  // When only ONE tab is enabled the bottom nav adds no value (the
  // visitor cannot move "across") — hide it. Also hides the
  // Messages-header back arrow downstream, since there is nowhere
  // for it to pop to.
  const tabCount = enabledTabCount(config.features);
  const showTabs = routeShowsTabs(route) && tabCount > 1;
  const isHome = route.kind === "home";
  const activeTab = routeToTab(route);

  const switchTab = (next: WidgetTab) => {
    // Mark the tab swap as a transition so the incoming tab's content
    // render (Apollo first-paint, list reconciliation) is interruptible
    // and yields to the slide animation's frames — the old tab stays
    // interactive until the new one is ready, then both the nav
    // highlight + the slide commit together. Keeps the route transition
    // off the animation's critical 16ms budget. See the perf notes in
    // the route `AnimatePresence` below (mode="sync").
    startTransition(() => {
      setRoute({ kind: next === "messages" ? "messages" : next });
    });
  };

  return (
    <>
      <motion.div
        aria-hidden={!isOpen}
        initial={false}
        animate={
          // Bottom-right bubble at the desktop dimensions on every
          // viewport. The className's `max-w` shrinks the rendered
          // width on narrow phones without overriding the inline
          // `width: 420` (CSS allows both — `max-width` clamps the
          // declared width regardless of source specificity).
          isOpen
            ? {
                opacity: 1,
                y: 0,
                scale: 1,
                pointerEvents: "auto",
                width: panelW,
                height: panelH,
              }
            : {
                opacity: 0,
                y: 16,
                scale: 0.98,
                pointerEvents: "none",
                width: panelW,
                height: panelH,
              }
        }
        transition={{
          // Open/close rises gently from the launcher on a soft spring.
          //
          // Width + height share ONE spring with identical physics, so an
          // expand/collapse grows BOTH dimensions in lockstep — smooth and
          // proportional. The previous 140 ms linear-ish tween made the
          // height appear to finish before the width: on a short viewport
          // the expanded height meets its `max-h` clamp partway, so a
          // constant-velocity tween hit that ceiling abruptly while the
          // width kept travelling. A spring decelerates into place, so the
          // clamp reads as a settle rather than a hard cut, and the two
          // axes track together regardless of how far each one moves.
          opacity: { type: "spring", stiffness: 320, damping: 30 },
          y: { type: "spring", stiffness: 320, damping: 30 },
          scale: { type: "spring", stiffness: 320, damping: 30 },
          width: { type: "spring", stiffness: 300, damping: 32 },
          height: { type: "spring", stiffness: 300, damping: 32 },
        }}
        data-wx-panel
        className={cn(
          // `isolate` (isolation: isolate) makes the panel a PERMANENT
          // stacking context. Without it the panel is only a stacking
          // context while `motion` has a `transform` applied (during the
          // open animation) — once that settles to `transform: none` the
          // home gradient's `-z-10` child escapes to the parent context
          // and gets painted BEHIND the panel's opaque `bg-wx-bg`, so it
          // flashes in then vanishes.
          "isolate flex flex-col overflow-hidden bg-wx-bg text-wx-fg",
          // Anchored to the operator's chosen corner (`launcherPosition`),
          // bottom-right by default. `max-w` / `max-h` clamp the bubble
          // with a margin — no `min-width` anywhere so motion's inline
          // `width: 420` can shrink down freely.
          //
          // `embedded` (React-component embed) → anchor to the host
          // `<div>` with `absolute` + %-based clamps so the panel stays
          // inside its container. Otherwise → `fixed` + vw/dvh clamps so
          // it owns the viewport corner (iframe / web-component embeds).
          //
          // `data-wx-panel` opts the element into the theme-aware
          // shadow + frame-glow rules in globals.css (light: drop
          // shadow; dark: hairline ring + radial glow blob + stronger
          // shadow).
          embedded ? "absolute" : "fixed",
          "bottom-24 rounded-wx-xl",
          embedded
            ? "max-w-[calc(100%-2rem)] max-h-[calc(100%-7rem)]"
            : "max-w-[calc(100vw-2rem)] max-h-[calc(100dvh-7rem)]",
          launcherLeft ? "left-4" : "right-4",
        )}
      >
        {/* Home gradient backdrop (panel-level so it bleeds under
            anything that overlays it). Base gradient stops on the
            operator-themed `--wx-bg` so the bottom edge dissolves
            cleanly into the panel below the `h-96` band — without
            this the dark mode used hardcoded greys and you'd see a
            seam wherever the operator's theme tinted `--wx-bg` away
            from those greys (e.g. a green-tinged dark palette). Only
            the radial-tint opacity differs between light and dark. */}
        {isHome && (
          <div
            aria-hidden="true"
            className="pointer-events-none absolute inset-x-0 top-0 -z-10 h-96 bg-[radial-gradient(120%_80%_at_50%_-10%,rgba(99,102,241,0.22),transparent_55%),linear-gradient(to_bottom,var(--wx-bg-elevated-2)_0%,var(--wx-bg-elevated)_40%,var(--wx-bg)_75%)] dark:bg-[radial-gradient(120%_80%_at_50%_-10%,rgba(99,102,241,0.35),transparent_55%),linear-gradient(to_bottom,var(--wx-bg-elevated-2)_0%,var(--wx-bg-elevated)_40%,var(--wx-bg)_75%)]"
          />
        )}

        {/* Per-route sticky header. Home has no sticky header — its
            chrome is rendered inside the scrollable content area. */}
        <RouteHeader
          route={route}
          onPop={() => setRoute(popRoute(route, config.features))}
          onClose={close}
        />

        {/* `relative` so the absolutely-anchored route layers stack
            inside the main area. Both exiting and entering routes
            occupy `inset-0` so the panel height never jumps mid-
            transition. */}
        <main className="relative flex flex-1 flex-col overflow-hidden">
          {/* Defer mounting tab content until the visitor has
              opened the panel at least once. The launcher unread
              query + visitor-auth handshake already cover what we
              need while closed; deferring everything else keeps the
              initial page-load footprint to one query (`visitorChatUnread`)
              instead of all four tabs racing to fetch their own
              data. After the first open, `hasOpened` stays true and
              the standard mount/unmount of routed tabs takes over. */}
          {hasOpened && (
            // `mode="sync"` (not `popLayout`): the routes are
            // `absolute inset-0` and cross-slide via a `transform` — there
            // are no siblings to reflow, so popLayout's per-frame FLIP
            // *layout* measurement (the bulk of the animation cost in
            // profiling: ~1.2s of `serviceScriptedAnimations`) was pure
            // overhead, and popLayout kept the *outgoing* heavy tab
            // re-rendering as it exited. `sync` overlaps enter+exit on
            // transform/opacity only — same visual, compositor-driven.
            <AnimatePresence mode="sync" initial={false} custom={direction}>
              <motion.div
                key={routeKey(route)}
                custom={direction}
                variants={routeVariants}
                initial="enter"
                animate="center"
                exit="exit"
                // Tween (not spring) for two reasons:
                //   1. Spring simulators re-render every frame until
                //      the velocity settles below threshold — for the
                //      visitor that's invisible work paid for *every*
                //      route change. A 180 ms ease-out covers the
                //      visible distance in fewer integration steps at
                //      lower CPU, and the result looks identical at
                //      this scale (28 px is too small for spring's
                //      overshoot to read).
                //   2. The outgoing route keeps re-rendering as React
                //      still owns it during the exit — a heavy tab
                //      (Messages with its live query) burns frames while
                //      exiting. The short tween caps that exit work to
                //      ~11 frames at 60 fps (and `startTransition` on the
                //      tab swap keeps the *incoming* render off these
                //      frames).
                transition={{
                  x: { type: "tween", duration: 0.18, ease: [0.32, 0.72, 0, 1] },
                  opacity: { duration: 0.14, ease: "easeOut" },
                }}
                // `will-change: transform` hoists the slide into its
                // own GPU compositor layer — paints stay off the main
                // thread, which is what makes the slide read as
                // smooth even when the incoming route's first frame
                // is heavy (Apollo first-paint, large lists, etc.).
                style={{ willChange: "transform, opacity" }}
                className="absolute inset-0 flex flex-col overflow-hidden"
              >
                {route.kind === "home" && (
                  <HomeTab
                    config={config}
                    organizationLogoUrl={organizationLogoUrl}
                    onClose={close}
                    onOpenTab={(tab) => setRoute({ kind: tab })}
                    onOpenNewsArticle={(id) => setRoute({ kind: "news-article", id })}
                    onOpenHelpArticle={(slug) =>
                      setRoute({
                        kind: "help-article",
                        slug,
                        from: "search",
                      })
                    }
                    isDummy={isDummy}
                    chatId={session.chatId ?? null}
                  />
                )}
                {route.kind === "messages" && (
                  <MessagesTab
                    isDummy={isDummy}
                    chatId={session.chatId}
                    token={session.token}
                    prechatForm={config.prechatForm}
                    messenger={config.messenger}
                    organizationLogoUrl={organizationLogoUrl}
                    organizationName={config.messenger?.title ?? ""}
                    isOpen={isOpen}
                    onInbound={playInbound}
                    onOutbound={playOutbound}
                    registerRealtimeHandler={registerMessagesRealtimeHandler}
                    unreadCount={unread.count}
                    clearUnread={unread.clear}
                    liveMessages={liveMessages}
                    appendLiveMessage={appendLiveMessage}
                    replaceLiveMessage={replaceLiveMessage}
                    initialVisitorMessage={pendingPeekReply}
                    onInitialVisitorMessageSent={() => setPendingPeekReply(null)}
                    visitorIdentity={visitorIdentity}
                    visitorPrefill={visitorPrefill}
                    security={config.security}
                    verified={session.verified}
                    onGoogleCredential={(idToken) => setWidgetIdentity({ googleIdToken: idToken })}
                    onPasskeySession={(result: PasskeySessionResult) => {
                      // Persist so a reload restores this verified session
                      // (passkey can't be silently re-proven). Also drive
                      // the immediate (pre-reload) UI via the override.
                      persistIdentifiedSession(result);
                      setPasskeySession({
                        token: result.token,
                        chatId: result.chatId,
                        peopleId: result.peopleId,
                        displayName: result.displayName,
                        isAuthenticating: false,
                        error: null,
                        verified: true,
                      });
                    }}
                    onInternalLink={(link) => {
                      // AI replies sometimes link to internal articles
                      // (`/help/.../slug` or `/news/slug`). Route them
                      // through the widget's own viewer instead of
                      // following the browser navigation to the widget's
                      // origin (where the path doesn't exist).
                      if (link.kind === "help-article") {
                        setRoute({
                          kind: "help-article",
                          slug: link.slug,
                          from: "search",
                          locale: link.locale,
                        });
                      } else if (link.kind === "news-article") {
                        // Best-effort fallback: drop the visitor on the
                        // news feed. A future improvement is to extend
                        // `NewsArticleView` to accept a slug so we can
                        // open the specific post directly. For now the
                        // visitor lands in the right tab and can find it.
                        setRoute({ kind: "news" });
                      }
                    }}
                  />
                )}
                {route.kind === "help" && (
                  <HelpTab
                    isDummy={isDummy}
                    onOpenCategory={(categoryId, meta) =>
                      setRoute({
                        kind: "help-category",
                        categoryId,
                        categoryName: meta?.name,
                        categoryDescription: meta?.description,
                        categoryArticleCount: meta?.articleCount,
                      })
                    }
                    onOpenArticle={(slug) =>
                      setRoute({ kind: "help-article", slug, from: "search" })
                    }
                  />
                )}
                {route.kind === "help-category" && (
                  <HelpCategoryView
                    categoryId={route.categoryId}
                    categoryName={route.categoryName}
                    categoryDescription={route.categoryDescription}
                    categoryArticleCount={route.categoryArticleCount}
                    isDummy={isDummy}
                    onOpenCategory={(cid, meta) =>
                      setRoute({
                        kind: "help-category",
                        categoryId: cid,
                        categoryName: meta?.name,
                        categoryDescription: meta?.description,
                        categoryArticleCount: meta?.articleCount,
                      })
                    }
                    onOpenArticle={(slug) =>
                      setRoute({
                        kind: "help-article",
                        slug,
                        from: "category",
                        fromCategoryId: route.categoryId,
                      })
                    }
                  />
                )}
                {route.kind === "help-article" && (
                  <Suspense fallback={<RouteChunkFallback />}>
                    <HelpArticleView
                      slug={route.slug}
                      // Honour a language-selector override (slug + the
                      // chosen variant's locale); otherwise the widget
                      // locale drives the lookup.
                      locale={route.locale ?? locale}
                      isDummy={isDummy}
                      onHandoff={() => setRoute({ kind: "messages" })}
                      onOpenArticle={(s: string) =>
                        setRoute({
                          kind: "help-article",
                          slug: s,
                          from: "search",
                        })
                      }
                      onOpenTranslation={(s: string, loc: string) =>
                        // Switch language in place — keep the same
                        // back-nav context so "Back" still lands where
                        // the visitor came from.
                        setRoute({
                          kind: "help-article",
                          slug: s,
                          locale: loc,
                          from: route.from,
                          fromCategoryId: route.fromCategoryId,
                        })
                      }
                      onTitleResolved={setArticleTitle}
                    />
                  </Suspense>
                )}
                {route.kind === "news" && (
                  <NewsTab
                    isDummy={isDummy}
                    onOpenArticle={(id) => setRoute({ kind: "news-article", id })}
                  />
                )}
                {route.kind === "news-article" && (
                  <Suspense fallback={<RouteChunkFallback />}>
                    <NewsArticleView
                      id={route.id}
                      isDummy={isDummy}
                      onOpenRelated={(rid) => setRoute({ kind: "news-article", id: rid })}
                      onTitleResolved={setArticleTitle}
                    />
                  </Suspense>
                )}
                {route.kind === "profile" && <ProfileTab isDummy={isDummy} />}
              </motion.div>
            </AnimatePresence>
          )}
        </main>

        {showTabs && (
          <BottomNav
            active={activeTab}
            features={config.features}
            onChange={switchTab}
            unreadCount={unread.count}
          />
        )}
        {/* Branding sits inline as the very last line of the panel.
            On list routes it lands under the tab nav; on drill-in
            routes (messages, article, etc.) it sits under the
            composer / content. Always animates up from below on
            mount via motion so it still feels like it "rises into
            place" without overlapping the composer's tap surface. */}
        {showBrandingFooter && <BrandingFooter />}
      </motion.div>

      <LauncherPeek
        message={!isOpen ? unread.lastMessage : null}
        onOpen={handlePeekOpen}
        onDismiss={unread.clear}
        onSendButton={handlePeekButton}
        position={launcherLeft ? "left" : "right"}
        embedded={embedded}
      />

      <WidgetLauncher
        isOpen={isOpen}
        onToggle={() => setIsOpen((prev) => !prev)}
        unreadCount={unread.count}
        position={launcherLeft ? "left" : "right"}
        embedded={embedded}
      />
    </>
  );

  function RouteHeader({
    route,
    onPop,
    onClose,
  }: {
    route: WidgetRoute;
    onPop: () => void;
    onClose: () => void;
  }) {
    if (route.kind === "messages") {
      // Messages is a drill-in route from any list tab — but if the
      // operator only enabled Messenger there is no list tab to pop
      // to, so we omit `onBack` entirely (the header hides the chip
      // rather than rendering a dead control).
      const canPop = tabCount > 1;
      // Operator can override the header title + subtitle via
      // `config.messenger`. Falls back to the org name / i18n
      // subtitle when not configured, so existing embeds without
      // the new config don't change behaviour.
      const messengerTitle = config.messenger?.title?.trim() || AI_ASSISTANT_NAME;
      const messengerSubtitle =
        config.messenger?.description?.trim() || tHeader("conversationSubtitle");
      return (
        <ConversationHeader
          title={messengerTitle}
          subtitle={messengerSubtitle}
          organizationLogoUrl={conversationLogoUrl}
          muted={muted}
          onToggleMute={toggleMuted}
          onBack={canPop ? onPop : undefined}
          onClose={onClose}
          expanded={effectiveExpanded}
          onToggleExpand={() => setExpanded((v) => !v)}
        />
      );
    }
    if (route.kind === "help") {
      return <TabTitleHeader title={tHeader("helpTitle")} onClose={onClose} />;
    }
    if (route.kind === "help-category") {
      return <TabTitleHeader title={tHeader("helpTitle")} onBack={onPop} onClose={onClose} />;
    }
    if (route.kind === "help-article") {
      return (
        <TabTitleHeader
          // Show the article's title once it has loaded — falls back
          // to the parent-tab nameplate while the data is in flight.
          title={articleTitle ?? tHeader("helpTitle")}
          onBack={onPop}
          onClose={onClose}
          expanded={effectiveExpanded}
          onToggleExpand={() => setExpanded((v) => !v)}
        />
      );
    }
    if (route.kind === "news") {
      return <TabTitleHeader title={tHeader("newsTitle")} onClose={onClose} />;
    }
    if (route.kind === "news-article") {
      return (
        <TabTitleHeader
          title={articleTitle ?? tHeader("newsTitle")}
          onBack={onPop}
          onClose={onClose}
          expanded={effectiveExpanded}
          onToggleExpand={() => setExpanded((v) => !v)}
        />
      );
    }
    return null; // home — no sticky header
  }
}
