"use client";

import { Check, Loader2, X } from "lucide-react";
import { useLocale, useTranslations } from "next-intl";
import { useCallback, useEffect, useMemo, useState } from "react";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Skeleton } from "@/components/ui/skeleton";
import { ALLOWED_UPLOAD_MIMES, fileToBase64, MAX_UPLOAD_BYTES } from "@/lib/file-to-base64";
import { useUploadVisitorMediaMutation } from "@/lib/graphql/queries/generated/messaging.generated";
import {
  useUpdateVisitorProfileMutation,
  useVisitorProfileQuery,
  VisitorProfileDocument,
  type VisitorProfileField,
} from "@/lib/graphql/queries/generated/profile.generated";
import { useWidgetConfig } from "@/lib/use-widget-config";
import { cn } from "@/lib/utils";
import { AvatarHero } from "./avatar-hero";
import { FieldRow } from "./field-row";
import { diffFields, isEmpty, pickDisplayName, seedValues } from "./helpers";
import { PreferencesSection } from "./preferences-section";
import {
  extractInvalidFieldKey,
  extractProfileErrorKind,
  profileErrorI18nKey,
} from "./profile-error";
import { Section } from "./section";
import { useApplyPref } from "./use-apply-pref";
import { validateFieldValue } from "./validators";

interface ProfileTabProps {
  /** Demo mode — the visitor-profile query is BE-only; in demo we render
   *  an explanatory placeholder so the tab still has *something* to show. */
  isDummy: boolean;
}

/**
 * Visitor-editable profile + preferences.
 *
 * Field shape + types are dictated by the BE (`visitorProfile.fields[]`).
 * Identity fields (name, email, phone, …) buffer locally and write on
 * "Save"; preferences (theme, language, notifications) auto-save with
 * an optimistic cache write so the widget chrome flips this tick.
 *
 * AVATAR is rendered as a centered hero, uploadable via the visitor
 * media service (base64 → `uploadVisitorMedia`); the resulting URL is
 * the value stored back on the profile field.
 *
 * This file is the ORCHESTRATOR — every concern lives in a sibling
 * module so each piece is independently testable:
 *
 *   - `avatar-hero.tsx`        — the centered avatar widget
 *   - `field-row.tsx`          — one row in the identity form
 *   - `field-controls/`        — one file per `VisitorProfileFieldType`
 *   - `preferences-section.tsx` — language / theme / notifications
 *   - `use-apply-pref.ts`      — preference auto-save hook
 *   - `helpers.ts`             — seed / diff / normalise / display
 *   - `validators.ts`          — email + phone (libphonenumber-js/min)
 *   - `profile-error.ts`       — Apollo error → kind + field key
 */
export function ProfileTab({ isDummy }: ProfileTabProps) {
  const t = useTranslations("profile");
  const tTabs = useTranslations("tabs");
  const locale = useLocale();
  const { config } = useWidgetConfig();

  // Visitors can pick a UI language only when the operator hasn't forced
  // one. `DEFAULT` strategy = operator pin → hide the row entirely.
  const languageEditable = config.localeStrategy !== "DEFAULT";

  const { data, loading, error: loadError, refetch } = useVisitorProfileQuery({ skip: isDummy });
  const profile = data?.visitorProfile;

  const [update, { loading: saving }] = useUpdateVisitorProfileMutation();
  const [uploadMedia, { loading: avatarUploading }] = useUploadVisitorMediaMutation();
  const { apply: applyPref, saving: prefSaving } = useApplyPref(profile, t);

  // Identity-field draft buffer. Edits ONLY become part of the mutation
  // when the visitor taps "Save" — preferences are auto-saved separately
  // (see `useApplyPref`). Keeping the two paths apart means a half-typed
  // name never sneaks into a theme-flip's payload.
  const [values, setValues] = useState<Record<string, string | null>>({});
  const [hasEdits, setHasEdits] = useState(false);
  const [savedFlash, setSavedFlash] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({});

  // Seed (or re-seed after a save) when the BE-resolved profile changes
  // and the visitor isn't mid-edit. Preferences are NOT seeded — they
  // read straight off `profile.preferences` (optimistic cache writes
  // flip the cache, so the form always reflects authoritative state
  // without local buffering).
  useEffect(() => {
    if (!profile) return;
    if (hasEdits) return;
    setValues(seedValues(profile));
  }, [profile, hasEdits]);

  const { avatarField, regularFields } = useMemo(() => {
    if (!profile) return { avatarField: null as VisitorProfileField | null, regularFields: [] };
    const av = profile.fields.find((f) => f.type === "AVATAR") ?? null;
    const rest = profile.fields.filter((f) => f.type !== "AVATAR");
    return { avatarField: av, regularFields: rest };
  }, [profile]);

  const setFieldValue = useCallback((key: string, value: string | null) => {
    setValues((prev) => ({ ...prev, [key]: value }));
    setHasEdits(true);
    setSavedFlash(false);
    setSubmitError(null);
    setFieldErrors((prev) => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  }, []);

  const handleDiscard = useCallback(() => {
    if (!profile) return;
    setValues(seedValues(profile));
    setHasEdits(false);
    setSubmitError(null);
    setFieldErrors({});
  }, [profile]);

  const handleSave = useCallback(async () => {
    if (!profile) return;

    // Client-side validation: required + per-field (email/phone) checks.
    // Collect ALL errors before bailing so the visitor sees every bad
    // field at once instead of one-at-a-time whack-a-mole.
    const nextErrors: Record<string, string> = {};
    for (const f of profile.fields) {
      if (f.pinned) continue;
      const v = values[f.key] ?? null;
      if (f.required && isEmpty(v)) {
        nextErrors[f.key] = t("requiredHint");
        continue;
      }
      const kind = validateFieldValue(f, v);
      if (kind) nextErrors[f.key] = t(kind);
    }
    if (Object.keys(nextErrors).length > 0) {
      setFieldErrors(nextErrors);
      setSubmitError(t("errorFieldInvalid"));
      return;
    }

    const fieldUpdates = diffFields(profile.fields, values);
    if (fieldUpdates.length === 0) return;

    setSubmitError(null);
    setFieldErrors({});
    try {
      const res = await update({
        variables: { input: { fields: fieldUpdates } },
        update: (cache, { data: mut }) => {
          const next = mut?.updateVisitorProfile;
          if (!next) return;
          cache.writeQuery({
            query: VisitorProfileDocument,
            data: { visitorProfile: next },
          });
        },
      });
      const next = res.data?.updateVisitorProfile;
      if (next) {
        setValues(seedValues(next));
        setHasEdits(false);
        setSavedFlash(true);
        setTimeout(() => setSavedFlash(false), 2400);
      }
    } catch (err) {
      const kind = extractProfileErrorKind(err);
      if (kind === "fieldInvalid") {
        const fk = extractInvalidFieldKey(err);
        if (fk) setFieldErrors({ [fk]: t("errorFieldInvalid") });
      }
      setSubmitError(t(profileErrorI18nKey(kind)));
    }
  }, [profile, t, update, values]);

  const handleAvatarFile = useCallback(
    async (file: File) => {
      if (!avatarField) return;
      setSubmitError(null);
      if (!ALLOWED_UPLOAD_MIMES.has(file.type) || !file.type.startsWith("image/")) {
        setSubmitError(t("errorGeneric"));
        return;
      }
      if (file.size > MAX_UPLOAD_BYTES) {
        setSubmitError(t("errorGeneric"));
        return;
      }
      try {
        const { base64 } = await fileToBase64(file);
        const res = await uploadMedia({
          variables: {
            input: { filename: file.name, mimetype: file.type, dataBase64: base64 },
          },
        });
        const url = res.data?.uploadVisitorMedia?.url;
        if (!url) throw new Error("empty upload response");
        setFieldValue(avatarField.key, url);
      } catch {
        setSubmitError(t("errorGeneric"));
      }
    },
    [avatarField, setFieldValue, t, uploadMedia],
  );

  if (isDummy) {
    return (
      <ScrollArea className="flex-1">
        <div className="flex flex-col gap-3 px-4 py-6">
          <h1 className="text-lg font-semibold text-wx-fg">{tTabs("profile")}</h1>
          <p className="text-sm text-wx-fg-muted">{t("subtitle")}</p>
        </div>
      </ScrollArea>
    );
  }

  if (loading) {
    return (
      <ScrollArea className="flex-1">
        <div className="flex flex-col gap-4 px-5 py-6" aria-busy="true">
          <div className="mx-auto flex flex-col items-center gap-3">
            <Skeleton className="h-24 w-24 rounded-full" />
            <Skeleton className="h-4 w-32 rounded" />
          </div>
          <Skeleton className="h-9 w-full rounded-wx-sm" />
          <Skeleton className="h-9 w-full rounded-wx-sm" />
          <Skeleton className="h-9 w-full rounded-wx-sm" />
          <span className="sr-only">{t("loading")}</span>
        </div>
      </ScrollArea>
    );
  }

  if (loadError || !profile) {
    return (
      <ScrollArea className="flex-1">
        <div className="flex flex-col gap-3 px-5 py-6">
          <p className="text-sm text-wx-danger">{t("loadError")}</p>
          <button
            type="button"
            onClick={() => refetch()}
            className="self-start rounded-full bg-wx-bg-elevated px-3 py-1.5 text-sm text-wx-fg hover:bg-wx-bg-elevated-2"
          >
            {t("retry")}
          </button>
        </div>
      </ScrollArea>
    );
  }

  const avatarValue = avatarField ? (values[avatarField.key] ?? null) : null;
  const avatarHeroName = pickDisplayName(profile, values);

  return (
    <div className="flex h-full min-h-0 flex-col">
      <ScrollArea className="min-h-0 flex-1">
        <form
          id="wx-profile-form"
          onSubmit={(e) => {
            e.preventDefault();
            void handleSave();
          }}
          className="flex flex-col px-5 pt-2 pb-4"
        >
          {avatarField && (
            <AvatarHero
              field={avatarField}
              value={avatarValue}
              uploading={avatarUploading}
              onPick={handleAvatarFile}
              onClear={() => setFieldValue(avatarField.key, null)}
              displayName={avatarHeroName}
              t={t}
            />
          )}

          {regularFields.length > 0 && (
            <Section eyebrow={t("title")}>
              {regularFields.map((f) => (
                <FieldRow
                  key={f.key}
                  field={f}
                  value={values[f.key] ?? null}
                  onChange={(v) => setFieldValue(f.key, v)}
                  error={fieldErrors[f.key]}
                  t={t}
                />
              ))}
            </Section>
          )}

          {!avatarField && regularFields.length === 0 && (
            <p className="py-6 text-center text-sm text-wx-fg-muted">{t("noFields")}</p>
          )}

          <PreferencesSection
            profile={profile}
            locale={locale}
            languageEditable={languageEditable}
            prefSaving={prefSaving}
            applyPref={applyPref}
            onNotificationError={(k) => setSubmitError(k ? t(k) : null)}
            t={t}
          />

          {submitError && (
            <p className="mt-4 flex items-start gap-1.5 rounded-wx-sm bg-wx-danger/10 px-3 py-2 text-xs text-wx-danger">
              <X size={13} aria-hidden="true" className="mt-0.5 shrink-0" />
              <span>{submitError}</span>
            </p>
          )}
          {savedFlash && !submitError && (
            <p className="mt-4 flex items-center gap-1.5 rounded-wx-sm bg-wx-success/10 px-3 py-2 text-xs text-wx-success">
              <Check size={13} aria-hidden="true" />
              <span>{t("saved")}</span>
            </p>
          )}
        </form>
      </ScrollArea>

      {/* Sticky save bar — only shown when identity fields have unsaved
          edits. Preferences auto-save (see `useApplyPref`) and don't
          surface a button here. */}
      {hasEdits && (
        <div className="flex items-center gap-2 border-t border-wx-border bg-wx-bg/95 px-4 py-3 backdrop-blur">
          <button
            type="submit"
            form="wx-profile-form"
            disabled={saving}
            className={cn(
              "flex flex-1 items-center justify-center gap-1.5 rounded-full bg-wx-primary px-4 py-2 text-sm font-semibold text-wx-primary-fg",
              "hover:bg-wx-primary-hover disabled:cursor-not-allowed disabled:opacity-60",
            )}
          >
            {saving && <Loader2 size={14} className="animate-spin" aria-hidden="true" />}
            {saving ? t("saving") : t("save")}
          </button>
          <button
            type="button"
            onClick={handleDiscard}
            disabled={saving}
            className={cn(
              "rounded-full bg-wx-bg-elevated px-4 py-2 text-sm font-medium text-wx-fg",
              "hover:bg-wx-bg-elevated-2 disabled:cursor-not-allowed disabled:opacity-60",
            )}
          >
            {t("cancel")}
          </button>
        </div>
      )}
    </div>
  );
}
