/**
 * Demo-mode conversation thread. Surfaced when the widget runs with
 * `forceDummyData` / `mode=demo` — see `lib/use-widget-env.tsx`.
 *
 * Structure (ids, direction, sender kind, media URLs + mimetypes,
 * button payloads, delivery status) lives here; the translatable text
 * (bubble body, chip labels, media alt text, time labels, visitor name)
 * comes from the `demo.conversation.*` next-intl namespace (both
 * locales), read via `t.raw()`. See `dummy/translator.ts`.
 *
 * The thread exercises every bubble variant (text, quick-reply chips,
 * single + multi-image galleries, video, PDF, voice note).
 */

import type { WidgetMessengerMessageKind } from "@/lib/widget-config";
import type { DemoTranslator } from "./translator";

/**
 * Demo welcome run painted at the top of the thread. Two kinds:
 *   - **SYSTEM** — centred status pill ("chat started with Gaia").
 *   - **HINT**   — bordered tip card with an icon (Intercom-style).
 * Both are always shown — see MessagesTab. (`TEXT` was retired alongside
 * the WEB_VISITOR_VISIT flow trigger; proactive bot greetings now arrive
 * via SSE as runtime messages.) Localised via `demo.messenger.welcome.*`.
 */
export function getMockWelcomeMessages(
  t: DemoTranslator,
): { kind: WidgetMessengerMessageKind; text: string }[] {
  return [
    { kind: "SYSTEM", text: t.raw("messenger.welcome.system") as string },
    { kind: "HINT", text: t.raw("messenger.welcome.hint") as string },
  ];
}

export interface MockMessageButton {
  text: string;
  payload: string;
}

export interface MockMessageMedia {
  url: string;
  mimetype: string;
  alt: string;
}

/**
 * Delivery state shared by inbound + outbound messages. Mirrors the
 * BE's `MessageDeliveryStatus` enum so values map 1:1 in either
 * direction.
 */
export type MockMessageDeliveryStatus = "SENT" | "DELIVERED" | "READ" | "FAILED";

export interface MockMessage {
  id: string;
  direction: "INBOUND" | "OUTBOUND";
  text: string;
  ageLabel: string;
  /** ISO timestamp the message was created. Drives the date-separator
   *  grouping. Absent on optimistic/live appends — the row builder treats
   *  a missing value as "now" (so a just-sent message groups under today). */
  createdAt?: string;
  /** Stable React key for the rendered row. Set at optimistic-append
   *  time and PRESERVED across the tmp-id → BE-id swap that happens
   *  when the send mutation resolves. Without this, `id` change would
   *  flip the `<AnimatePresence>` key and the bubble would unmount +
   *  remount → visible re-animation that reads as a "lag". History
   *  messages don't carry a clientKey; the row builder falls back to
   *  `id` for them (which is stable, being the BE-canonical id). */
  clientKey?: string;
  sender: {
    kind: "operator" | "ai" | "bot" | "visitor";
    name: string;
    avatar?: string;
  };
  buttons?: MockMessageButton[];
  media?: MockMessageMedia[];
  deliveryStatus?: MockMessageDeliveryStatus;
}

/** Locale-independent fields, defined once. Sender `name` is set for
 *  AI / operator senders (proper names, not translated); visitor
 *  bubbles take the localised name from `conversation.visitorName`.
 *  Button `payload`s and media URL + mimetype never change across
 *  locales. */
interface ConvStruct {
  id: string;
  direction: MockMessage["direction"];
  sender: { kind: MockMessage["sender"]["kind"]; name?: string };
  buttons?: { payload: string }[];
  media?: { url: string; mimetype: string }[];
  deliveryStatus?: MockMessageDeliveryStatus;
}

