/**
 * Build the demo conversation from the active `demo` translator. Per-
 * message text / chip labels / media alts come from
 * `demo.conversation.messages.<id>.*`; the visitor's display name from
 * `demo.conversation.visitorName`.
 */
export function getMockConversation(t: DemoTranslator): MockMessage[] {
  const visitorName = t.raw("conversation.visitorName") as string;
  return CONV_STRUCT.map((s) => {
    const base = `conversation.messages.${s.id}`;
    const message: MockMessage = {
      id: s.id,
      direction: s.direction,
      text: t.raw(`${base}.text`) as string,
      ageLabel: t.raw(`${base}.ageLabel`) as string,
      sender: {
        kind: s.sender.kind,
        name: s.sender.kind === "visitor" ? visitorName : (s.sender.name ?? ""),
      },
    };
    if (s.buttons) {
      const labels = t.raw(`${base}.buttons`) as string[];
      message.buttons = s.buttons.map((b, i) => ({ payload: b.payload, text: labels[i] ?? "" }));
    }
    if (s.media) {
      const alts = t.raw(`${base}.mediaAlts`) as string[];
      message.media = s.media.map((m, i) => ({ ...m, alt: alts[i] ?? "" }));
    }
    if (s.deliveryStatus) message.deliveryStatus = s.deliveryStatus;
    return message;
  });
}
