import type { MockMessageButton } from "@/dummy";
import type { DemoTranslator } from "@/dummy/translator";

/**
 * Picks a canned AI reply for demo mode. Pattern-matches the visitor's
 * text against a few intents; falls back to a generic "let me check"
 * line. Returned reply may carry follow-up quick-reply buttons so the
 * conversation can keep going without typing.
 *
 * Reply text + button labels are localised via the demo `messenger.replies.*`
 * namespace (read off the passed `DemoTranslator`). The intent *keywords*
 * are still English-only — non-Latin / localised input falls through to
 * the (localised) fallback reply, which is acceptable for the demo.
 */
export function pickDummyReply(
  text: string,
  t: DemoTranslator,
): { text: string; buttons?: MockMessageButton[] } {
  const lower = text.toLowerCase();
  if (lower.includes("pric")) {
    return {
      text: t.raw("messenger.replies.pricing.text") as string,
      buttons: [
        { text: t.raw("messenger.replies.pricing.planBtn") as string, payload: "plans" },
        { text: t.raw("messenger.replies.pricing.salesBtn") as string, payload: "sales" },
      ],
    };
  }
  if (lower.includes("gaia") || lower.includes("ai")) {
    return {
      text: t.raw("messenger.replies.gaia.text") as string,
      buttons: [
        { text: t.raw("messenger.replies.gaia.handoffBtn") as string, payload: "handoff-flow" },
      ],
    };
  }
  if (lower.includes("human") || lower.includes("chat with") || lower.includes("operator")) {
    return { text: t.raw("messenger.replies.human.text") as string };
  }
  return { text: t.raw("messenger.replies.fallback.text") as string };
}
