/**
 * Client-safe locale primitives — split out of `lib/i18n.ts` (which
 * imports `next/headers` and is server-only) so client components can
 * pull the supported-locale list / type without dragging the server
 * module into the browser bundle.
 *
 * Adding a new locale is a three-step change:
 *
 *   1. Add the code to `SUPPORTED_LOCALES` below.
 *   2. Drop `messages/<code>.json` with the same key shape as `en.json`.
 *   3. (Optional) extend `lib/locale-detect.ts` if the new locale uses
 *      a non-standard `Accept-Language` token that needs aliasing.
 *
 * Keep this list short — every locale ships in the widget bundle.
 */
export const SUPPORTED_LOCALES = ["en", "uk"] as const;
export const DEFAULT_LOCALE = "en";

export type SupportedLocale = (typeof SUPPORTED_LOCALES)[number];

export function isSupportedLocale(value: unknown): value is SupportedLocale {
  return typeof value === "string" && (SUPPORTED_LOCALES as readonly string[]).includes(value);
}
