"use client";

import { ChevronRight } from "lucide-react";
import { motion } from "motion/react";
import { useTranslations } from "next-intl";
import { useVisitorNewsPostCardQuery } from "@/lib/graphql/queries/generated/news.generated";
import { useWidgetEnv } from "@/lib/use-widget-env";
import type { HomeBlock, WidgetTab } from "@/lib/widget-config";
import { extractFeaturedPost } from "../helpers";

/** Single hero card for a featured news post.
 *  - **Live mode**: `newsId` set → hydrate via `visitorNewsPost({ id })`,
 *    render the post's cover + title + excerpt with the operator's
 *    `ctaLabel` (or i18n default) underneath. No id / not-found →
 *    paint a gradient placeholder.
 *  - **Demo mode**: hardcoded Pioneer "Save the date" preview so the
 *    dashboard's demo toggle shows the populated look operators are
 *    designing toward.
 */
export function FeaturedArticleBlock({
  block,
  onOpenTab,
  onOpenNewsArticle,
  isDummy,
}: {
  block: Extract<HomeBlock, { kind: "featured-article" }>;
  onOpenTab: (tab: WidgetTab) => void;
  onOpenNewsArticle?: (id: string) => void;
  isDummy: boolean;
}) {
  const t = useTranslations("home");
  const env = useWidgetEnv();

  // Dashboard-prefetched lookup takes precedence — the preview pane
  // already has the operator-side post loaded, so we render that
  // instead of round-tripping through the visitor surface.
  const previewPost =
    !isDummy && block.newsId ? env.previewData?.newsPostsById?.[block.newsId] : undefined;
  const hasPreview = previewPost !== undefined;

  // Real-data path — `visitorNewsPost({ id })` returns the post or
  // `null` for unpublished / cross-integration / missing ids. Uses the
  // slim card-only selection (no `contentMarkdown` / joins); the full
  // post hydrates lazily inside the article-detail view.
  const { data, loading } = useVisitorNewsPostCardQuery({
    variables: { args: { id: block.newsId ?? "" } },
    skip: isDummy || hasPreview || !block.newsId,
  });

  if (isDummy) {
    return (
      <motion.button
        type="button"
        // The demo hero IS the Pioneer 2026 post (`demo-news-1`) — open
        // it directly so the CTA reads as "see this article", not "go
        // to the news list". Falls back to the news tab if the shell
        // didn't wire article navigation.
        onClick={() => (onOpenNewsArticle ? onOpenNewsArticle("demo-news-1") : onOpenTab("news"))}
        whileHover={{ y: -2 }}
        whileTap={{ scale: 0.99 }}
        transition={{ type: "spring", stiffness: 360, damping: 26 }}
        className="block w-full overflow-hidden rounded-wx-xl bg-wx-bg-elevated text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wx-primary"
      >
        {/* Hero: gradient cover + centered eyebrow / headline / subline */}
        <div
          className="relative w-full"
          style={{
            aspectRatio: "16 / 11",
            backgroundImage: "linear-gradient(135deg, #1e1f3b 0%, #1a1a2e 55%, #3a1e2b 100%)",
          }}
        >
          <div className="absolute inset-0 flex flex-col items-center justify-center gap-1.5 px-6 text-center text-white">
            <p className="text-[11px] font-semibold tracking-[0.22em] uppercase opacity-80">
              {t("featuredArticleDemoEyebrow")}
            </p>
            <p className="text-2xl leading-tight font-bold">{t("featuredArticleDemoHeadline")}</p>
            <p className="text-sm opacity-85">{t("featuredArticleDemoSubline")}</p>
          </div>
        </div>
        {/* Footer CTA row — tonal background, separates from the hero */}
        <div className="flex items-center justify-between gap-2 px-4 py-3">
          <span className="truncate text-sm font-semibold text-wx-fg">
            {t("featuredArticleDemoCta")}
          </span>
          <ChevronRight size={16} className="shrink-0 text-wx-fg-subtle" />
        </div>
      </motion.button>
    );
  }

  // ─── Live mode ───────────────────────────────────────────────
  // No id → placeholder. Loading / not-found → placeholder. Both
  // states render the gradient hero so the block is never blank.
  const post = extractFeaturedPost(hasPreview ? previewPost : data?.visitorNewsPost);
  const interactive = !!post;
  const ctaLabel = block.ctaLabel?.trim() || t("featuredArticleTap");
  const onClick = interactive
    ? () => (onOpenNewsArticle ? onOpenNewsArticle(post.id) : onOpenTab("news"))
    : undefined;
  const coverImage = post?.coverImageUrl;

  if (!block.newsId || (!loading && !post)) {
    return (
      <motion.button
        type="button"
        onClick={() => onOpenTab("news")}
        whileHover={{ y: -1 }}
        whileTap={{ scale: 0.99 }}
        transition={{ type: "spring", stiffness: 360, damping: 26 }}
        className="block w-full overflow-hidden rounded-wx-xl bg-wx-bg-elevated text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wx-primary"
      >
        <div
          className="relative w-full"
          style={{
            aspectRatio: "16 / 11",
            backgroundImage: "linear-gradient(135deg, #1e1f3b 0%, #1a1a2e 55%, #3a1e2b 100%)",
          }}
        >
          <div className="absolute inset-0 flex flex-col items-center justify-center gap-1 px-6 text-center text-white">
            <p className="text-2xl leading-tight font-bold">
              {block.newsId ? t("featuredArticleLoading") : t("featuredArticleEmpty")}
            </p>
            <p className="text-sm opacity-80">{block.newsId ? "" : t("featuredArticleSetUp")}</p>
          </div>
        </div>
      </motion.button>
    );
  }

  return (
    <motion.button
      type="button"
      onClick={onClick}
      whileHover={interactive ? { y: -2 } : undefined}
      whileTap={interactive ? { scale: 0.99 } : undefined}
      transition={{ type: "spring", stiffness: 360, damping: 26 }}
      disabled={!interactive}
      className="block w-full overflow-hidden rounded-wx-xl bg-wx-bg-elevated text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wx-primary"
    >
      <div
        className="relative w-full"
        style={{
          aspectRatio: "16 / 11",
          backgroundImage: coverImage
            ? `linear-gradient(180deg, rgba(0,0,0,0.05) 0%, rgba(0,0,0,0.65) 100%), url(${coverImage})`
            : "linear-gradient(135deg, #1e1f3b 0%, #1a1a2e 55%, #3a1e2b 100%)",
          backgroundSize: "cover",
          backgroundPosition: "center",
        }}
      >
        <div className="absolute inset-0 flex flex-col items-center justify-center gap-1.5 px-6 text-center text-white">
          <p className="text-2xl leading-tight font-bold">{post?.title}</p>
          {post?.excerpt && <p className="text-sm opacity-85 line-clamp-2">{post.excerpt}</p>}
        </div>
      </div>
      <div className="flex items-center justify-between gap-2 px-4 py-3">
        <span className="truncate text-sm font-semibold text-wx-fg">{ctaLabel}</span>
        <ChevronRight size={16} className="shrink-0 text-wx-fg-subtle" />
      </div>
    </motion.button>
  );
}
