"use client";

import { Volume2, VolumeX } from "lucide-react";
import { useTranslations } from "next-intl";
import { Button } from "@/components/ui/button";
import { Icon } from "@/components/ui/icon";

interface SoundToggleProps {
  muted: boolean;
  onToggle: () => void;
}

/**
 * Mute/unmute affordance — sits in the header next to the close
 * button. Visitor-level preference is persisted by `useSoundPlayer`
 * to `localStorage` so the choice survives reloads + new tabs.
 *
 * Icon swaps between `Volume2` (audible) and `VolumeX` (muted) so the
 * current state reads at a glance. aria-label flips with state for
 * screen readers.
 */
export function SoundToggle({ muted, onToggle }: SoundToggleProps) {
  const t = useTranslations("sound");
  return (
    <Button
      type="button"
      variant="ghost"
      size="icon"
      aria-label={muted ? t("unmute") : t("mute")}
      onClick={onToggle}
    >
      <Icon icon={muted ? VolumeX : Volume2} size={18} />
    </Button>
  );
}
