"use client";

import { motion } from "motion/react";
import { useTranslations } from "next-intl";
import { lazy, Suspense, useCallback } from "react";
import type { MockMessage, MockMessageButton, MockMessageMedia } from "@/dummy";
import { AI_ASSISTANT_NAME } from "@/lib/ai-assistant";
import { type InternalLink, parseInternalLink } from "@/lib/internal-link";
import { cn } from "@/lib/utils";
import { BotAvatar } from "./bot-avatar";
import type { LightboxItem } from "./media-lightbox";

// `wavesurfer.js` is only needed for voice-note bubbles — split it out
// of the initial payload and fetch on demand. See `Media` below.
const AudioBubblePlayer = lazy(() =>
  import("./audio-bubble-player").then((m) => ({
    default: m.AudioBubblePlayer,
  })),
);

export function MessageBubble({
  message,
  organizationLogoUrl,
  organizationName,
  aiAssistantAvatarUrl,
  buttonsActive,
  onButtonClick,
  onOpenLightbox,
  onInternalLink,
}: {
  message: MockMessage;
  organizationLogoUrl?: string | null;
  organizationName?: string;
  /** Operator-uploaded AI assistant avatar URL — surfaced on AI/bot
   *  bubbles when present. When `null` / `undefined`, AI bubbles
   *  render without an avatar (the column collapses). */
  aiAssistantAvatarUrl?: string | null;
  /** When `true`, the bubble's `buttons` render as clickable chips
   *  (latest outbound run); otherwise they're hidden. */
  buttonsActive?: boolean;
  onButtonClick?: (button: MockMessageButton) => void;
  /** Opens the full-screen gallery overlay starting at the given
   *  index inside the message's visual media batch. */
  onOpenLightbox?: (items: LightboxItem[], index: number) => void;
  /** Called when the visitor taps a widget-internal link inside the
   *  message body (e.g. AI reply pointing at `/help/foo/bar`). The
   *  shell wires it to `setRoute(...)` so the article opens inside
   *  the widget instead of triggering a browser navigation to the
   *  widget's own origin (which would 404). */
  onInternalLink?: (link: InternalLink) => void;
}) {
  const t = useTranslations("messages");
  const isOutbound = message.direction === "OUTBOUND";
  // AI / bot ALWAYS reads as AI_ASSISTANT_NAME regardless of whatever label the
  // BE attached ("Bot", "WEB widget", an internal handle, …). The
  // history mapper + SSE consumer already pre-relabel, but bubble-
  // shaped messages from other entry points (preview pane, demo) may
  // not — re-assert here as a safety net so a stray "Bot" can't leak.
  // Operator names flow through; empty operator name falls back to
  // the role label below.
  const displayName =
    message.sender.kind === "ai" || message.sender.kind === "bot"
      ? AI_ASSISTANT_NAME
      : message.sender.name?.trim() || "";
  // Only show a role suffix when there's no name AND we couldn't
  // brand-default to Gaia — i.e. the sender's `kind` is `operator` or
  // unknown. Keeps the meta line clean when AI_ASSISTANT_NAME already conveys
  // the role.
  const senderRoleLabel = displayName
    ? null
    : message.sender.kind === "operator"
      ? t("operator")
      : null;
  return (
    <motion.div
      layout="position"
      // `data-message-id` is the lookup the tab's scroll effect uses to find
      // a newly-arrived bubble (querying by id) so it can scroll the TOP of
      // long operator/AI messages into view, instead of pinning the bottom.
      data-message-id={message.id}
      // Directional entrance: received (operator/AI, left) bubbles slide
      // in from the left; the visitor's own (right) bubbles from the
      // right — a short, subtle "conversation coming alive" feel.
      initial={{ opacity: 0, x: isOutbound ? -16 : 16 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0 }}
      transition={{ duration: 0.24, ease: "easeOut" }}
      className={cn("flex flex-col gap-1.5", isOutbound ? "items-start" : "items-end")}
    >
      <div
        className={cn(
          "flex max-w-[85%] items-start gap-2",
          isOutbound ? "flex-row" : "flex-row-reverse",
        )}
      >
        {isOutbound && (
          <BotAvatar
            size={28}
            senderKind={message.sender.kind}
            senderName={message.sender.name}
            senderAvatarUrl={message.sender.avatar}
            aiAssistantAvatarUrl={aiAssistantAvatarUrl}
            organizationLogoUrl={organizationLogoUrl}
            organizationName={organizationName}
            className="mt-0.5"
          />
        )}
        {(() => {
          // Split media into VISUAL (image / video) vs NON-VISUAL
          // (audio / document). Visual renders FULL-BLEED at the top
          // of the bubble; caption + non-visual media sit padded
          // below. When neither caption nor non-visual content
          // exists, the bubble background drops away and only the
          // rounded visual remains — matches modern messenger UIs
          // (Telegram / Intercom).
          const allMedia = message.media ?? [];
          // PDFs are previewable in the lightbox (iframe-rendered), so they
          // join image/video at the FULL-BLEED top of the bubble instead of
          // sitting inset in the padded section. Audio + other docs still
          // render inside the padded `nonVisual` block below.
          const isVisual = (m: MockMessageMedia) =>
            m.mimetype.startsWith("image/") ||
            m.mimetype.startsWith("video/") ||
            m.mimetype === "application/pdf";
          const visual = allMedia.filter(isVisual);
          const nonVisual = allMedia.filter((m) => !isVisual(m));
          const hasCaption = !!message.text;
          const hasNonVisual = nonVisual.length > 0;
          const showBubbleBg = hasCaption || hasNonVisual;
          return (
            <div
              className={cn(
                "max-w-full overflow-hidden rounded-wx-lg",
                showBubbleBg &&
                  (isOutbound
                    ? "bg-wx-bg-elevated text-wx-fg"
                    : "bg-wx-primary text-wx-primary-fg"),
              )}
            >
              {visual.length > 0 && (
                <VisualMediaBlock items={visual} onOpenLightbox={onOpenLightbox} />
              )}
              {(hasCaption || hasNonVisual) && (
                <div
                  className={cn(
                    "flex flex-col gap-2 px-4 py-2.5 text-sm",
                    // Tighter top padding when visual media sits
                    // above — keeps caption read as a label on the
                    // image, not a free-floating bubble.
                    visual.length > 0 && "pt-2",
                  )}
                >
                  {hasCaption && (
                    <MessageBody
                      text={message.text}
                      isOutbound={isOutbound}
                      onInternalLink={onInternalLink}
                    />
                  )}
                  {nonVisual.map((m, idx) => (
                    // biome-ignore lint/suspicious/noArrayIndexKey: per-message media is fixed-order and never reordered
                    <Media key={idx} media={m} onDark={!isOutbound} />
                  ))}
                </div>
              )}
            </div>
          );
        })()}
      </div>
      {/* Sender + time meta line. Indents to match the bubble's
          left edge (after the avatar) on outbound; right-aligns
          flush with the visitor bubble on inbound. */}
      {(displayName || message.ageLabel) && (
        <p
          className={cn(
            "flex items-center gap-1.5 text-[11px] text-wx-fg-subtle",
            isOutbound ? "ml-9" : "mr-1",
          )}
        >
          {isOutbound && displayName && (
            <span className="font-medium text-wx-fg-muted">{displayName}</span>
          )}
          {isOutbound && senderRoleLabel && (
            <>
              <span aria-hidden="true">·</span>
              <span>{senderRoleLabel}</span>
            </>
          )}
          {message.ageLabel && (
            <>
              {(isOutbound && displayName) || (isOutbound && senderRoleLabel) ? (
                <span aria-hidden="true">·</span>
              ) : null}
              <span>{message.ageLabel}</span>
            </>
          )}
        </p>
      )}
      {buttonsActive && message.buttons && message.buttons.length > 0 && (
        <motion.div
          initial={{ opacity: 0, y: 4 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0 }}
          transition={{ duration: 0.18, ease: "easeOut" }}
          className={cn(
            "flex flex-wrap gap-1",
            isOutbound ? "ml-9 max-w-[85%]" : "mr-1 justify-end",
          )}
        >
          {message.buttons.map((btn) => (
            <motion.button
              key={btn.payload}
              type="button"
              onClick={() => onButtonClick?.(btn)}
              whileHover={{ y: -1 }}
              whileTap={{ scale: 0.96 }}
              transition={{ type: "spring", stiffness: 480, damping: 26 }}
              className={cn(
                // Inside the conversation the chips read as
                // satellites of the operator bubble — so they take
                // the SAME `bg-wx-bg-elevated` surface as the
                // bubble itself (the launcher peek uses bare
                // `bg-wx-bg` because it sits on the host page, not
                // inside a panel). Hover fills with full brand.
                "rounded-full bg-wx-bg-elevated px-2.5 py-1 text-xs font-medium text-wx-primary",
                "transition-colors hover:bg-wx-primary hover:text-wx-primary-fg",
              )}
            >
              {btn.text}
            </motion.button>
          ))}
        </motion.div>
      )}
    </motion.div>
  );
}

/**
 * Renders message body text. Detects HTML by looking for a leading
 * tag opener — operator messages composed in the dashboard's TipTap
 * editor arrive as serialised HTML (`<p class="tiptap-paragraph">…`)
 * and need to be parsed, not displayed literally. Plain-text replies
 * (bot, visitor input, AI handoff intros) keep the existing pre-wrap
 * paragraph styling.
 *
 * The HTML branch uses `dangerouslySetInnerHTML` — operator content
 * is sanitised on the BE before persistence (the operator editor's
 * allowlist matches the visitor renderer's allowlist). The widget's
 * `prose`-style ruleset clamps headings / list spacing to the bubble
 * geometry so a paragraph from the editor doesn't blow out the chat
 * width.
 */
function MessageBody({
  text,
  isOutbound,
  onInternalLink,
}: {
  text: string;
  isOutbound: boolean;
  onInternalLink?: (link: InternalLink) => void;
}) {
  // Delegate click handling on the bubble body so any `<a>` embedded
  // by the operator / AI reply gets a chance to route through the
  // widget instead of letting the browser navigate. Modifier-clicks
  // (cmd / ctrl / shift / middle button) fall through to default
  // behaviour — those are explicit "open elsewhere" gestures and the
  // visitor's intent already overrides ours.
  const handleClick = useCallback(
    (event: React.MouseEvent<HTMLDivElement>) => {
      if (!onInternalLink) return;
      if (event.defaultPrevented) return;
      if (event.metaKey || event.ctrlKey || event.shiftKey || event.altKey) return;
      if (event.button !== 0) return;
      const anchor = (event.target as HTMLElement | null)?.closest?.("a");
      if (!anchor) return;
      const href = anchor.getAttribute("href");
      if (!href) return;
      const internal = parseInternalLink(href);
      if (!internal) return;
      event.preventDefault();
      onInternalLink(internal);
    },
    [onInternalLink],
  );

  const isHtml = /^\s*<[a-z][a-z0-9]*(\s|>|\/)/i.test(text);
  if (!isHtml) {
    return <p className="whitespace-pre-wrap leading-relaxed">{text}</p>;
  }
  return (
    // biome-ignore lint/a11y/noStaticElementInteractions: click is a delegating dispatcher — the underlying `<a>` is keyboard-activatable natively, the wrapper just intercepts mouse-driven default navigation
    <div
      onClick={handleClick}
      // biome-ignore lint/security/noDangerouslySetInnerHtml: BE-sanitised
      dangerouslySetInnerHTML={{ __html: text }}
      className={cn(
        "leading-relaxed",
        // Tighten editor-spawned block elements to match bubble cadence.
        "[&>p]:my-0 [&>p+p]:mt-2",
        "[&_a]:underline [&_a]:underline-offset-2 [&_a]:opacity-90 [&_a:hover]:opacity-100",
        "[&_strong]:font-semibold [&_em]:italic",
        "[&_ul]:my-1.5 [&_ul]:list-disc [&_ul]:pl-5",
        "[&_ol]:my-1.5 [&_ol]:list-decimal [&_ol]:pl-5",
        "[&_li]:my-0.5",
        "[&_code]:rounded-sm [&_code]:bg-black/10 [&_code]:px-1 [&_code]:py-0.5 [&_code]:text-[0.85em]",
        // Inbound bubbles use primary-fg text → keep code/link contrast.
        !isOutbound && "[&_code]:bg-white/15",
      )}
    />
  );
}

/**
 * Renders the visual (image / video) media stack at the top of a
 * message bubble. Single item → full-width tile that triggers the
 * lightbox on tap; multiple items → 2-column grid where each cell
 * crops to a sensible thumbnail and opens the lightbox at the
 * right index. Videos get the inline `<video controls>` for quick
 * preview AND the lightbox click affordance.
 */
function VisualMediaBlock({
  items,
  onOpenLightbox,
}: {
  items: { url: string; mimetype: string; alt: string }[];
  onOpenLightbox?: (items: LightboxItem[], index: number) => void;
}) {
  const t = useTranslations("messages");
  if (items.length === 0) return null;
  const multi = items.length > 1;
  return (
    <div
      className={cn(
        "grid w-full",
        multi ? "max-h-[20rem] grid-cols-2 gap-0.5 auto-rows-fr" : "grid-cols-1",
      )}
    >
      {items.map((item, idx) => {
        const handleOpen = () => onOpenLightbox?.(items, idx);
        // PDF — full-bleed clickable card; opens the lightbox (iframe). No
        // inline preview thumbnail (we'd need PDF.js to rasterise the first
        // page) so we show a "PDF" badge + filename + mimetype.
        if (item.mimetype === "application/pdf") {
          return (
            <button
              type="button"
              // biome-ignore lint/suspicious/noArrayIndexKey: per-message media is fixed-order and never reordered
              key={idx}
              onClick={handleOpen}
              aria-label={item.alt || t("openPreview")}
              className={cn(
                "group flex w-full cursor-zoom-in items-center gap-3 px-4 py-3 text-left",
                "bg-wx-bg-elevated text-wx-fg transition-colors hover:bg-wx-bg-elevated-2",
              )}
            >
              <span className="flex h-10 w-10 shrink-0 items-center justify-center rounded-wx-sm bg-wx-bg text-[10px] font-bold tracking-wider text-wx-fg-muted shadow-sm">
                PDF
              </span>
              <span className="flex min-w-0 flex-1 flex-col">
                <span className="truncate text-sm font-medium">{item.alt}</span>
                <span className="truncate text-xs text-wx-fg-muted">{item.mimetype}</span>
              </span>
            </button>
          );
        }
        if (item.mimetype.startsWith("video/")) {
          return (
            // biome-ignore lint/suspicious/noArrayIndexKey: per-message media is fixed-order and never reordered
            <div key={idx} className="relative w-full">
              {/* biome-ignore lint/a11y/useMediaCaption: operator-provided */}
              <video
                src={item.url}
                controls
                preload="metadata"
                className={cn("block w-full", multi ? "h-full object-cover" : "max-h-80")}
              />
              {/* Invisible click target above the video, but only
                  in the top-right corner — leaves the native
                  controls fully usable while still surfacing a
                  lightbox affordance for the rest. Simpler:
                  multi-gallery always lightboxes; single video
                  lets the visitor play inline. */}
              {multi && (
                <button
                  type="button"
                  aria-label={item.alt || t("openPreview")}
                  onClick={handleOpen}
                  className="absolute inset-0 cursor-zoom-in"
                />
              )}
            </div>
          );
        }
        return (
          <button
            type="button"
            // biome-ignore lint/suspicious/noArrayIndexKey: per-message media is fixed-order and never reordered
            key={idx}
            onClick={handleOpen}
            aria-label={item.alt || t("openImage")}
            className={cn("group relative block w-full overflow-hidden", "cursor-zoom-in")}
          >
            {/* biome-ignore lint/performance/noImgElement: operator/visitor message media of arbitrary host/dimensions; next/image needs known sizes + an allowlist */}
            <img
              src={item.url}
              alt={item.alt}
              loading="lazy"
              className={cn(
                "block w-full transition-transform duration-200 group-hover:scale-[1.02]",
                multi ? "h-full object-cover" : "max-h-80 object-cover",
              )}
            />
          </button>
        );
      })}
    </div>
  );
}

/**
 * Renderer for NON-VISUAL message media (audio / documents). Visual
 * media (image / video) is handled upstream by `VisualMediaBlock`
 * so it can sit full-bleed at the top of the bubble; this helper
 * stays focused on the in-bubble item types where the bubble
 * background needs to stick.
 */
function Media({
  media,
  onDark,
}: {
  media: { url: string; mimetype: string; alt: string };
  /** True when the surrounding bubble uses `bg-wx-primary` (visitor's
   *  own message). Forwarded to the audio player so it inverts its
   *  palette. */
  onDark?: boolean;
}) {
  if (media.mimetype.startsWith("audio/")) {
    // `AudioBubblePlayer` pulls in `wavesurfer.js` (~60 KB) — lazy so
    // it only loads for conversations that actually contain a voice
    // note. The fallback keeps the bubble's height stable while the
    // chunk streams in.
    return (
      <Suspense
        fallback={
          <div className="h-12 w-56 max-w-full animate-pulse rounded-wx bg-wx-bg-elevated" />
        }
      >
        <AudioBubblePlayer src={media.url} onDark={onDark} />
      </Suspense>
    );
  }
  return <FileCard media={media} />;
}

/**
 * Generic file card. Used for documents (PDF, docx, xlsx, txt, etc.)
 * — anything the visitor can't preview inline. The icon hints at
 * mimetype family; tap → open in a new tab.
 */
function FileCard({ media }: { media: { url: string; mimetype: string; alt: string } }) {
  const label = media.alt || media.url.split("/").pop() || media.mimetype || "File";
  const typeChip = mimetypeChip(media.mimetype);
  return (
    <a
      href={media.url}
      target="_blank"
      rel="noopener"
      className="flex max-w-xs items-center gap-3 rounded-wx-sm bg-wx-bg-elevated/60 px-3 py-2.5 text-xs text-wx-fg transition-colors hover:bg-wx-bg-elevated"
    >
      <span className="flex h-9 w-9 shrink-0 items-center justify-center rounded-wx-sm bg-wx-bg-elevated-2 text-[10px] font-bold tracking-wider text-wx-fg-muted uppercase">
        {typeChip}
      </span>
      <span className="min-w-0 flex-1">
        <span className="block truncate font-medium text-wx-fg">{label}</span>
        <span className="block truncate text-wx-fg-subtle">{media.mimetype || "file"}</span>
      </span>
    </a>
  );
}

function mimetypeChip(mimetype: string): string {
  if (!mimetype) return "FILE";
  if (mimetype.includes("pdf")) return "PDF";
  if (mimetype.includes("zip") || mimetype.includes("compressed")) return "ZIP";
  if (mimetype.includes("spreadsheet") || mimetype.includes("excel")) return "XLS";
  if (mimetype.includes("word") || mimetype.includes("document")) return "DOC";
  if (mimetype.startsWith("text/")) return "TXT";
  const sub = mimetype.split("/")[1] ?? "";
  return sub.slice(0, 4).toUpperCase() || "FILE";
}
