"use client";

import { motion } from "motion/react";
import { useTranslations } from "next-intl";
import { BotAvatar } from "./bot-avatar";

/**
 * Typing indicator rendered as a real bubble — avatar + bubble with
 * three animated dots inside. Reads as "this sender is composing"
 * with the same visual weight as a regular operator message, so
 * it slots cleanly into the conversation flow.
 */
export function TypingBubble({
  actorName,
  actorKind,
  actorAvatarUrl,
  actorPhase,
  aiAssistantAvatarUrl,
  organizationLogoUrl,
  organizationName,
}: {
  actorName: string;
  actorKind?: string;
  /** Operator's own photo from the SSE beat (`from.avatar`). Wins over
   *  the initials monogram / org logo for human senders; AI/bot beats
   *  ignore it (they use `aiAssistantAvatarUrl`). */
  actorAvatarUrl?: string;
  /** AI turn phase (`"thinking"` / `"searching"` / `"typing"`) — drives
   *  the caption beneath the bubble. Defaults to "typing" for operators. */
  actorPhase?: string;
  /** Operator-uploaded AI avatar — surfaced on AI/bot typing
   *  indicators when the configured `aiAssistantAvatarUrl` is set.
   *  When null, the indicator renders without an avatar (column
   *  collapses) — matches the no-bot-identity choice on the
   *  message-bubble side. */
  aiAssistantAvatarUrl?: string | null;
  organizationLogoUrl?: string | null;
  organizationName?: string;
}) {
  const t = useTranslations("messages");
  return (
    <motion.div
      layout="position"
      initial={{ opacity: 0, y: 6 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0 }}
      transition={{ duration: 0.18 }}
      className="flex flex-col items-start gap-1.5"
    >
      <div className="flex max-w-[85%] items-start gap-2">
        <BotAvatar
          size={28}
          senderKind={actorKind}
          // Threading the actor's name lets BotAvatar paint the
          // operator's initials in the monogram fallback when the
          // SSE typing event omits an avatar URL. Previously the
          // typing indicator showed the org's first letter "W"
          // regardless of who was typing.
          senderName={actorName}
          senderAvatarUrl={actorAvatarUrl}
          aiAssistantAvatarUrl={aiAssistantAvatarUrl}
          organizationLogoUrl={organizationLogoUrl}
          organizationName={organizationName}
          className="mt-0.5"
        />
        <div className="rounded-wx-lg bg-wx-bg-elevated px-4 py-3 text-sm text-wx-fg">
          <span className="inline-flex items-end gap-1">
            <span className="h-1.5 w-1.5 animate-bounce rounded-full bg-wx-fg-muted [animation-delay:-0.3s]" />
            <span className="h-1.5 w-1.5 animate-bounce rounded-full bg-wx-fg-muted [animation-delay:-0.15s]" />
            <span className="h-1.5 w-1.5 animate-bounce rounded-full bg-wx-fg-muted" />
          </span>
        </div>
      </div>
      <p className="ml-9 text-[11px] text-wx-fg-subtle">
        {/* Fall back to a generic name when the SSE event lacks a real
            one — the previous `"…"` placeholder read as a literal
            ellipsis next to "typing…", which looked broken. */}
        <span className="font-medium text-wx-fg-muted">
          {actorName && actorName !== "…" ? actorName : t("typingSomeone")}
        </span>
        <span aria-hidden="true"> · </span>
        <span>
          {actorPhase === "thinking"
            ? t("aiThinking")
            : actorPhase === "searching"
              ? t("aiSearching")
              : t("typing")}
        </span>
      </p>
    </motion.div>
  );
}
