"use client";

import { useTranslations } from "next-intl";
import { AvatarStack } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { XIcon, type XIconHandle } from "@/components/widget/icons/animated";
import { useIconHover } from "@/lib/use-icon-hover";
import { DEFAULT_HOME_LAYOUT, type WidgetConfig, type WidgetTab } from "@/lib/widget-config";
import { filterHomeBlocks, HomeBlocks } from "../home-blocks";
import { WexioMark } from "../icons/wexio-mark";

interface HomeTabProps {
  config: WidgetConfig;
  /** Operator logo, already resolved to a single URL by the shell
   *  (`config.organizationLogo` is per-mode; the shell collapses it
   *  against the active theme mode). `null` → framed Wexio mark. */
  organizationLogoUrl: string | null;
  onClose: () => void;
  /** Open a top-level tab — Home blocks route into Messenger / Help /
   *  News rather than hydrating their content inline. */
  onOpenTab: (tab: WidgetTab) => void;
  /** Demo data mode — threaded to content-rendering blocks (news, etc.)
   *  so they pick between bundled samples and real BE data. */
  isDummy: boolean;
  /** Authenticated visitor chat id. `null` when the visitor hasn't
   *  auth'd yet — chat-bound blocks (`recent-message`) hide in that
   *  state. */
  chatId: string | null;
  /** Drill into a specific news article — `featured-article` calls this
   *  when the operator-picked post resolves. */
  onOpenNewsArticle?: (id: string) => void;
  /** Drill into a specific help article by slug — `pinned-articles`
   *  calls this when the operator-picked row resolves. */
  onOpenHelpArticle?: (slug: string) => void;
}

/**
 * Home tab — an operator-configured ordered list of blocks
 * (`config.homeLayout`, falling back to `DEFAULT_HOME_LAYOUT`).
 *
 * The header (logo + operator avatars + close) is fixed chrome and
 * scrolls away with content; everything below it is block-driven and
 * rendered by `<HomeBlocks>`. Blocks that depend on a disabled feature
 * are dropped via `filterHomeBlocks`.
 */
export function HomeTab({
  config,
  organizationLogoUrl,
  onClose,
  onOpenTab,
  isDummy,
  chatId,
  onOpenNewsArticle,
  onOpenHelpArticle,
}: HomeTabProps) {
  const tHeader = useTranslations("header");
  const closeHover = useIconHover<XIconHandle>();

  const blocks = filterHomeBlocks(config.homeLayout ?? DEFAULT_HOME_LAYOUT, config.features);

  // Greeting can be omitted entirely (operator set both lines empty).
  // Mirror the Greeting component's render guard here so we can lift
  // the first block off the header chrome — without the greeting the
  // blocks otherwise sit flush under the close/avatar row.
  // Demo always shows the localised default greeting; real mode only
  // when the operator configured a line. Mirror the `Greeting` guard.
  const hasGreeting =
    isDummy || !!config.greeting?.headline?.trim() || !!config.greeting?.subheadline?.trim();

  return (
    <ScrollArea className="flex-1">
      <div className="flex flex-col pb-6">
        {/* Inline header — scrolls away with content. The Wexio mark is
            ONLY a demo-mode placeholder so the marketing/Storybook view
            never paints a blank left chrome; in live mode an empty logo
            slot stays empty (operator hasn't uploaded one yet). */}
        <div className="flex items-center justify-between px-5 pt-5 pb-3">
          {organizationLogoUrl ? (
            // biome-ignore lint/performance/noImgElement: uploaded image of arbitrary host/dimensions; next/image needs known sizes + an allowlist
            <img
              src={organizationLogoUrl}
              alt={config.messenger?.title ?? ""}
              className="h-9 w-auto max-w-[140px] object-contain"
            />
          ) : isDummy ? (
            <WexioMark size={28} />
          ) : (
            <span className="h-9" aria-hidden="true" />
          )}
          <div className="flex items-center gap-1">
            {config.operatorAvatars.length > 0 && (
              <AvatarStack
                avatars={config.operatorAvatars}
                ringClass="ring-wx-bg-elevated/60"
                className="mr-2"
              />
            )}
            <Button
              type="button"
              variant="ghost"
              size="icon"
              aria-label={tHeader("close")}
              onClick={onClose}
              {...closeHover.parentHandlers}
            >
              <XIcon ref={closeHover.iconRef} size={18} />
            </Button>
          </div>
        </div>

        {/* Greeting — driven by the operator's `greeting.{headline,
            subheadline}` config. When the operator has set NEITHER
            field, the section is omitted entirely (no i18n placeholder
            fallback) so an unconfigured home tab doesn't surface a
            generic "Hi there 👋 / How can we help?" as if it were the
            operator's copy. */}
        <Greeting config={config} isDummy={isDummy} />

        <div className={hasGreeting ? undefined : "pt-4"}>
          <HomeBlocks
            blocks={blocks}
            config={config}
            onOpenTab={onOpenTab}
            onOpenNewsArticle={onOpenNewsArticle}
            onOpenHelpArticle={onOpenHelpArticle}
            isDummy={isDummy}
            chatId={chatId}
          />
        </div>
      </div>
    </ScrollArea>
  );
}

function Greeting({ config, isDummy }: { config: WidgetConfig; isDummy: boolean }) {
  const t = useTranslations("home");
  // Demo: show the LOCALISED default greeting (the demo config's
  // hardcoded English is only a placeholder, so it followed the widget
  // locale into Ukrainian etc.). Real: the operator's configured
  // greeting, or nothing when they set neither line.
  const headline = isDummy ? t("greetingHeadline") : (config.greeting?.headline?.trim() ?? "");
  const subheadline = isDummy
    ? t("greetingSubheadline")
    : (config.greeting?.subheadline?.trim() ?? "");
  // Operator hasn't configured either line — render nothing so the
  // home tab doesn't show a generic placeholder as if it were their
  // copy. The home gradient backdrop already carries enough visual
  // weight to anchor the top of the panel without the heading.
  if (!headline && !subheadline) return null;
  return (
    <section className="px-5 pt-2 pb-4">
      {headline && <p className="text-3xl leading-tight font-bold text-wx-fg-muted">{headline}</p>}
      {subheadline && (
        <p className="mt-1 text-3xl leading-tight font-bold text-wx-fg">{subheadline}</p>
      )}
    </section>
  );
}
