"use client";

import { useTranslations } from "next-intl";
import { useCallback, useEffect, useRef, useState } from "react";
import { getMockConversation, type MockMessage } from "@/dummy";
import { useVisitorChatUnreadLazyQuery } from "@/lib/graphql/queries/generated/messaging.generated";
import type { RealtimeMessageEvent } from "@/lib/use-visitor-realtime";

export interface UnreadPeekButton {
  /** Label rendered on the peek chip. */
  text: string;
  /** Payload sent back to the BE when the visitor taps the chip. */
  payload: string;
}

export interface UnreadPeekMessage {
  id: string;
  text: string | null;
  sender: {
    kind: string;
    name: string;
    avatar?: string;
  };
  /** Quick-reply chips attached to the message — rendered inside the
   *  peek so the visitor can answer without opening the panel. */
  buttons: UnreadPeekButton[];
}

export interface VisitorUnread {
  count: number;
  /** Most recent unread operator message. `null` when the visitor's
   *  caught up — peek hides. */
  lastMessage: UnreadPeekMessage | null;
  /** Clear locally — fired when the panel opens to Messages so the
   *  badge + peek disappear without waiting for a refetch. */
  clear: () => void;
  /** Apply an inbound realtime event to the local counter. Called by
   *  the shell's SSE pump so the badge updates without re-querying
   *  `visitorChatUnread` for every frame. */
  noteInbound: (event: RealtimeMessageEvent) => void;
  /** Apply a read-receipt event. Local count drops by the number of
   *  newly-read messages (clamped at 0); peek clears when the last
   *  unread is acked. */
  noteRead: (messageIds: string[]) => void;
}

interface UseVisitorUnreadOpts {
  chatId: string | null;
  isDummy: boolean;
}

/**
 * Drives the launcher unread badge + peek card.
 *
 * **Real mode** — fetches `visitorChatUnread` ONCE per session
 * (initial seed when `chatId` resolves) and then tracks every
 * inbound / read-receipt event locally. The SSE stream is the
 * realtime source of truth; the initial query is just reconciliation
 * for messages the visitor missed while the widget was closed on
 * previous visits.
 *
 * **Demo mode** — derives from `getMockConversation()`: the last
 * OUTBOUND message with `deliveryStatus !== "READ"` drives count + peek.
 * Calling `clear()` flags the message id as locally-read so the peek
 * dismisses; visitor can still see the messages on the panel.
 */
export function useVisitorUnread({ chatId, isDummy }: UseVisitorUnreadOpts): VisitorUnread {
  // Demo translator — drives the demo conversation language so the peek
  // preview matches the rest of the localised demo content.
  const tDemo = useTranslations("demo");

  // ─── Demo path ────────────────────────────────────────────────────
  // Seed from getMockConversation() — `cleared` flips on the visitor's
  // first visit to Messages and stays sticky for the rest of the
  // session (matches the real-mode behaviour of bulk-read).
  const [demoCleared, setDemoCleared] = useState(false);

  // ─── Real path ────────────────────────────────────────────────────
  // Local-only state — seeded once from the BE, then advanced/decremented
  // entirely from SSE events. No `refetch` on inbound — that was the
  // expensive part the user flagged.
  const [count, setCount] = useState(0);
  const [lastMessage, setLastMessage] = useState<UnreadPeekMessage | null>(null);
  // Tracks ids that already incremented our counter — protects against
  // double-counts when the SSE stream reconnects + replays. Using a ref
  // so updates don't force re-renders.
  const countedIdsRef = useRef<Set<string>>(new Set());
  // Whether the initial reconciliation pass has run for this chatId.
  // Resets when `chatId` changes (visitor session rotation).
  const seededChatRef = useRef<string | null>(null);
  // Flips `true` the moment the visitor acknowledges (opens Messages →
  // `clear()`). Guards the initial fetch's response from clobbering an
  // already-cleared state — without this, opening Messages immediately
  // on first paint would race the in-flight `visitorChatUnread` and
  // the badge would flicker back to N before the BE's read ack lands.
  const clearedSinceSeedRef = useRef(false);
  const [runUnread] = useVisitorChatUnreadLazyQuery({
    fetchPolicy: "network-only",
  });

  useEffect(() => {
    if (isDummy || !chatId) return;
    if (seededChatRef.current === chatId) return;
    seededChatRef.current = chatId;
    // Reset local tracking — new chat session, new accounting.
    countedIdsRef.current = new Set();
    clearedSinceSeedRef.current = false;
    runUnread({ variables: { chatId } })
      .then((res) => {
        // Visitor already acked while the request was in flight —
        // discard the response so we don't overwrite their cleared
        // state with a stale BE snapshot.
        if (clearedSinceSeedRef.current) return;
        const remote = res.data?.visitorChatUnread;
        if (!remote) return;
        setCount(remote.count ?? 0);
        if (remote.lastMessage) {
          const peek: UnreadPeekMessage = {
            id: remote.lastMessage.id,
            text: remote.lastMessage.text ?? null,
            sender: {
              kind: remote.lastMessage.sender.kind,
              name: remote.lastMessage.sender.name,
              avatar: remote.lastMessage.sender.avatar ?? undefined,
            },
            buttons: normaliseButtons(remote.lastMessage.buttons),
          };
          // Seed the dedupe set with the id we just learned about so
          // the SSE replay (if any) doesn't double-count it.
          countedIdsRef.current.add(peek.id);
          setLastMessage(peek);
        } else {
          setLastMessage(null);
        }
      })
      .catch(() => {
        // Soft-fail — the badge stays at 0 until SSE delivers an
        // event. We don't surface this to the visitor; the next
        // chatId change retries.
      });
  }, [chatId, isDummy, runUnread]);

  const clear = useCallback(() => {
    if (isDummy) {
      setDemoCleared(true);
      return;
    }
    // Pure local reset. The BE-side `markChatRead` mutation is owned
    // by `MessagesTab` (it has the scroll context to decide *when*
    // the visitor actually saw the message — at the bottom of the
    // list vs. scrolled up reading history). The shell calls this
    // helper after firing the mutation so the launcher peek + badge
    // disappear without waiting for the SSE read-receipt round-trip.
    setCount(0);
    setLastMessage(null);
    clearedSinceSeedRef.current = true;
    // Hold onto countedIds so a late SSE replay of already-read
    // messages can't push the counter back up — the BE has already
    // ack'd these as read on its side.
  }, [isDummy]);

  const noteInbound = useCallback(
    (event: RealtimeMessageEvent) => {
      if (isDummy) return;
      // Only real new messages count toward unread. Typing pings,
      // read-receipts, and visitor-echoes are all filtered upstream
      // in the shell — but guard here too in case a caller forgets.
      if (event.kind === "typing" || event.kind === "read-receipt") return;
      const sender = event.from ?? event.sender;
      if (sender?.kind === "visitor") return;
      const id = event.externalMessageId;
      if (!id) return;
      // Dedupe — SSE reconnects can replay the same event id.
      if (countedIdsRef.current.has(id)) return;
      countedIdsRef.current.add(id);
      setCount((prev) => prev + 1);
      const buttons: UnreadPeekButton[] = Array.isArray(event.buttons)
        ? event.buttons.map((b) => ({ text: b.label, payload: b.value }))
        : [];
      setLastMessage({
        id,
        text: event.text ?? null,
        sender: {
          kind: sender?.kind ?? "operator",
          name: sender?.name ?? "",
          ...(sender?.avatar ? { avatar: sender.avatar } : {}),
        },
        buttons,
      });
    },
    [isDummy],
  );

  const noteRead = useCallback(
    (messageIds: string[]) => {
      if (isDummy) return;
      if (messageIds.length === 0) return;
      // Drop the read ids from our dedupe set so we don't keep
      // suppressing them forever, and bring the count down by the
      // size of the overlap with what's currently in the set
      // (we only counted ids we'd previously added).
      let drop = 0;
      for (const id of messageIds) {
        if (countedIdsRef.current.has(id)) {
          countedIdsRef.current.delete(id);
          drop += 1;
        }
      }
      if (drop > 0) {
        setCount((prev) => Math.max(0, prev - drop));
      }
      setLastMessage((prev) => {
        if (!prev) return prev;
        return messageIds.includes(prev.id) ? null : prev;
      });
    },
    [isDummy],
  );

  if (isDummy) {
    const peek = demoCleared ? null : derivePeekFromMock(tDemo);
    return {
      count: peek ? 1 : 0,
      lastMessage: peek,
      clear,
      noteInbound,
      noteRead,
    };
  }

  return {
    count,
    lastMessage,
    clear,
    noteInbound,
    noteRead,
  };
}

/**
 * Walks the mock conversation back-to-front and returns the most
 * recent operator/AI message whose buttons (if any) the visitor can
 * still quick-reply with. Returns null when the conversation tail
 * is a visitor message — that means the visitor's caught up.
 */
function derivePeekFromMock(
  t: Parameters<typeof getMockConversation>[0],
): UnreadPeekMessage | null {
  const conversation = getMockConversation(t);
  for (let i = conversation.length - 1; i >= 0; i--) {
    const m: MockMessage = conversation[i];
    if (m.direction !== "OUTBOUND") continue;
    return {
      id: m.id,
      text: m.text,
      sender: {
        kind: m.sender.kind,
        name: m.sender.name,
      },
      buttons: m.buttons?.map((b) => ({ text: b.text, payload: b.payload })) ?? [],
    };
  }
  return null;
}

/**
 * The BE returns buttons as a raw JSON column — could be shaped as
 * the message-buttons schema (`{ label, value, url, type }`) OR as
 * the simpler `{ text, payload }` shape used by the visitor SDK.
 * Both are flat label/value pairs; we collapse them defensively so
 * the peek doesn't crash on an operator-side variant we didn't anticipate.
 */
function normaliseButtons(raw: unknown): UnreadPeekButton[] {
  if (!Array.isArray(raw)) return [];
  return raw
    .filter((b): b is Record<string, unknown> => typeof b === "object" && b !== null)
    .map((b) => {
      const text = pickString(b.text, b.label) ?? "";
      const payload = pickString(b.payload, b.value) ?? text;
      return { text, payload };
    })
    .filter((b) => b.text.length > 0);
}

function pickString(...values: unknown[]): string | undefined {
  for (const v of values) {
    if (typeof v === "string" && v.length > 0) return v;
  }
  return undefined;
}
