/**
 * Client-side runtime locale swap.
 *
 * The widget SSRs with one locale (resolved by middleware from cookie /
 * Accept-Language / config). After mount, the visitor's saved profile
 * preference, or a postMessage from the dashboard, can override that
 * choice WITHOUT a reload — `<RuntimeIntlProvider>` subscribes to this
 * module's signal, dynamically imports the matching messages bundle,
 * and re-renders `NextIntlClientProvider` with the new `locale` +
 * `messages` props so every `useTranslations()` call flips on next
 * render.
 *
 * Keeping the bus as a plain module avoids needing context plumbing
 * just to nudge the provider from a deep child (the ProfileTab fires
 * `setRuntimeLocale()` right after its mutation succeeds).
 */

import { DEFAULT_LOCALE, isSupportedLocale, type SupportedLocale } from "./locales";

export type MessagesBundle = Record<string, unknown>;

type Listener = (locale: SupportedLocale) => void;

let current: SupportedLocale | null = null;
const listeners = new Set<Listener>();

/** Current runtime locale, if anyone has set one. `null` means the
 *  SSR-resolved locale is still in effect — fall back to that. */
export function getRuntimeLocale(): SupportedLocale | null {
  return current;
}

/** Publish a new locale. Noop when the value matches the current one or
 *  isn't in the supported set. */
export function setRuntimeLocale(value: unknown): void {
  if (!isSupportedLocale(value)) return;
  if (current === value) return;
  current = value;
  for (const fn of listeners) fn(value);
}

export function subscribeRuntimeLocale(fn: Listener): () => void {
  listeners.add(fn);
  return () => {
    listeners.delete(fn);
  };
}

// Static import map — keeps every supported locale in the same chunk
// graph so the dynamic `import()` resolves predictably under Turbopack
// + production builds (a literal `import(\`@/messages/${l}.json\`) would
// be inferred as an any-string load and ship every JSON file in the repo).
const loaders: Record<SupportedLocale, () => Promise<MessagesBundle>> = {
  en: () => import("@/messages/en.json").then((m) => m.default as MessagesBundle),
  uk: () => import("@/messages/uk.json").then((m) => m.default as MessagesBundle),
};

export async function loadMessages(locale: SupportedLocale): Promise<MessagesBundle> {
  const loader = loaders[locale] ?? loaders[DEFAULT_LOCALE];
  return loader();
}
