"use client";

import { useTranslations } from "next-intl";
import { AvatarStack } from "@/components/ui/avatar";
import type { HomeBlock, WidgetConfig } from "@/lib/widget-config";

export function TeamStatusBlock({
  block,
  config,
}: {
  block: Extract<HomeBlock, { kind: "team-status" }>;
  config: WidgetConfig;
}) {
  const t = useTranslations("home");
  return (
    <div className="flex items-center gap-3 rounded-wx-lg bg-wx-bg-elevated px-3.5 py-3">
      <span aria-hidden="true" className="h-2 w-2 shrink-0 rounded-full bg-wx-success" />
      <div className="min-w-0 flex-1">
        <p className="text-sm font-semibold text-wx-fg">{t("teamStatusOnline")}</p>
        {block.showResponseTime && (
          <p className="text-xs text-wx-fg-muted">{t("teamStatusReplyTime")}</p>
        )}
      </div>
      {block.showOperatorAvatars && config.operatorAvatars.length > 0 && (
        <AvatarStack avatars={config.operatorAvatars} size="sm" ringClass="ring-wx-bg-elevated" />
      )}
    </div>
  );
}
