/**
 * Convert a `File` to a base64-encoded string suitable for the BE's
 * `uploadVisitorMedia` mutation. Strips the `data:<mime>;base64,`
 * prefix the FileReader emits — the BE wants raw base64 bytes only.
 *
 * Returns the decoded byte count alongside the payload so the
 * caller can check it against `WEB_UPLOAD_MAX_BYTES` (10 MB on the
 * BE) BEFORE invoking the mutation. A short-circuit at the FE saves
 * a 1 MB+ network round-trip on oversized files.
 */
export async function fileToBase64(file: File): Promise<{
  base64: string;
  size: number;
}> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result;
      if (typeof result !== "string") {
        reject(new Error("FileReader returned non-string result"));
        return;
      }
      // `result` is `data:<mime>;base64,<payload>` — strip the prefix.
      const comma = result.indexOf(",");
      const payload = comma >= 0 ? result.slice(comma + 1) : result;
      resolve({ base64: payload, size: file.size });
    };
    reader.onerror = () => reject(reader.error ?? new Error("File read failed"));
    reader.readAsDataURL(file);
  });
}

/** Mime allowlist — must match the BE's `WebUploadService.ALLOWED_MIMES`.
 *  Keeping these in lockstep prevents the FE from picking a file the
 *  BE will reject. */
export const ALLOWED_UPLOAD_MIMES = new Set<string>([
  "image/png",
  "image/jpeg",
  "image/gif",
  "image/webp",
  "audio/mpeg",
  "audio/ogg",
  "audio/webm",
  "video/mp4",
  "application/pdf",
]);

/** 10 MB — matches the BE's `MAX_UPLOAD_BYTES`. */
export const MAX_UPLOAD_BYTES = 10 * 1024 * 1024;
