import { cookies, headers } from "next/headers";
import { getRequestConfig } from "next-intl/server";

// Client-safe primitives live in `lib/locales.ts` so client components can
// import them without dragging this server-only module (and `next/headers`)
// into the browser bundle. Re-exported here for back-compat with any
// existing `from "@/lib/i18n"` imports on the server side.
export {
  DEFAULT_LOCALE,
  isSupportedLocale,
  SUPPORTED_LOCALES,
  type SupportedLocale,
} from "./locales";

import { DEFAULT_LOCALE, isSupportedLocale, type SupportedLocale } from "./locales";

/**
 * Best-match a raw `Accept-Language` header against `SUPPORTED_LOCALES`.
 * Walks the quality-ordered list, strips region tags (`uk-UA` → `uk`),
 * and returns the first supported hit. `null` when nothing matches.
 */
function matchAcceptLanguage(header: string | null): SupportedLocale | null {
  if (!header) return null;
  const tags = header
    .split(",")
    .map((part) => part.split(";")[0].trim().toLowerCase())
    .filter(Boolean);
  for (const tag of tags) {
    const base = tag.split("-")[0];
    if (isSupportedLocale(base)) return base;
  }
  return null;
}

/**
 * Server-side request config — next-intl invokes this on every render
 * to pick the locale + load its messages bundle. Resolution order:
 *
 *   1. next-intl `requestLocale` (set by routing/middleware, if any)
 *   2. `wexio-locale` cookie (per-visitor preference / manual override)
 *   3. `Accept-Language` header best-match against `SUPPORTED_LOCALES`
 *   4. `DEFAULT_LOCALE` fallback
 *
 * The client embeds (web-component / react-component) resolve locale
 * separately via `detectClientLocale` (adds `?lang=` support); this
 * server path covers the Next iframe app.
 */
export default getRequestConfig(async ({ requestLocale }) => {
  const locale = await resolveServerLocale(requestLocale);
  // The `demo` namespace (mock news / help / conversation content) lives
  // in its own `messages/demo.<locale>.json` so the demo strings stay out
  // of the operator-facing chrome file. Merge it back under `demo` —
  // `useTranslations("demo")` is called unconditionally by several
  // components (the demo content is only READ when `isDummy`), so the
  // namespace must exist for every locale or those hooks throw
  // MISSING_MESSAGE (which is exactly the `uk` error we hit).
  const [base, demo] = await Promise.all([
    import(`@/messages/${locale}.json`),
    import(`@/messages/demo.${locale}.json`),
  ]);
  return {
    locale,
    messages: { ...base.default, demo: demo.default },
  };
});

async function resolveServerLocale(
  requestLocale: Promise<string | undefined>,
): Promise<SupportedLocale> {
  const requested = await requestLocale;
  if (isSupportedLocale(requested)) return requested;

  try {
    const hdrs = await headers();
    // `?lang=` for this render — set by `middleware.ts` (also persisted
    // to the cookie below for subsequent navigations).
    const fromQuery = hdrs.get("x-wexio-locale");
    if (isSupportedLocale(fromQuery)) return fromQuery;

    const cookieLocale = (await cookies()).get("wexio-locale")?.value;
    if (isSupportedLocale(cookieLocale)) return cookieLocale;

    const fromHeader = matchAcceptLanguage(hdrs.get("accept-language"));
    if (fromHeader) return fromHeader;
  } catch {
    // `headers()` / `cookies()` unavailable (e.g. static render) — fall
    // through to the default.
  }

  return DEFAULT_LOCALE;
}
