import type { WidgetTab } from "@/lib/widget-config";
import type { WidgetRoute } from "@/lib/widget-route";

/**
 * Pure helpers extracted from `WidgetShell` — theme/logo resolution,
 * route ranking, and the route-transition motion variants. Kept out of
 * the shell component so they can be unit-tested in isolation (see
 * `widget-shell-helpers.test.ts`).
 */

/** Normalise the operator's saved theme-mode enum (BE serialises it
 *  uppercase) down to the lowercase set the widget's CSS expects. */
export function normaliseThemeMode(value: unknown): "light" | "dark" | "auto" {
  if (typeof value !== "string") return "auto";
  const v = value.toLowerCase();
  if (v === "light" || v === "dark" || v === "auto") return v;
  return "auto";
}

/**
 * Collapse the operator's per-mode `organizationLogo` down to the
 * single URL the header components render.
 *
 *   - prefer the resolved theme mode's logo
 *   - fall back to the OTHER mode's logo (one logo beats none — an
 *     operator who only uploaded a light logo still wants it shown
 *     in dark mode rather than the generic Wexio mark)
 *   - `null` when neither mode has a logo
 */
export function resolveOrgLogo(
  logo: { light: string | null; dark: string | null } | null,
  mode: "light" | "dark",
): string | null {
  if (!logo) return null;
  const primary = mode === "dark" ? logo.dark : logo.light;
  const fallback = mode === "dark" ? logo.light : logo.dark;
  return primary ?? fallback ?? null;
}

export function defaultRouteFor(tab: WidgetTab): WidgetRoute {
  if (tab === "messages") return { kind: "messages" };
  if (tab === "help") return { kind: "help" };
  if (tab === "news") return { kind: "news" };
  if (tab === "profile") return { kind: "profile" };
  return { kind: "home" };
}

/**
 * Stable per-route ranking used to derive transition direction.
 * Higher number = "deeper" in the visitor's mental stack. Tabs are
 * 0..3 in their nav order; drill-ins of Help live at 2.5/2.75 so
 * help → category → article reads as forward, then back returns
 * through the same rank scale.
 */
export function routeRank(route: WidgetRoute): number {
  switch (route.kind) {
    case "home":
      return 0;
    case "messages":
      return 1;
    case "help":
      return 2;
    case "help-category":
      return 2.5;
    case "help-article":
      return 2.75;
    case "news":
      return 3;
    case "news-article":
      return 3.25;
    case "profile":
      return 4;
  }
}

export function routeKey(route: WidgetRoute): string {
  if (route.kind === "help-category") return `help-category:${route.categoryId}`;
  if (route.kind === "help-article") return `help-article:${route.slug}`;
  if (route.kind === "news-article") return `news-article:${route.id}`;
  return route.kind;
}

/**
 * Route transition variants — Day-11 rework. Goals:
 *   1. **No height jump.** Anchor exit + enter at `inset-0` and
 *      avoid layout-affecting transforms (no scale, no blur). The
 *      panel chrome stays put, only the content slides.
 *   2. **Direction-aware slide.** Forward navigation → new view
 *      slides in from the right, old slides out to the left;
 *      back-nav mirrors. Tab-swap (direction = 0) → crossfade only.
 *   3. **Crisp settle.** Tight spring (high stiffness, high damping)
 *      so the slide reads as responsive, not springy/bouncy.
 */
export const routeVariants = {
  enter: (direction: number) => ({
    x: direction > 0 ? 28 : direction < 0 ? -28 : 0,
    opacity: 0,
  }),
  center: {
    x: 0,
    opacity: 1,
  },
  exit: (direction: number) => ({
    x: direction > 0 ? -28 : direction < 0 ? 28 : 0,
    opacity: 0,
  }),
};
